// SIEMLess DB versions cache: rule name -> { id, version, rule_content }
var _ruleVersionCache = {};
var _ruleVersionsLoaded = false;

async function syncDetectionRulesToSupabase(rules) {
  if (!window._dactaSupabase || !rules || rules.length === 0) return;
  try {
    // Load all existing rules from SIEMLess DB to compare
    var res = await window._dactaSupabase.from('detection_rules').select('id,name,version,rule_content');
    var existing = {};
    if (res.data) {
      res.data.forEach(function(r) { existing[r.name] = r; });
    }
    // Update version cache for renderRules
    _ruleVersionCache = {};
    if (res.data) {
      res.data.forEach(function(r) { _ruleVersionCache[r.name] = { id: r.id, version: r.version }; });
    }
    _ruleVersionsLoaded = true;
    // Re-render to pick up real versions
    renderRules();

    var currentUser = _getCurrentUserEmail();
    for (var i = 0; i < rules.length; i++) {
      var rule = rules[i];
      var ruleContent = JSON.stringify({ id: rule.id, type: rule.type, severity: rule.severity, mitre: rule.mitre, logSources: rule.logSources, hits: rule.hits });
      try {
        if (!existing[rule.name]) {
          // Insert new rule
          var ins = await window._dactaSupabase.from('detection_rules').insert({
            name: rule.name,
            description: '',
            rule_content: ruleContent,
            syntax: rule.type,
            severity: rule.severity,
            status: rule.status || 'Production',
            mitre_tactic: '',
            mitre_technique_id: rule.mitre !== '\u2014' ? rule.mitre : null,
            mitre_technique_name: '',
            data_sources: rule.logSources || [],
            tags: [],
            author: rule.author || 'Custom',
            version: 1,
            avg_daily_hits: rule.hits || 0
          });
          if (ins.error) {
            console.warn('[RuleSync] Insert failed for rule:', rule.name, ins.error.message);
            return;
          }
          // Re-fetch the inserted row to get its ID
          if (!ins.data || !ins.data[0]) {
            var fetch_ins = await window._dactaSupabase.from('detection_rules').select('id').eq('name', rule.name).limit(1).single();
            if (fetch_ins.error || !fetch_ins.data) {
              console.warn('[RuleSync] Failed to fetch inserted rule:', rule.name);
              return;
            }
            ins.data = [fetch_ins.data];
          }
          if (ins.data && ins.data[0]) {
            _ruleVersionCache[rule.name] = { id: ins.data[0].id, version: 1 };
            logToSupabase('audit_log', {
              user_email: 'system',
              action: 'rule_sync',
              resource_type: 'detection_rule',
              resource_id: ins.data[0].id,
              details: { rule_name: rule.name, version: 1, change_type: 'sync_from_elastic', event: 'new_rule' }
            });
          }
        } else {
          var ex = existing[rule.name];
          var existingContent = ex.rule_content || '';
          var newVersion = ex.version || 1;
          var changed = existingContent !== ruleContent;
          if (changed) {
            newVersion = (ex.version || 1) + 1;
            await window._dactaSupabase.from('detection_rules').update({
              rule_content: ruleContent,
              version: newVersion,
              severity: rule.severity,
              status: rule.status || 'Production',
              avg_daily_hits: rule.hits || 0,
              last_triggered_at: new Date().toISOString()
            }).eq('id', ex.id);
            _ruleVersionCache[rule.name] = { id: ex.id, version: newVersion };
            logToSupabase('audit_log', {
              user_email: 'system',
              action: 'rule_sync',
              resource_type: 'detection_rule',
              resource_id: ex.id,
              details: { rule_name: rule.name, version: newVersion, change_type: 'sync_from_elastic', event: 'rule_updated' }
            });
          } else {
            _ruleVersionCache[rule.name] = { id: ex.id, version: ex.version || 1 };
          }
        }
      } catch(ruleErr) { console.warn('[RuleSync] Error syncing rule:', rule.name, ruleErr); }
    }
    // Re-render with updated versions
    renderRules();
    console.log('[RuleSync] Synced ' + rules.length + ' rules to SIEMLess DB');
  } catch(e) { console.warn('[RuleSync] SIEMLess DB sync error:', e); }
}

// Show rule version history from audit_log
async function showRuleHistory(ruleId, ruleName) {
  if (!window._dactaSupabase) { showToast('SIEMLess DB not connected', 'warn'); return; }
  try {
    var res = await window._dactaSupabase.from('audit_log')
      .select('created_at,user_email,action,details')
      .eq('resource_type', 'detection_rule')
      .eq('resource_id', ruleId)
      .order('created_at', { ascending: false })
      .limit(20);
    var rows = res.data || [];
    var html = '<div style="font-family:\'Sora\',sans-serif;font-size:13px;font-weight:700;color:#f1f5f9;margin-bottom:14px;">Version History: ' + ruleName + '</div>';
    if (rows.length === 0) {
      html += '<div style="font-size:11px;color:rgba(241,245,249,0.5);">No version history recorded yet.</div>';
    } else {
      html += '<div style="display:flex;flex-direction:column;gap:8px;">';
      rows.forEach(function(r) {
        var d = r.details || {};
        var ts = r.created_at ? new Date(r.created_at).toLocaleString('en-SG', { timeZone: 'Asia/Singapore', day: '2-digit', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit' }) : '';
        html += '<div style="padding:10px 12px;background:rgba(0,212,255,0.04);border:1px solid rgba(0,212,255,0.1);border-radius:8px;">';
        html += '<div style="display:flex;align-items:center;gap:8px;margin-bottom:4px;">';
        html += '<span style="font-family:var(--font-mono);font-size:10px;color:#00d4ff;font-weight:700;">v' + (d.version || '?') + '.0</span>';
        html += '<span style="font-size:10px;color:rgba(241,245,249,0.6);">' + ts + '</span>';
        html += '<span style="font-size:9px;padding:1px 6px;background:rgba(0,212,255,0.08);border:1px solid rgba(0,212,255,0.15);border-radius:3px;color:rgba(241,245,249,0.7);">' + (d.change_type || r.action) + '</span>';
        html += '</div>';
        html += '<div style="font-size:10px;color:rgba(241,245,249,0.5);">By: ' + (r.user_email || 'system') + '</div>';
        html += '</div>';
      });
      html += '</div>';
    }
    html += '<div style="margin-top:14px;text-align:right;"><button onclick="document.getElementById(\'ruleHistoryOverlay\').style.display=\'none\'" style="padding:8px 18px;border-radius:8px;border:1px solid rgba(0,212,255,0.3);background:rgba(0,212,255,0.08);color:#00d4ff;font-family:\'Sora\',sans-serif;font-size:12px;font-weight:600;cursor:pointer;">Close</button></div>';
    // Show in overlay
    var overlay = document.getElementById('ruleHistoryOverlay');
    if (!overlay) {
      overlay = document.createElement('div');
      overlay.id = 'ruleHistoryOverlay';
      overlay.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.65);backdrop-filter:blur(4px);z-index:99999;display:flex;align-items:center;justify-content:center;';
      overlay.innerHTML = '<div id="ruleHistoryContent" style="background:rgba(8,12,24,0.97);border:1px solid rgba(0,212,255,0.18);border-radius:16px;padding:24px 28px;width:520px;max-width:95vw;max-height:70vh;overflow-y:auto;backdrop-filter:blur(12px);box-shadow:0 24px 80px rgba(0,0,0,0.6);"></div>';
      document.body.appendChild(overlay);
    } else {
      overlay.style.display = 'flex';
    }
    document.getElementById('ruleHistoryContent').innerHTML = html;
  } catch(e) { showToast('Failed to load history: ' + e.message, 'warn'); }
}

