var _rulesPage = 1;
var _rulesPerPage = 25;
var _rulesTotalCount = 0;
var _rulesCurrentFilters = { search: '', type: '', severity: '', logSource: '', author: '', status: '' };
var _rulesLoading = false;

// Lightweight cache for on-demand detail/playbook fetches
var _ruleDetailCache = {};
var _playbookCache = {};
var _playbooksLoaded = false; // kept for compat — always true once first fetch done

// Slim columns for table listing (no heavy text blobs)
var _rulesListColumns = 'id,name,syntax,severity,status,mitre_tactic,mitre_technique_id,vendor,author,version,avg_daily_hits,false_positive_rate,is_enabled,source_type,log_source_product,log_source_category,log_source_service';

// ── Map raw DB row → display object (slim) ──
function mapRuleRow(r) {
  var sevMap = { 'critical': 'Critical', 'high': 'High', 'medium': 'Medium', 'low': 'Low', 'informational': 'Informational' };
  var syntaxMap = { 'sigma': 'Sigma', 'yara': 'YARA', 'threshold': 'Threshold', 'ml': 'ML', 'eql': 'EQL', 'correlation': 'Correlation', 'kql': 'Sigma', 'spl': 'Sigma' };
  var statusMap = { 'testing': 'Testing', 'active': 'Production', 'disabled': 'Deprecated' };
  var logSources = r.log_source_product ? [r.log_source_product] : [];
  return {
    id: r.id.substring(0, 8).toUpperCase(),
    _dbId: r.id,
    name: r.name || 'Unnamed Rule',
    type: syntaxMap[r.syntax] || 'Sigma',
    mitre: r.mitre_technique_id || '\u2014',
    severity: sevMap[r.severity] || 'Medium',
    logSources: logSources,
    author: (r.author === 'DACTA SIEMLess Engine') ? 'Dacta SOC' : (r.author || 'Custom'),
    ver: 'v' + (r.version || 1) + '.0',
    status: statusMap[r.status] || 'Testing',
    fp: (r.false_positive_rate !== null && r.false_positive_rate !== undefined) ? r.false_positive_rate + '%' : '\u2014',
    hits: r.avg_daily_hits || 0,  // Real hits come from Elastic only
    _source: 'supabase',
    _vendor: r.vendor || '',
    _isEnabled: r.is_enabled !== false,
    _syntax: r.syntax || 'sigma',
    _sourceType: (r.source_type && r.log_source_service && r.log_source_service !== r.source_type && r.log_source_service.toLowerCase() !== (r.vendor || '').toLowerCase()) ? r.source_type + ' \u2014 ' + r.log_source_service : (r.source_type || ''),
    _logSourceProduct: r.log_source_product || '',
    _logSourceCategory: r.log_source_category || '',
    _logSourceService: r.log_source_service || ''
  };
}

// ── Fetch ONE page of rules with server-side filter/sort ──
async function loadRulesPage(page, filters) {
  // Wait up to 3s for DB client init (may not be ready yet on first nav)
  if (!window._dactaSupabase) {
    for (var _w = 0; _w < 15 && !window._dactaSupabase; _w++) await new Promise(function(r) { setTimeout(r, 200); });
  }
  if (!window._dactaSupabase) { console.warn('[DetectionRules] SIEMLess DB not initialized'); return { data: [], count: 0 }; }
  filters = filters || _rulesCurrentFilters;
  var perPage = _rulesPerPage;
  var from = (page - 1) * perPage;
  var to = from + perPage - 1;

  var query = window._dactaSupabase.from('detection_rules')
    .select(_rulesListColumns, { count: 'exact' })
    .range(from, to)
    .order('created_at', { ascending: false });

  // Apply server-side filters
  if (filters.search) {
    query = query.or('name.ilike.%' + filters.search + '%,mitre_technique_id.ilike.%' + filters.search + '%,description.ilike.%' + filters.search + '%,source_type.ilike.%' + filters.search + '%,vendor.ilike.%' + filters.search + '%');
  }
  if (filters.severity) {
    var sevReverseMap = { 'Critical': 'critical', 'High': 'high', 'Medium': 'medium', 'Low': 'low' };
    query = query.eq('severity', sevReverseMap[filters.severity] || filters.severity.toLowerCase());
  }
  if (filters.type) {
    var typeReverseMap = { 'Sigma': 'sigma', 'YARA': 'yara', 'Threshold': 'threshold', 'ML': 'ml', 'EQL': 'eql', 'Correlation': 'correlation' };
    query = query.eq('syntax', typeReverseMap[filters.type] || filters.type.toLowerCase());
  }
  if (filters.logSource) {
    var ls = filters.logSource.toLowerCase();
    // filters.logSource is a DB vendor value (e.g. 'crowdstrike') — use exact eq match
    query = query.eq('vendor', ls);
  }
  if (filters.author) {
    if (filters.author === 'Dacta SOC') query = query.eq('author', 'DACTA SIEMLess Engine');
    else if (filters.author === 'Community (Sigma HQ)') query = query.eq('author', 'Community');
    else if (filters.author === 'Custom / Client') query = query.eq('author', 'Custom');
  }
  if (filters.status) {
    var statReverseMap = { 'Production': 'active', 'Testing': 'testing', 'Draft': 'draft', 'Deprecated': 'disabled' };
    query = query.eq('status', statReverseMap[filters.status] || filters.status.toLowerCase());
  }

  var res = await query;
  if (res.error) { console.warn('[DetectionRules] Page query error:', res.error.message, res.error.code, res.error); return { data: [], count: 0 }; }
  return { data: (res.data || []).map(mapRuleRow), count: res.count || 0 };
}

// ── Load stat card counts via parallel lightweight queries ──
async function loadRuleStatCounts() {
  // Wait up to 3s for DB client init
  if (!window._dactaSupabase) {
    for (var _w = 0; _w < 15 && !window._dactaSupabase; _w++) await new Promise(function(r) { setTimeout(r, 200); });
  }
  if (!window._dactaSupabase) { console.warn('[DetectionRules] SIEMLess DB not ready for stat counts'); return; }
  var sb = window._dactaSupabase;
  try {
    // Use limit(1) instead of head:true — more reliable count across JS SDK versions
    var [totalRes, activeRes, edrRes, fwRes, critRes, cloudRes] = await Promise.all([
      sb.from('detection_rules').select('id', { count: 'exact' }).limit(1),
      sb.from('detection_rules').select('id', { count: 'exact' }).eq('status', 'active').limit(1),
      sb.from('detection_rules').select('id', { count: 'exact' }).in('log_source_category', ['edr', 'process_creation', 'security']).limit(1),
      sb.from('detection_rules').select('id', { count: 'exact' }).eq('log_source_category', 'firewall').limit(1),
      sb.from('detection_rules').select('id', { count: 'exact' }).eq('severity', 'critical').limit(1),
      sb.from('detection_rules').select('id', { count: 'exact' }).in('log_source_category', ['cloud', 'identity']).limit(1)
    ]);
    console.log('[DetectionRules] Stat counts:', { total: totalRes.count, active: activeRes.count, edr: edrRes.count, fw: fwRes.count, crit: critRes.count, cloud: cloudRes.count });
    var eT = document.getElementById('drStatTotal');
    var eA = document.getElementById('drStatActive');
    var eE = document.getElementById('drStatEDR');
    var eF = document.getElementById('drStatFirewall');
    var eC = document.getElementById('drStatCritical');
    var eCl = document.getElementById('drStatCloud');
    if (eT) eT.textContent = (totalRes.count != null ? totalRes.count : 0).toLocaleString();
    if (eA) eA.textContent = (activeRes.count != null ? activeRes.count : 0).toLocaleString();
    if (eE) eE.textContent = (edrRes.count != null ? edrRes.count : 0).toLocaleString();
    if (eF) eF.textContent = (fwRes.count != null ? fwRes.count : 0).toLocaleString();
    if (eC) eC.textContent = (critRes.count != null ? critRes.count : 0).toLocaleString();
    if (eCl) eCl.textContent = (cloudRes.count != null ? cloudRes.count : 0).toLocaleString();
  } catch (e) { console.warn('[DetectionRules] Stat count error:', e); }
}

// ── Fetch full rule detail on demand (for modal, inline expand, edit) ──
async function fetchRuleDetail(dbId) {
  if (_ruleDetailCache[dbId]) return _ruleDetailCache[dbId];
  if (!window._dactaSupabase) return null;
  var res = await window._dactaSupabase.from('detection_rules')
    .select('*')
    .eq('id', dbId)
    .single();
  if (res.error || !res.data) return null;
  var r = res.data;
  var detail = mapRuleRow(r);
  detail._ruleContent = r.rule_content || '';
  detail._detectionLogic = r.detection_logic || '';
  detail._description = r.description || '';
  detail._deploymentTargets = r.deployment_targets || [];
  detail._confidenceScore = r.confidence_score || 0;
  detail._tags = r.tags || [];
  detail._dataSources = r.data_sources || [];
  detail._mitreTactic = r.mitre_tactic || '';
  detail._mitreTechniqueName = r.mitre_technique_name || '';
  detail._ruleCategory = r.rule_category || '';
  detail._platform = r.platform || '';
  detail._batchId = r.batch_id || '';
  _ruleDetailCache[dbId] = detail;
  return detail;
}

// ── Fetch playbook on demand ──
async function fetchPlaybook(ruleDbId) {
  if (_playbookCache[ruleDbId]) return _playbookCache[ruleDbId];
  if (!window._dactaSupabase) return null;
  var res = await window._dactaSupabase.from('response_playbooks')
    .select('id,detection_rule_id,rule_name,playbook_name,description,severity,triage_steps,containment_steps,eradication_steps,recovery_steps,post_incident_steps,auto_response_actions,escalation_criteria,investigation_queries,evidence_collection,false_positive_guidance,mitre_tactic,mitre_technique_id,estimated_time_minutes,difficulty,status')
    .eq('detection_rule_id', ruleDbId)
    .limit(1)
    .maybeSingle();
  if (res.error || !res.data) return null;
  _playbookCache[ruleDbId] = res.data;
  _playbooksLoaded = true;
  return res.data;
}

// ── Show Playbook (on-demand fetch) ──
async function showPlaybook(ruleDbId, ruleName) {
  var pb = _playbookCache[ruleDbId];
  if (!pb) {
    showToast('Loading playbook...', 'info');
    pb = await fetchPlaybook(ruleDbId);
  }
  if (!pb) { showToast('No playbook found for this rule. Generate one in the Rule Builder.', 'warn'); return; }
  var html = '<div style="font-family:\'Sora\',sans-serif;">';
  html += '<div style="font-size:15px;font-weight:700;color:#f1f5f9;margin-bottom:4px;">' + (pb.playbook_name || ruleName) + '</div>';
  html += '<div style="font-size:11px;color:rgba(241,245,249,0.5);margin-bottom:16px;">' + (pb.description || '') + '</div>';
  var phases = [
    { name: 'Triage', data: pb.triage_steps, color: '#00d4ff' },
    { name: 'Containment', data: pb.containment_steps, color: '#f59e0b' },
    { name: 'Eradication', data: pb.eradication_steps, color: '#ef4444' },
    { name: 'Recovery', data: pb.recovery_steps, color: '#10b981' },
    { name: 'Post-Incident', data: pb.post_incident_steps, color: '#8b5cf6' }
  ];
  phases.forEach(function(phase) {
    var steps = phase.data || [];
    if (steps.length === 0) return;
    html += '<div style="margin-bottom:14px;">';
    html += '<div style="font-size:11px;font-weight:700;color:' + phase.color + ';margin-bottom:6px;text-transform:uppercase;letter-spacing:0.5px;">' + phase.name + '</div>';
    steps.forEach(function(s) {
      html += '<div style="display:flex;gap:8px;margin-bottom:6px;padding:6px 10px;background:rgba(255,255,255,0.02);border-radius:6px;border-left:2px solid ' + phase.color + ';">';
      if (typeof s === 'string') {
        html += '<div style="font-size:11px;color:#f1f5f9;">' + s + '</div>';
      } else {
        html += '<span style="font-size:10px;font-weight:700;color:' + phase.color + ';min-width:18px;">' + (s.step || '') + '</span>';
        html += '<div><div style="font-size:11px;color:#f1f5f9;">' + (s.action || '') + '</div>';
        if (s.tool) html += '<div style="font-size:9px;color:rgba(241,245,249,0.4);margin-top:2px;">Tool: ' + s.tool + '</div>';
        html += '</div>';
      }
      html += '</div>';
    });
    html += '</div>';
  });
  var autoActions = pb.auto_response_actions || [];
  if (autoActions.length > 0) {
    html += '<div style="margin-bottom:14px;"><div style="font-size:11px;font-weight:700;color:#00d4ff;margin-bottom:6px;text-transform:uppercase;">Auto-Response Actions</div>';
    autoActions.forEach(function(a) {
      var actionLabel = (typeof a === 'string') ? a : ((a.action || a.action_type || '').replace(/_/g, ' ') + (a.target_field ? ' \u2192 ' + a.target_field : (a.description ? ' \u2014 ' + a.description : '')));
      var approvalBadge = (a && a.requires_approval) ? '<span style="font-size:8px;padding:1px 5px;background:rgba(245,158,11,0.15);color:#f59e0b;border-radius:3px;">Needs Approval</span>' : '<span style="font-size:8px;padding:1px 5px;background:rgba(16,185,129,0.15);color:#10b981;border-radius:3px;">Auto-Execute</span>';
      html += '<div style="padding:6px 10px;background:rgba(0,212,255,0.04);border-radius:6px;margin-bottom:4px;display:flex;justify-content:space-between;align-items:center;">';
      html += '<span style="font-size:11px;color:#f1f5f9;">' + actionLabel + '</span>';
      html += approvalBadge + '</div>';
    });
    html += '</div>';
  }
  html += '<div style="display:flex;gap:8px;margin-top:16px;">';
  html += '<div style="flex:1;padding:8px;background:rgba(0,212,255,0.04);border-radius:8px;text-align:center;"><div style="font-size:16px;font-weight:700;color:#00d4ff;">' + (pb.estimated_time_minutes || 30) + 'min</div><div style="font-size:9px;color:var(--text-muted);">Est. Time</div></div>';
  html += '<div style="flex:1;padding:8px;background:rgba(0,212,255,0.04);border-radius:8px;text-align:center;"><div style="font-size:11px;font-weight:600;color:#f1f5f9;text-transform:capitalize;">' + (pb.difficulty || 'intermediate') + '</div><div style="font-size:9px;color:var(--text-muted);">Difficulty</div></div>';
  html += '</div></div>';
  html += '<div style="margin-top:14px;text-align:right;"><button onclick="closePlaybookOverlay()" style="padding:8px 18px;border-radius:8px;border:1px solid rgba(0,212,255,0.3);background:rgba(0,212,255,0.08);color:#00d4ff;font-family:\'Sora\',sans-serif;font-size:12px;font-weight:600;cursor:pointer;">Close</button></div>';
  var overlay = document.getElementById('playbookOverlay');
  if (!overlay) {
    overlay = document.createElement('div');
    overlay.id = 'playbookOverlay';
    overlay.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.65);backdrop-filter:blur(4px);z-index:99999;display:flex;align-items:center;justify-content:center;cursor:pointer;';
    overlay.onclick = function(e) { if (e.target === overlay) overlay.style.display = 'none'; };
    overlay.innerHTML = '<div id="playbookContent" style="background:rgba(8,12,24,0.97);border:1px solid rgba(0,212,255,0.18);border-radius:16px;padding:24px 28px;width:620px;max-width:95vw;max-height:80vh;overflow-y:auto;backdrop-filter:blur(12px);box-shadow:0 24px 80px rgba(0,0,0,0.6);cursor:default;"></div>';
    document.body.appendChild(overlay);
  } else {
    overlay.style.display = 'flex';
  }
  document.getElementById('playbookContent').innerHTML = html;
}

function closePlaybookOverlay() {
  var overlay = document.getElementById('playbookOverlay');
  if (overlay) overlay.style.display = 'none';
}

// ── Escape key: close Detection Rules modals ──
document.addEventListener('keydown', function(e) {
  if (e.key === 'Escape') {
    // Playbook overlay
    var pb = document.getElementById('playbookOverlay');
    if (pb && pb.style.display !== 'none') { pb.style.display = 'none'; return; }
    // Rule detail modal
    var rd = document.getElementById('ruleDetailModalOverlay');
    if (rd && rd.style.display !== 'none') { rd.style.display = 'none'; return; }
    // Save & Test modal
    var st = document.getElementById('saveTestModalOverlay');
    if (st && st.style.display !== 'none') { st.style.display = 'none'; return; }
    // Bulk Import modal
    var bi = document.getElementById('bulkImportOverlay');
    if (bi && bi.style.display !== 'none') { closeBulkImport(); return; }
    // Bulk Deploy modal
    var bd = document.getElementById('bulkDeployModal');
    if (bd && bd.style.display !== 'none') { closeBulkDeployModal(); return; }
  }
});

// ── Elastic live rule loader (lightweight — no SIEMLess DB needed) ──
async function loadElasticRules() {
  try {
    var resp = await _siemFetch('/api/elastic', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        action: 'search',
        index: '.internal.alerts-security*',
        body: {
          size: 0,
          aggs: {
            rules: {
              terms: { field: 'kibana.alert.rule.name', size: 100 },
              aggs: {
                severity: { terms: { field: 'kibana.alert.severity', size: 1 } },
                category: { terms: { field: 'kibana.alert.rule.category', size: 1 } },
                latest: { top_hits: { size: 1, sort: [{ '@timestamp': 'desc' }], _source: ['kibana.alert.rule.name', 'kibana.alert.rule.category', 'kibana.alert.severity', 'kibana.alert.rule.description', 'kibana.alert.rule.tags'] } }
              }
            }
          }
        }
      })
    });
    var result = await resp.json();
    if (!result || !result.aggregations) return [];
    var buckets = result.aggregations.rules ? result.aggregations.rules.buckets : [];
    var elasticRules = [];
    var idx = 1;
    buckets.forEach(function(b) {
      var hit = (b.latest && b.latest.hits && b.latest.hits.hits && b.latest.hits.hits[0]) ? b.latest.hits.hits[0]._source : {};
      var alert = hit.kibana ? hit.kibana.alert || {} : {};
      var rule = alert.rule || {};
      var sev = (b.severity && b.severity.buckets && b.severity.buckets[0]) ? b.severity.buckets[0].key : 'medium';
      var cat = (b.category && b.category.buckets && b.category.buckets[0]) ? b.category.buckets[0].key : 'Custom Query Rule';
      var sevMap = { 'critical': 'Critical', 'high': 'High', 'medium': 'Medium', 'low': 'Low' };
      var typeMap = { 'Custom Query Rule': 'Sigma', 'Threshold Rule': 'Threshold', 'EQL Rule': 'EQL', 'Machine Learning Rule': 'ML', 'Indicator Match Rule': 'Correlation' };
      var tags = rule.tags || [];
      var mitre = '\u2014';
      tags.forEach(function(t) { if (t && t.match && t.match(/^T\d{4}/)) mitre = t; });
      var isDacta = b.key.indexOf('DACTA') >= 0;
      var logSources = [];
      if (b.key.toLowerCase().indexOf('ip ') >= 0 || b.key.toLowerCase().indexOf('ioc') >= 0) logSources.push('network');
      if (b.key.toLowerCase().indexOf('web') >= 0 || b.key.toLowerCase().indexOf('shell') >= 0) logSources.push('windows');
      if (b.key.toLowerCase().indexOf('edr') >= 0 || b.key.toLowerCase().indexOf('crowdstrike') >= 0) logSources.push('edr');
      if (b.key.toLowerCase().indexOf('firewall') >= 0 || b.key.toLowerCase().indexOf('forti') >= 0) logSources.push('firewall');
      if (logSources.length === 0) logSources.push('edr');
      elasticRules.push({
        id: 'RUL-' + String(3000 + idx).padStart(4, '0'),
        name: b.key,
        type: typeMap[cat] || 'Sigma',
        mitre: mitre,
        severity: sevMap[sev] || 'Medium',
        logSources: logSources,
        author: isDacta ? 'Dacta SOC' : 'Custom',
        ver: '1.0',
        status: 'Production',
        fp: '\u2014',
        hits: b.doc_count,
        _source: 'elastic',
        _vendor: '',
        _isEnabled: true,
        _syntax: 'sigma',
        _sourceType: '',
        _logSourceProduct: '',
        _logSourceCategory: 'edr'
      });
      idx++;
    });
    return elasticRules;
  } catch(err) {
    console.warn('[DetectionRules] Elastic load failed, SIEMLess DB-only mode:', err.message);
    return [];
  }
}

