    + (r.fp && r.fp !== '\u2014' ? '<div style="font-size:10px;font-weight:700;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;margin-top:12px;margin-bottom:4px;">False Positive Rate</div><div style="font-size:11px;color:var(--text-secondary);">' + r.fp + '</div>' : '')
