    + '<button class="btn btn-secondary btn-sm" onclick="document.getElementById(\'ruleDetailModalOverlay\').style.display=\'none\';testRuleInLab(\'' + r._dbId + '\',\'' + (r.name||'').replace(/\'/g,"\\'") + '\')">Test Rule</button>'
