  var pbSummary = pb ? '<span style="color:var(--green);">' + dIcon('check',14) + ' ' + (pb.playbook_name||'Playbook attached') + '</span> \u00b7 <span style="color:var(--text-muted);">' + (pb.estimated_time_minutes||30) + 'min \u00b7 ' + (pb.difficulty||'intermediate') + '</span>' : '<span style="color:var(--text-muted);">No playbook attached</span>';
  var confColor = r._confidenceScore >= 80 ? 'var(--green)' : r._confidenceScore >= 50 ? 'var(--amber)' : 'var(--red-bright)';
  var targets = (r._deploymentTargets && r._deploymentTargets.length > 0) ? r._deploymentTargets.join(', ') : 'Not deployed';
  var logic = (r._detectionLogic || '').substring(0, 200);
  detailRow.innerHTML = '<td colspan="13" style="padding:12px 16px;background:rgba(0,212,255,0.02);border-left:3px solid var(--cyan);">'
    + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;">'
