/**
 * loadReportingLive()
 * Called by the main app whenever the Reporting page is shown.
 * Loads all data for the compliance dashboard (Tab 1).
 * Other tabs lazy-load on first activation.
 */
window.loadReportingLive = function() {
  _rptFwFilter = 'all';
  // Reset lazy-load flags so tabs refresh
  window._rptAuditLoaded    = false;
  window._rptReportingLoaded = false;
  window._rptUsersLoaded    = false;

  rptLoadComplianceKPIs();
  rptLoadFrameworks();
  rptRenderRefFrameworks();

  // Start auto-refresh timer
  if (typeof rptStartAutoRefresh === 'function') rptStartAutoRefresh();
};

// ============================================================
// TAB 1: COMPLIANCE DASHBOARD
// ============================================================

function rptLoadComplianceKPIs() {
  var sb = window._supabaseRef;
  if (!sb) return;

  sb.from('compliance_frameworks')
    .select('*')
    .then(function(res) {
      if (res.error) {
        console.warn('[RPT] compliance_frameworks KPI error', res.error);
        rptRenderKPIsFromData([]);
        return;
      }
      rptRenderKPIsFromData(res.data || []);
    });
}

function rptRenderKPIsFromData(frameworks) {
  var totalControls = 0;
  var totalMet = 0;
  var openFindings = 0;
  var overdueCount = 0;
  var now = new Date();

  for (var i = 0; i < frameworks.length; i++) {
    var fw = frameworks[i];
    totalControls += (fw.total_controls || 0);
    totalMet      += (fw.controls_met  || 0);
    if (fw.status === 'gaps_found') openFindings++;
    if (fw.last_assessed) {
      var last = new Date(fw.last_assessed);
      var daysDiff = (now - last) / (1000 * 60 * 60 * 24);
      if (daysDiff > 90) overdueCount++;
    }
  }

  var score = totalControls > 0 ? Math.round((totalMet / totalControls) * 100) : 0;

  var scoreEl  = document.getElementById('rpt-kpi-score');
  var fwEl     = document.getElementById('rpt-kpi-frameworks');
  var metEl    = document.getElementById('rpt-kpi-controls-met');
  var findEl   = document.getElementById('rpt-kpi-findings');
  var overdueEl= document.getElementById('rpt-kpi-overdue');

  if (scoreEl)   scoreEl.textContent   = score + '%';
  if (fwEl)      fwEl.textContent      = frameworks.length;
  if (metEl)     metEl.textContent     = totalMet;
  if (findEl)    findEl.textContent    = openFindings;
  if (overdueEl) overdueEl.textContent = overdueCount;
}

function rptLoadFrameworks() {
  var sb = window._supabaseRef;
  if (!sb) {
    rptRenderFrameworkCards();
    return;
  }

  sb.from('compliance_frameworks')
    .select('*')
    .order('name', { ascending: true })
    .then(function(res) {
      if (res.error) {
        console.warn('[RPT] compliance_frameworks load error', res.error);
        _rptAllFrameworks = [];
      } else {
        _rptAllFrameworks = res.data || [];
      }
      rptRenderKPIsFromData(_rptAllFrameworks);
      rptRenderFrameworkCards();
    });
}

window.rptRenderFrameworkCards = function() {
  var grid = document.getElementById('rpt-fw-grid');
  if (!grid) return;

  var filter = window._rptFwFilter || 'all';
  var filtered = [];
  for (var i = 0; i < _rptAllFrameworks.length; i++) {
    var fw = _rptAllFrameworks[i];
    if (filter === 'all') {
      filtered.push(fw);
    } else if (filter === 'compliant' && fw.status === 'compliant') {
      filtered.push(fw);
    } else if (filter === 'in_progress' && fw.status === 'in_progress') {
      filtered.push(fw);
    } else if (filter === 'gaps_found' && fw.status === 'gaps_found') {
      filtered.push(fw);
    }
  }

  if (filtered.length === 0) {
    grid.innerHTML = '<div class="rpt-empty" style="grid-column:1/-1;">'
      + '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M9 5H7a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2h-2"/><rect x="9" y="3" width="6" height="4" rx="1"/></svg>'
      + '<div class="rpt-empty-title">No frameworks found</div>'
      + '<div class="rpt-empty-sub">Add a framework using the button above</div>'
      + '</div>';
    return;
  }

  var html = '';
  for (var j = 0; j < filtered.length; j++) {
    html += rptBuildFrameworkCard(filtered[j]);
  }
  grid.innerHTML = html;
};

function rptBuildFrameworkCard(fw) {
  var total   = fw.total_controls || 0;
  var met     = fw.controls_met   || 0;
  var pct     = total > 0 ? Math.round((met / total) * 100) : 0;
  var fillCls = pct >= 80 ? 'green' : (pct >= 50 ? '' : 'amber');
  var statusBadge = rptStatusBadge(fw.status);
  var org = fw.org_id ? escapeHtml(fw.org_id) : '—';
  var lastAssessed = fw.last_assessed ? rptFormatDate(fw.last_assessed) : 'Not assessed';
  var fwId = fw.id;
  var fwName = escapeHtml(fw.name || '');

  return '<div class="rpt-fw-card" onclick="rptOpenFrameworkDetail(' + fwId + ', \'' + fwName + '\')">'
    + '<div class="rpt-fw-card-header">'
    +   '<div>'
    +     '<div class="rpt-fw-name">' + fwName + '</div>'
    +     '<div class="rpt-fw-version">' + escapeHtml(fw.version || '') + '</div>'
    +   '</div>'
    +   statusBadge
    + '</div>'
    + '<div class="rpt-fw-org">Org: ' + org + '</div>'
    + '<div class="rpt-progress-bar"><div class="rpt-progress-fill ' + fillCls + '" style="width:' + pct + '%;"></div></div>'
    + '<div class="rpt-progress-label"><span>' + met + ' / ' + total + ' controls</span><span>' + pct + '%</span></div>'
    + '<div class="rpt-fw-actions" onclick="event.stopPropagation();">'
    +   '<button class="rpt-btn rpt-btn-ghost rpt-btn-sm" onclick="rptOpenFrameworkDetail(' + fwId + ', \'' + fwName + '\')">'
    +     'View Controls'
    +   '</button>'
    +   '<button class="rpt-btn rpt-btn-purple-ghost rpt-btn-sm" onclick="rptRunAIAssessment(' + fwId + ', \'' + fwName + '\')">'
    +     'Run AI Assessment'
    +   '</button>'
    + '</div>'
    + '<div style="margin-top:8px;font-size:10px;color:var(--text-muted);font-family:\'IBM Plex Mono\',monospace;">Last assessed: ' + lastAssessed + '</div>'
    + '</div>';
}

function rptStatusBadge(status) {
  var map = {
    'compliant':    '<span class="badge badge-green">Compliant</span>',
    'in_progress':  '<span class="badge badge-cyan">In Progress</span>',
    'gaps_found':   '<span class="badge badge-amber">Gaps Found</span>',
    'not_started':  '<span class="badge badge-gray">Not Started</span>'
  };
  return map[status] || '<span class="badge badge-gray">' + escapeHtml(status || 'Unknown') + '</span>';
}

// ---- Framework Detail Modal ----
window.rptOpenFrameworkDetail = function(fwId, fwName) {
  _rptCurrentFwId   = fwId;
  _rptCurrentFwName = fwName;

  var title = document.getElementById('rpt-fw-modal-title');
  if (title) title.textContent = fwName + ' — Controls';

  // Find framework in local cache
  var fw = null;
  for (var i = 0; i < _rptAllFrameworks.length; i++) {
    if (_rptAllFrameworks[i].id === fwId) { fw = _rptAllFrameworks[i]; break; }
  }

  // Meta
  var metaEl = document.getElementById('rpt-fw-modal-meta');
  if (metaEl && fw) {
    metaEl.innerHTML = rptStatusBadge(fw.status)
      + '<span class="badge badge-gray">' + escapeHtml(fw.version || '') + '</span>'
      + '<span class="badge badge-blue">Org: ' + escapeHtml(fw.org_id || '—') + '</span>'
      + (fw.last_assessed ? '<span class="badge badge-gray">Assessed: ' + rptFormatDate(fw.last_assessed) + '</span>' : '');
  }

  // Progress in modal
  var progEl = document.getElementById('rpt-fw-modal-progress');
  if (progEl && fw) {
    var total = fw.total_controls || 0;
    var met   = fw.controls_met   || 0;
    var pct   = total > 0 ? Math.round((met / total) * 100) : 0;
    var fillCls = pct >= 80 ? 'green' : (pct >= 50 ? '' : 'amber');
    progEl.innerHTML = '<div style="display:flex;justify-content:space-between;margin-bottom:4px;font-size:11px;color:var(--text-muted);font-family:\'IBM Plex Mono\',monospace;">'
      + '<span>Overall Progress</span><span>' + met + ' / ' + total + ' (' + pct + '%)</span></div>'
      + '<div class="rpt-progress-bar" style="height:6px;"><div class="rpt-progress-fill ' + fillCls + '" style="width:' + pct + '%;"></div></div>';
  }

  // Load controls
  rptLoadControls(fwId);
  rptOpenModal('rpt-fw-detail-modal');
};

function rptLoadControls(fwId) {
  var tbody = document.getElementById('rpt-fw-controls-tbody');
  if (!tbody) return;
  tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;padding:24px;color:var(--text-muted);">Loading controls…</td></tr>';

  var sb = window._supabaseRef;
  if (!sb) {
    tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;padding:24px;color:var(--text-muted);">SIEMLess DB not connected</td></tr>';
    return;
  }

  sb.from('compliance_controls')
    .select('*')
    .eq('framework_id', fwId)
    .order('control_id', { ascending: true })
    .then(function(res) {
      if (res.error || !res.data || res.data.length === 0) {
        tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;padding:24px;color:var(--text-muted);">No controls found for this framework</td></tr>';
        return;
      }
      var html = '';
      for (var i = 0; i < res.data.length; i++) {
        var ctrl = res.data[i];
        html += '<tr>'
          + '<td class="rpt-mono" style="color:var(--cyan);">' + escapeHtml(ctrl.control_id || '') + '</td>'
          + '<td>' + escapeHtml(ctrl.title || '') + '</td>'
          + '<td>' + rptControlStatusBadge(ctrl.status) + '</td>'
          + '<td style="color:var(--text-muted);font-size:11px;">' + escapeHtml(ctrl.assessed_by || '—') + '</td>'
          + '<td style="color:var(--text-muted);font-size:11px;max-width:160px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="' + escapeHtml(ctrl.notes || '') + '">' + escapeHtml(ctrl.notes || '—') + '</td>'
          + '</tr>';
      }
      tbody.innerHTML = html;
    });
}

function rptControlStatusBadge(status) {
  var map = {
    'met':          '<span class="badge badge-green">Met</span>',
    'not_met':      '<span class="badge badge-red">Not Met</span>',
    'partial':      '<span class="badge badge-amber">Partial</span>',
    'not_assessed': '<span class="badge badge-gray">Not Assessed</span>',
    'n/a':          '<span class="badge badge-gray">N/A</span>'
  };
  return map[(status || '').toLowerCase()] || '<span class="badge badge-gray">' + escapeHtml(status || '') + '</span>';
}

window.rptRunAIAssessment = function(fwId, fwName) {
  if (typeof showToast === 'function') {
    showToast('Running AI compliance assessment for ' + fwName + '…', 'info');
  }
  // Simulate assessment (in production, call AI endpoint)
  setTimeout(function() {
    if (typeof showToast === 'function') {
      showToast('AI assessment completed for ' + fwName, 'success');
    }
  }, 2800);
};

window.rptRunAIAssessmentModal = function() {
  rptRunAIAssessment(_rptCurrentFwId, _rptCurrentFwName);
  rptCloseModal('rpt-fw-detail-modal');
};

window.rptSubmitAddFramework = function() {
  var nameEl   = document.getElementById('rpt-add-fw-name');
  var orgEl    = document.getElementById('rpt-add-fw-org');
  var statusEl = document.getElementById('rpt-add-fw-status');

  if (!nameEl || !orgEl || !statusEl) return;
  if (!orgEl.value) {
    if (typeof showToast === 'function') showToast('Please select an organisation', 'warning');
    return;
  }

  var fwName = nameEl.value;
  // Look up controls count from reference data
  var ctrlCount = 0;
  var version   = '';
  for (var i = 0; i < RPT_REF_FRAMEWORKS.length; i++) {
    if (RPT_REF_FRAMEWORKS[i].name === fwName) {
      ctrlCount = RPT_REF_FRAMEWORKS[i].controls;
      version   = RPT_REF_FRAMEWORKS[i].version;
      break;
    }
  }

  var sb = window._supabaseRef;
  if (!sb) {
    if (typeof showToast === 'function') showToast('SIEMLess DB not connected', 'error');
    return;
  }

  var payload = {
    name: fwName,
    version: version,
    description: '',
    total_controls: ctrlCount,
    controls_met: 0,
    org_id: orgEl.value,
    status: statusEl.value,
    last_assessed: null
  };

  sb.from('compliance_frameworks')
    .insert([payload])
    .then(function(res) {
      if (res.error) {
        if (typeof showToast === 'function') showToast('Error adding framework: ' + res.error.message, 'error');
        return;
      }
      if (typeof showToast === 'function') showToast('Framework "' + fwName + '" added successfully', 'success');
      rptCloseModal('rpt-add-fw-modal');
      rptLoadFrameworks();
    });
};

