window.rptLoadAuditLogs = function(silent) {
  var sb = window._supabaseRef;
  if (!sb) return;

  if (!silent) {
    var tbody = document.getElementById('rpt-audit-tbody');
    if (tbody) {
      tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:24px;color:var(--text-muted);">'
        + '<span class="rpt-skeleton" style="display:inline-block;width:200px;height:14px;">&nbsp;</span></td></tr>';
    }
  }

  sb.from('audit_logs')
    .select('*')
    .order('created_at', { ascending: false })
    .limit(500)
    .then(function(res) {
      if (res.error) {
        console.warn('[RPT] audit_logs load error', res.error);
        _rptAllAuditLogs = [];
      } else {
        _rptAllAuditLogs = res.data || [];
      }
      rptRenderAuditTable();
    });
};

window.rptFilterAuditLogs = function() {
  _rptAuditPage = 1;
  rptRenderAuditTable();
};

function rptGetFilteredAuditLogs() {
  var search   = (document.getElementById('rpt-audit-search')   || {}).value || '';
  var category = (document.getElementById('rpt-audit-category') || {}).value || '';
  var severity = (document.getElementById('rpt-audit-severity') || {}).value || '';
  var dateFrom = (document.getElementById('rpt-audit-date-from')|| {}).value || '';
  var dateTo   = (document.getElementById('rpt-audit-date-to')  || {}).value || '';

  search = search.toLowerCase();

  var result = [];
  for (var i = 0; i < _rptAllAuditLogs.length; i++) {
    var log = _rptAllAuditLogs[i];

    if (category && (log.category || '').toLowerCase() !== category) continue;
    if (severity && (log.severity || '').toLowerCase() !== severity) continue;

    if (dateFrom) {
      var logDate = new Date(log.created_at);
      var fromDate = new Date(dateFrom);
      if (logDate < fromDate) continue;
    }
    if (dateTo) {
      var logDate2 = new Date(log.created_at);
      var toDate = new Date(dateTo);
      toDate.setHours(23, 59, 59, 999);
      if (logDate2 > toDate) continue;
    }

    if (search) {
      var actor  = (log.actor  || '').toLowerCase();
      var action = (log.action || '').toLowerCase();
      var target = (log.target || '').toLowerCase();
      if (actor.indexOf(search) === -1 && action.indexOf(search) === -1 && target.indexOf(search) === -1) continue;
    }

    result.push(log);
  }
  return result;
}

function rptRenderAuditTable() {
  var tbody = document.getElementById('rpt-audit-tbody');
  if (!tbody) return;

  var filtered = rptGetFilteredAuditLogs();
  var start = (_rptAuditPage - 1) * _rptAuditPageSize;
  var page  = filtered.slice(start, start + _rptAuditPageSize);

  if (filtered.length === 0) {
    tbody.innerHTML = '<tr><td colspan="7">'
      + '<div class="rpt-empty"><div class="rpt-empty-title">No audit log entries</div>'
      + '<div class="rpt-empty-sub">No logs match the current filters</div></div>'
      + '</td></tr>';
    rptRenderAuditPagination(0);
    return;
  }

  var html = '';
  for (var i = 0; i < page.length; i++) {
    var log = page[i];
    var sevBadge = rptSeverityBadge(log.severity);
    var catBadge = rptCategoryBadge(log.category);
    html += '<tr>'
      + '<td class="rpt-mono" style="font-size:11px;">' + rptFormatDateTime(log.created_at) + '</td>'
      + '<td>' + escapeHtml(log.actor || '—') + '</td>'
      + '<td>' + escapeHtml(log.action || '—') + '</td>'
      + '<td style="color:var(--text-muted);">' + escapeHtml(log.target || '—') + '</td>'
      + '<td>' + catBadge + '</td>'
      + '<td>' + sevBadge + '</td>'
      + '<td style="color:var(--text-muted);font-size:11px;max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="' + escapeHtml(log.details || '') + '">' + escapeHtml(log.details || '—') + '</td>'
      + '</tr>';
  }
  tbody.innerHTML = html;
  rptRenderAuditPagination(filtered.length);
}

function rptRenderAuditPagination(total) {
  var el = document.getElementById('rpt-audit-pagination');
  if (!el) return;
  var totalPages = Math.ceil(total / _rptAuditPageSize);
  if (totalPages <= 1) { el.innerHTML = '<span>' + total + ' entries</span>'; return; }

  var html = '<span>' + total + ' entries</span>'
    + '<button class="rpt-btn rpt-btn-ghost rpt-btn-sm" onclick="rptAuditPrevPage()" ' + (_rptAuditPage <= 1 ? 'disabled' : '') + '>‹ Prev</button>'
    + '<span>Page ' + _rptAuditPage + ' of ' + totalPages + '</span>'
    + '<button class="rpt-btn rpt-btn-ghost rpt-btn-sm" onclick="rptAuditNextPage(' + totalPages + ')" ' + (_rptAuditPage >= totalPages ? 'disabled' : '') + '>Next ›</button>';
  el.innerHTML = html;
}

window.rptAuditPrevPage = function() {
  if (_rptAuditPage > 1) { _rptAuditPage--; rptRenderAuditTable(); }
};
window.rptAuditNextPage = function(total) {
  if (_rptAuditPage < total) { _rptAuditPage++; rptRenderAuditTable(); }
};

function rptSeverityBadge(severity) {
  var map = {
    'info':     '<span class="badge badge-blue">INFO</span>',
    'warning':  '<span class="badge badge-amber">WARN</span>',
    'error':    '<span class="badge badge-red">ERROR</span>',
    'critical': '<span class="badge badge-red" style="background:rgba(239,68,68,0.25);color:#ff4d4d;border-color:rgba(239,68,68,0.5);">CRITICAL</span>'
  };
  return map[(severity || '').toLowerCase()] || '<span class="badge badge-gray">' + escapeHtml(severity || '?') + '</span>';
}

function rptCategoryBadge(category) {
  var map = {
    'system':     '<span class="badge badge-gray">SYSTEM</span>',
    'security':   '<span class="badge badge-red">SECURITY</span>',
    'compliance': '<span class="badge badge-purple">COMPLIANCE</span>',
    'user':       '<span class="badge badge-cyan">USER</span>'
  };
  return map[(category || '').toLowerCase()] || '<span class="badge badge-gray">' + escapeHtml(category || '?') + '</span>';
}


// ── DEF-008: PDF Export via print dialog ──
function dactaExportPagePDF(reportTitle) {
  showToast('Preparing PDF export...', 'info');
  // Create a print-friendly version
  var activePage = document.querySelector('.page.active');
  if (!activePage) { showToast('No active page to export.', 'warn'); return; }

  // Add print styles dynamically
  var printStyle = document.createElement('style');
  printStyle.id = 'dacta-print-style';
  printStyle.textContent = '@media print { ' +
    'body { background: white !important; color: black !important; } ' +
    '#sidebar, #topbar, .demo-toggle-wrap, .prod-badge, .live-badge, .topbar-right { display: none !important; } ' +
    '#content-area { margin: 0 !important; padding: 20px !important; overflow: visible !important; height: auto !important; } ' +
    '.page { display: none !important; } ' +
    '.page.active { display: block !important; } ' +
    '.card { break-inside: avoid; border: 1px solid #ddd !important; background: white !important; } ' +
    '.badge { border: 1px solid #999 !important; } ' +
    'h1, h2, h3, .card-header { color: black !important; } ' +
    '@page { size: A4 landscape; margin: 15mm; } ' +
  '}';
  document.head.appendChild(printStyle);

  // Set document title for PDF filename
  var oldTitle = document.title;
  document.title = (reportTitle || 'DACTA SIEMLess Report') + ' — ' + new Date().toISOString().slice(0, 10);

  setTimeout(function() {
    window.print();
    // Cleanup
    setTimeout(function() {
      document.title = oldTitle;
      var ps = document.getElementById('dacta-print-style');
      if (ps) ps.remove();
    }, 1000);
  }, 300);
}
window.dactaExportPagePDF = dactaExportPagePDF;

window.rptExportAuditLogs = function() {
  var filtered = rptGetFilteredAuditLogs();
  if (typeof showToast === 'function') {
    showToast('Exporting ' + filtered.length + ' audit log entries to CSV…', 'info');
  }

  // Build CSV
  var lines = ['Timestamp,Actor,Action,Target,Category,Severity,Details,IP Address'];
  for (var i = 0; i < filtered.length; i++) {
    var log = filtered[i];
    lines.push([
      rptFormatDateTime(log.created_at),
      '"' + (log.actor    || '').replace(/"/g, '""') + '"',
      '"' + (log.action   || '').replace(/"/g, '""') + '"',
      '"' + (log.target   || '').replace(/"/g, '""') + '"',
      '"' + (log.category || '').replace(/"/g, '""') + '"',
      '"' + (log.severity || '').replace(/"/g, '""') + '"',
      '"' + (log.details  || '').replace(/"/g, '""') + '"',
      '"' + (log.ip_address || '').replace(/"/g, '""') + '"'
    ].join(','));
  }

  var csv = lines.join('\n');
  var blob = new Blob([csv], { type: 'text/csv' });
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a');
  a.href = url;
  a.download = 'dacta_audit_logs_' + new Date().toISOString().slice(0,10) + '.csv';
  a.click();
  URL.revokeObjectURL(url);

  if (typeof showToast === 'function') showToast('Audit logs exported successfully', 'success');
};

