function rptRenderUsersTable() {
  var tbody = document.getElementById('rpt-users-tbody');
  if (!tbody) return;

  if (_rptAllUsers.length === 0) {
    tbody.innerHTML = '<tr><td colspan="5">'
      + '<div class="rpt-empty"><div class="rpt-empty-title">No users found</div>'
      + '<div class="rpt-empty-sub">Platform users table may be empty</div></div>'
      + '</td></tr>';
    return;
  }

  var roleBadges = {
    'admin':   '<span class="badge badge-red">Admin</span>',
    'analyst': '<span class="badge badge-cyan">Analyst</span>',
    'viewer':  '<span class="badge badge-gray">Viewer</span>'
  };

  var statusBadges = {
    'active':   '<span class="badge badge-green">Active</span>',
    'inactive': '<span class="badge badge-gray">Inactive</span>',
    'suspended':'<span class="badge badge-red">Suspended</span>'
  };

  var html = '';
  for (var i = 0; i < _rptAllUsers.length; i++) {
    var u = _rptAllUsers[i];
    var initials = rptGetInitials(u.name || u.email || '?');
    var roleBadge  = roleBadges[(u.role || '').toLowerCase()] || '<span class="badge badge-gray">' + escapeHtml(u.role || '?') + '</span>';
    var statBadge  = statusBadges[(u.status || 'active').toLowerCase()] || '<span class="badge badge-gray">' + escapeHtml(u.status || '?') + '</span>';
    var userId = u.id;
    var userName = escapeHtml(u.name || u.email || '');

    html += '<tr>'
      + '<td>'
      +   '<div class="rpt-user-cell">'
      +     '<div class="rpt-user-avatar">' + initials + '</div>'
      +     '<div>'
      +       '<div style="font-weight:600;color:var(--text-primary);font-size:12px;">' + userName + '</div>'
      +       '<div style="font-size:10px;color:var(--text-muted);">' + escapeHtml(u.email || '') + '</div>'
      +     '</div>'
      +   '</div>'
      + '</td>'
      + '<td>' + roleBadge + '</td>'
      + '<td>' + statBadge + '</td>'
      + '<td class="rpt-mono" style="font-size:11px;">' + (u.last_login ? rptFormatDate(u.last_login) : '—') + '</td>'
      + '<td>'
      +   '<button class="rpt-btn rpt-btn-ghost rpt-btn-sm" onclick="rptOpenRoleModal(' + userId + ', \'' + userName + '\', \'' + escapeHtml(u.role || 'viewer') + '\')">Change Role</button>'
      + '</td>'
      + '</tr>';
  }
  tbody.innerHTML = html;
}

window.rptOpenRoleModal = function(userId, userName, currentRole) {
  var nameEl = document.getElementById('rpt-role-user-name');
  var idEl   = document.getElementById('rpt-role-user-id');
  var roleEl = document.getElementById('rpt-role-new');

  if (nameEl) nameEl.textContent = userName;
  if (idEl)   idEl.value         = userId;
  if (roleEl) roleEl.value       = currentRole || 'viewer';

  rptOpenModal('rpt-role-modal');
};

window.rptSubmitRoleChange = function() {
  var userId = (document.getElementById('rpt-role-user-id') || {}).value;
  var newRole = (document.getElementById('rpt-role-new')     || {}).value;
  var userName = (document.getElementById('rpt-role-user-name') || {}).textContent;

  if (!userId || !newRole) return;

  var sb = window._supabaseRef;
  if (!sb) {
    if (typeof showToast === 'function') showToast('SIEMLess DB not connected', 'error');
    return;
  }

  sb.from('platform_users')
    .update({ role: newRole })
    .eq('id', userId)
    .then(function(res) {
      if (res.error) {
        if (typeof showToast === 'function') showToast('Error updating role: ' + res.error.message, 'error');
        return;
      }
      if (typeof showToast === 'function') showToast('Role updated to "' + newRole + '" for ' + userName, 'success');
      rptCloseModal('rpt-role-modal');
      rptLoadPlatformUsers();
    });
};

