// ============================================================
// UTILITY FUNCTIONS
// ============================================================

function rptFormatDate(isoStr) {
  if (!isoStr) return '—';
  try {
    var d = new Date(isoStr);
    return d.toLocaleDateString('en-SG', { day: '2-digit', month: 'short', year: 'numeric' });
  } catch(e) { return isoStr; }
}

function rptFormatDateTime(isoStr) {
  if (!isoStr) return '—';
  try {
    var d = new Date(isoStr);
    return d.toLocaleDateString('en-SG', { day: '2-digit', month: 'short' })
      + ' ' + d.toLocaleTimeString('en-SG', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false });
  } catch(e) { return isoStr; }
}

function rptGetInitials(name) {
  if (!name) return '?';
  var parts = name.trim().split(/[\s@.]+/);
  if (parts.length >= 2) return (parts[0][0] + parts[1][0]).toUpperCase();
  return parts[0].slice(0, 2).toUpperCase();
}

