async function loadThreatHuntingLive() {

  var page = document.getElementById('page-hunting');
  if (!page) return;
  console.log('[ThreatHunting] Initializing revamped page...');

  // Load data from SIEMLess DB (Supabase), fall back to seed
  _huntData = await _huntLoadDataFromDB();

  // Populate org selectors
  _huntPopulateOrgSelectors();

  // Render all panels
  _huntRenderActiveHunts();
  _huntRenderFindingsTable();
  _huntRenderKanban();
  _huntRenderPlaybooks();
  _huntRenderMitreMatrix();

  // Update KPIs
  _huntUpdateKPIs();

  // Populate findings filter dropdowns
  _huntPopulateFindingsFilters();

  // Try to enrich with live Elastic data
  _huntTryLiveElastic();

  console.log('[ThreatHunting] Page ready. Hunts:', _huntData.hunts.length);
}

// ─── Data persistence via SIEMLess DB ────────────────────────
async function _huntLoadDataFromDB() {
  var data = { hunts: [], findings: [], pipeline: [], playbooks: [] };
  try {
    if (!window._supabaseRef) throw new Error('SIEMLess DB not initialized');
    var sb = window._supabaseRef;
    var results = await Promise.all([
      sb.from('threat_hunts').select('*').order('created_at', { ascending: false }),
      sb.from('hunt_findings').select('*').order('date', { ascending: false }),
      sb.from('hunt_pipeline').select('*').order('id', { ascending: true }),
      sb.from('hunt_playbooks').select('*').order('id', { ascending: true })
    ]);
    var hunts = (results[0].data && results[0].data.length > 0) ? results[0].data : [];
    var findings = (results[1].data && results[1].data.length > 0) ? results[1].data : [];
    var pipeline = (results[2].data && results[2].data.length > 0) ? results[2].data : [];
    var playbooks = (results[3].data && results[3].data.length > 0) ? results[3].data : [];

    // Map DB rows to the expected JS format
    if (hunts.length > 0) {
      data.hunts = hunts.map(function(h) {
        return {
          id: h.id, name: h.name, status: h.status, severity: h.severity,
          mitre: (typeof h.mitre_techniques === 'string') ? JSON.parse(h.mitre_techniques) : (h.mitre_techniques || []),
          platform: h.platform, hunter: h.hunter,
          scope: (typeof h.scope === 'string') ? JSON.parse(h.scope) : (h.scope || ['all']),
          events_scanned: h.events_scanned || 0, suspects: h.suspects || 0,
          confirmed: h.confirmed || 0, query: h.query || '',
          created: h.created_at ? h.created_at.substring(0, 10) : '',
          desc: h.description || '', org_id: h.org_id || 'all'
        };
      });
    }
    if (findings.length > 0) {
      data.findings = findings.map(function(f) {
        return {
          id: f.id, date: f.date ? f.date.substring(0, 10) : '',
          hunt_id: f.hunt_id, hunt_name: f.hunt_name, severity: f.severity,
          status: f.status, ticket: f.ticket || '', rule: f.rule || '',
          details: f.details || '', iocs: f.iocs || []
        };
      });
    }
    if (pipeline.length > 0) {
      data.pipeline = pipeline.map(function(p) {
        return {
          hunt_name: p.hunt_name, stage: p.stage, criteria_met: p.criteria_met,
          criteria_total: p.criteria_total, note: p.note || '',
          rule: p.rule || '', deployed: p.deployed_date || ''
        };
      });
    }
    if (playbooks.length > 0) {
      data.playbooks = playbooks.map(function(pb) {
        return {
          id: pb.id, name: pb.name, level: pb.level, duration: pb.duration,
          last_run: pb.last_run || '',
          steps: (typeof pb.steps === 'string') ? JSON.parse(pb.steps) : (pb.steps || []),
          description: pb.description || ''
        };
      });
    }

    console.log('[ThreatHunting] Loaded from SIEMLess DB: ' + data.hunts.length + ' hunts, ' + data.findings.length + ' findings, ' + data.pipeline.length + ' pipeline, ' + data.playbooks.length + ' playbooks');
    return data;
  } catch (e) {
    console.warn('[ThreatHunting] SIEMLess DB load failed:', e.message);
  }
  // Return empty structure — no seed data fallback
  return { hunts: [], findings: [], pipeline: [], playbooks: [] };
}

function _huntSaveData(data) {
  // Save to localStorage as fast cache
  try {
    localStorage.setItem('dacta_hunts', JSON.stringify(data));
  } catch (e) { /* ignore */ }
}

// ─── Supabase DB persistence helpers ─────────────────────────
async function _huntUpsertHuntDB(hunt) {
  try {
    if (!window._supabaseRef) { console.warn('[TH] DB not available for upsert'); return; }
    var sb = window._supabaseRef;
    var row = {
      id: hunt.id,
      name: hunt.name,
      status: hunt.status,
      severity: hunt.severity,
      mitre_techniques: hunt.mitre || [],
      platform: hunt.platform,
      hunter: hunt.hunter,
      scope: hunt.scope || ['all'],
      events_scanned: hunt.events_scanned || 0,
      suspects: hunt.suspects || 0,
      confirmed: hunt.confirmed || 0,
      query: hunt.query || '',
      description: hunt.desc || '',
      org_id: (hunt.scope && hunt.scope[0]) ? hunt.scope[0] : 'all',
      updated_at: new Date().toISOString()
    };
    var res = await sb.from('threat_hunts').upsert(row, { onConflict: 'id' });
    if (res.error) console.warn('[TH] DB upsert hunt error:', res.error.message);
    else console.log('[TH] Hunt "' + hunt.name + '" persisted to DB');
  } catch (e) { console.warn('[TH] Hunt upsert failed:', e.message); }
}

async function _huntDeleteHuntDB(huntId) {
  try {
    if (!window._supabaseRef) return;
    var sb = window._supabaseRef;
    var res = await sb.from('threat_hunts').delete().eq('id', huntId);
    if (res.error) console.warn('[TH] DB delete hunt error:', res.error.message);
    else console.log('[TH] Hunt ' + huntId + ' deleted from DB');
  } catch (e) { console.warn('[TH] Hunt delete failed:', e.message); }
}

