function huntAIGeneratePlaybook() {
  huntOpenNewPlaybookModal();
  // Show loading state
  _huntSetFieldVal('new-pb-name', 'Generating...');
  _huntSetFieldVal('new-pb-steps', 'Calling DACTA AI...');
  showToast('Generating playbook via DACTA AI...', 'info');

  // Gather context from existing hunts
  var huntContext = '';
  if (_huntData && _huntData.hunts.length > 0) {
    var activeHunts = _huntData.hunts.filter(function(h) { return h.status === 'running' || h.status === 'scheduled'; });
    if (activeHunts.length > 0) {
      huntContext = 'Active hunts: ' + activeHunts.map(function(h) { return h.name + ' (' + (h.mitre || []).join(',') + ')'; }).join('; ');
    }
  }

  var prompt = 'You are a SOC threat hunting playbook generator. Generate a structured threat hunting playbook. ' +
    'Return ONLY valid JSON with these fields: name (string), level (BEGINNER/INTERMEDIATE/ADVANCED), duration (string like "2-3hrs"), ' +
    'focus (string describing what the playbook hunts for), steps (array of step strings, 5-8 steps). ' +
    (huntContext ? 'Context: ' + huntContext + '. Generate a complementary playbook that covers gaps. ' : 'Generate a playbook for detecting lateral movement and privilege escalation. ') +
    'Make it practical and actionable for a SOC analyst.';

  _siemFetch('/api/copilot', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ message: prompt, context: 'threat_hunting_playbook' })
  })
  .then(function(r) { return r.json(); })
  .then(function(data) {
    var aiText = (data.response || data.message || '').trim();
    // Try to extract JSON from the response
    var jsonMatch = aiText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        var pb = JSON.parse(jsonMatch[0]);
        _huntSetFieldVal('new-pb-name', pb.name || 'AI-Generated Hunt Playbook');
        _huntSetSelectVal('new-pb-level', pb.level || 'INTERMEDIATE');
        _huntSetFieldVal('new-pb-duration', pb.duration || '2-4hrs');
        _huntSetFieldVal('new-pb-focus', pb.focus || '');
        var stepsText = Array.isArray(pb.steps) ? pb.steps.join('\n') : (pb.steps || '');
        _huntSetFieldVal('new-pb-steps', stepsText);
        showToast('AI playbook generated — review and save.', 'success');
        return;
      } catch (e) { /* JSON parse failed, fall through */ }
    }
    // Fallback: use raw text
    _huntSetFieldVal('new-pb-name', 'AI-Generated Hunt Playbook');
    _huntSetSelectVal('new-pb-level', 'INTERMEDIATE');
    _huntSetFieldVal('new-pb-duration', '2-4hrs');
    _huntSetFieldVal('new-pb-focus', 'AI-generated threat hunting playbook');
    _huntSetFieldVal('new-pb-steps', aiText.substring(0, 2000));
    showToast('AI playbook generated — review and save.', 'success');
  })
  .catch(function(err) {
    console.warn('[TH] AI playbook generation failed:', err);
    // Fallback to template
    _huntSetFieldVal('new-pb-name', 'AI-Generated: Lateral Movement Detection');
    _huntSetSelectVal('new-pb-level', 'INTERMEDIATE');
    _huntSetFieldVal('new-pb-duration', '3-4hrs');
    _huntSetFieldVal('new-pb-focus', 'Lateral movement, privilege escalation, credential theft');
    _huntSetFieldVal('new-pb-steps',
      'Enumerate authentication events for pass-the-hash/ticket patterns\n' +
      'Identify SMB/WinRM lateral movement between non-standard host pairs\n' +
      'Correlate privilege escalation events with subsequent admin actions\n' +
      'Check for credential dumping tool signatures (mimikatz, rubeus)\n' +
      'Validate service account usage against baseline behavior'
    );
    showToast('AI unavailable — template pre-filled. Review and save.', 'warning');
  });
}

// ─── MITRE ATT&CK COVERAGE TAB ───────────────────────────────
function _huntRenderMitreMatrix() {
  var grid = document.getElementById('hunt-mitre-grid');
  if (!grid) return;

  // Build dynamic coverage map from _huntData
  var covMap = {}; // technique ID -> { coverage: 'covered'|'partial'|'gap', hunts: [] }
  if (_huntData) {
    // Active / running hunts -> covered
    // Scheduled / paused hunts -> partial
    // Completed hunts -> covered (graduated)
    var hunts = _huntData.hunts || [];
    for (var hi = 0; hi < hunts.length; hi++) {
      var h = hunts[hi];
      var mitreArr = h.mitre || [];
      var hStatus = (h.status || '').toLowerCase();
      var level = (hStatus === 'running' || hStatus === 'completed') ? 'covered' : 'partial';
      for (var mi = 0; mi < mitreArr.length; mi++) {
        var tid = mitreArr[mi];
        if (!covMap[tid]) covMap[tid] = { coverage: level, hunts: [] };
        else if (level === 'covered' && covMap[tid].coverage !== 'covered') covMap[tid].coverage = 'covered';
        covMap[tid].hunts.push(h.id);
      }
    }
    // Cross-reference pipeline with hunts to enrich coverage
    // Pipeline items link by hunt_name to the hunts (which have MITRE techniques)
    var pipeline = _huntData.pipeline || [];
    for (var pi = 0; pi < pipeline.length; pi++) {
      var p = pipeline[pi];
      if (p.stage === 'graduated' && p.rule) {
        // Find matching hunt by name to get MITRE techniques
        var pName = (p.hunt_name || '').toLowerCase();
        for (var phi = 0; phi < hunts.length; phi++) {
          if ((hunts[phi].name || '').toLowerCase().indexOf(pName) !== -1 || pName.indexOf((hunts[phi].name || '').toLowerCase().split(' ')[0]) !== -1) {
            var pmitreArr = hunts[phi].mitre || [];
            for (var pmi = 0; pmi < pmitreArr.length; pmi++) {
              var ptid = pmitreArr[pmi];
              if (!covMap[ptid]) covMap[ptid] = { coverage: 'covered', hunts: [] };
              else covMap[ptid].coverage = 'covered';
              covMap[ptid].hunts.push('graduated\u2192' + p.rule);
            }
          }
        }
      }
    }
  }

  grid.innerHTML = '';
  var coveredTotal = 0, partialTotal = 0, gapTotal = 0, naTotal = 0;

  for (var ti = 0; ti < HUNT_MITRE_TACTICS.length; ti++) {
    var tactic = HUNT_MITRE_TACTICS[ti];
    var col = document.createElement('div');
    col.className = 'hunt-mitre-tactic-col';

    var headerDiv = document.createElement('div');
    headerDiv.className = 'hunt-mitre-tactic-header';
    headerDiv.innerHTML = '<div>' + escapeHtml(tactic.name) + '<br><span style="font-size:8px;opacity:0.6;">' + escapeHtml(tactic.id) + '</span></div>';
    col.appendChild(headerDiv);

    var techs = tactic.techniques || [];
    for (var tei = 0; tei < techs.length; tei++) {
      var tech = techs[tei];
      // Compute coverage dynamically
      var dynCov = covMap[tech.id];
      var coverage = tech.na ? 'na' : (dynCov ? dynCov.coverage : 'gap');
      var relatedHunts = dynCov ? dynCov.hunts : [];

      // Attach computed coverage to tech object for modal display
      tech.coverage = coverage;
      tech.hunts = relatedHunts;

      var techDiv = document.createElement('div');
      techDiv.className = 'hunt-mitre-tech hunt-mitre-' + coverage;
      techDiv.title = tech.id + ': ' + tech.name;
      techDiv.innerHTML = escapeHtml(tech.id);
      (function(t, tacticId) {
        techDiv.onclick = function() { huntShowMitreTechDetail(t, tacticId); };
      })(tech, tactic.id);
      col.appendChild(techDiv);

      if (coverage === 'covered') coveredTotal++;
      else if (coverage === 'partial') partialTotal++;
      else if (coverage === 'gap') gapTotal++;
      else naTotal++;
    }
    grid.appendChild(col);
  }

  // Update stats
  var totalActives = coveredTotal + partialTotal + gapTotal;
  var pct = totalActives > 0 ? Math.round(((coveredTotal + partialTotal * 0.5) / totalActives) * 100) : 0;
  _huntSetEl('hunt-mitre-covered-count', coveredTotal);
  _huntSetEl('hunt-mitre-partial-count', partialTotal);
  _huntSetEl('hunt-mitre-gap-count', gapTotal);
  _huntSetEl('hunt-mitre-pct', pct + '%');
}

function huntShowMitreTechDetail(tech, tacticId) {
  var overlay = document.getElementById('hunt-mitre-modal-overlay');
  if (!overlay) return;

  var coverageLabel = { covered: 'Fully Covered', partial: 'Partial Coverage', gap: 'Coverage Gap', na: 'Not Applicable' };
  var coverageColor = { covered: '#10b981', partial: '#f59e0b', gap: '#ef4444', na: '#475569' };

  var relatedHunts = '';
  var hunts = tech.hunts || [];
  if (hunts.length > 0) {
    relatedHunts = '<div class="hunt-detail-section">' +
      '<div class="hunt-detail-label">Related Hunts</div>';
    for (var i = 0; i < hunts.length; i++) {
      relatedHunts += '<span style="font-family:\'IBM Plex Mono\',monospace;font-size:11px;color:#00d4ff;background:rgba(0,212,255,0.07);border:1px solid rgba(0,212,255,0.15);padding:2px 8px;border-radius:4px;margin-right:6px;">' + escapeHtml(hunts[i]) + '</span>';
    }
    relatedHunts += '</div>';
  }

  var generateBtn = tech.coverage !== 'covered' ?
    '<button class="btn btn-primary btn-sm" onclick="huntGenerateHuntForGap(\'' + escapeHtml(tech.id) + '\',\'' + escapeHtml(tech.name) + '\');huntCloseModal(\'hunt-mitre-modal-overlay\');">Generate Hunt for Gap</button>' : '';

  var body =
    '<div class="hunt-detail-section">' +
      '<div class="hunt-detail-label">Technique</div>' +
      '<div style="font-family:\'IBM Plex Mono\',monospace;font-size:13px;color:#00d4ff;">' + escapeHtml(tech.id) + '</div>' +
      '<div style="font-size:13px;color:var(--text-primary);margin-top:4px;">' + escapeHtml(tech.name) + '</div>' +
    '</div>' +
    '<div class="hunt-detail-section">' +
      '<div class="hunt-detail-label">Coverage Status</div>' +
      '<div style="font-size:13px;font-weight:600;color:' + (coverageColor[tech.coverage] || '#fff') + ';">' + (coverageLabel[tech.coverage] || tech.coverage) + '</div>' +
    '</div>' +
    relatedHunts +
    '<div class="hunt-form-actions">' +
      '<button class="btn btn-secondary btn-sm" onclick="huntCloseModal(\'hunt-mitre-modal-overlay\')">Close</button>' +
      generateBtn +
    '</div>';

  var titleEl = document.getElementById('hunt-mitre-modal-title');
  if (titleEl) titleEl.textContent = tech.id + ': ' + tech.name;
  var bodyEl = document.getElementById('hunt-mitre-modal-body');
  if (bodyEl) bodyEl.innerHTML = body;

  overlay.classList.add('open');
}

function huntGenerateHuntForGap(techId, techName) {
  huntCloseModal('hunt-mitre-modal-overlay');
  // Open AI generate modal pre-configured for this technique
  huntOpenAIGenerateModal();
  // Set the tactic from technique prefix if possible
  showToast('AI Hunt Generator opened for technique ' + techId + ': ' + techName, 'info');
}

function huntExportNavigatorJSON() {
  var layers = [];
  for (var ti = 0; ti < HUNT_MITRE_TACTICS.length; ti++) {
    var tactic = HUNT_MITRE_TACTICS[ti];
    var techs = tactic.techniques || [];
    for (var tei = 0; tei < techs.length; tei++) {
      var tech = techs[tei];
      var covStatus = tech.coverage || 'gap';
      if (covStatus === 'na') continue;
      var score = covStatus === 'covered' ? 100 : (covStatus === 'partial' ? 50 : 0);
      var color = covStatus === 'covered' ? '#10b981' : (covStatus === 'partial' ? '#f59e0b' : '#ef4444');
      layers.push({
        techniqueID: tech.id.split('.')[0],
        tactic: tactic.id,
        score: score,
        color: color,
        comment: covStatus === 'covered' ? 'Hunted: ' + (tech.hunts || []).join(', ') : covStatus
      });
    }
  }
  var nav = {
    name: 'DACTA Threat Hunting Coverage',
    versions: { attack: '14', navigator: '4.9', layer: '4.5' },
    domain: 'enterprise-attack',
    description: 'Generated by DACTA SIEMLess MSSP Platform',
    techniques: layers,
    gradient: { colors: ['#ef4444','#f59e0b','#10b981'], minValue: 0, maxValue: 100 },
    legendItems: [
      { label: 'No Coverage', color: '#ef4444' },
      { label: 'Partial Coverage', color: '#f59e0b' },
      { label: 'Full Coverage', color: '#10b981' }
    ]
  };
  var json = JSON.stringify(nav, null, 2);
  try {
    var blob = new Blob([json], { type: 'application/json' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url;
    a.download = 'dacta_att&ck_navigator.json';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    showToast('Navigator JSON exported successfully.', 'success');
  } catch (e) {
    navigator.clipboard.writeText(json);
    showToast('JSON copied to clipboard.', 'success');
  }
}

