function huntAIPreviewGenerate() {
  var tactic = _huntGetSelectVal('ai-hunt-tactic') || 'TA0001';
  var actor = _huntGetSelectVal('ai-hunt-actor') || 'generic';
  var platform = _huntGetSelectVal('ai-hunt-platform') || 'KQL';
  var client = _huntGetSelectVal('ai-hunt-client') || 'all';

  var preview = document.getElementById('ai-hunt-preview');
  if (preview) preview.innerHTML = '<div style="display:flex;align-items:center;gap:8px;color:#00d4ff;"><div class="spinner" style="width:16px;height:16px;border:2px solid rgba(0,212,255,0.2);border-top-color:#00d4ff;border-radius:50%;animation:spin 0.8s linear infinite;"></div> DACTA AI generating hunt hypothesis...</div>';

  var queryWrap = document.getElementById('ai-hunt-query-wrap');
  if (queryWrap) queryWrap.style.display = 'none';

  var tacticNames = {
    'TA0001':'Initial Access','TA0002':'Execution','TA0003':'Persistence','TA0004':'Privilege Escalation',
    'TA0005':'Defense Evasion','TA0006':'Credential Access','TA0007':'Discovery','TA0008':'Lateral Movement',
    'TA0009':'Collection','TA0010':'Exfiltration','TA0011':'Command & Control','TA0040':'Impact',
    'TA0042':'Resource Development','TA0043':'Reconnaissance'
  };
  var tacticName = tacticNames[tactic] || tactic;

  var prompt = 'You are a SOC threat hunting expert. Generate a hunt hypothesis and detection query for:\n' +
    '- MITRE Tactic: ' + tactic + ' (' + tacticName + ')\n' +
    '- Threat Actor: ' + actor + '\n' +
    '- Query Language: ' + platform + '\n\n' +
    'Return ONLY valid JSON with fields: hypothesis (string, 2-3 sentences), query (string, the detection query in ' + platform + ' syntax), techniques (array of MITRE technique IDs like T1566.001). Make it production-ready.';

  _siemFetch('/api/copilot', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ message: prompt, context: 'threat_hunt_generation' })
  })
  .then(function(r) { return r.json(); })
  .then(function(data) {
    var aiText = (data.response || data.message || '').trim();
    var jsonMatch = aiText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        var result = JSON.parse(jsonMatch[0]);
        if (preview) preview.innerHTML = '<em style="color:#00d4ff;">' + dIcon('sparkle',14) + ' AI Hypothesis:</em><br><br>' + escapeHtml(result.hypothesis || 'No hypothesis generated');
        var queryEl = document.getElementById('ai-hunt-query');
        if (queryEl) queryEl.value = result.query || '// AI query generation pending';
        if (queryWrap) queryWrap.style.display = 'block';
        showToast('AI hypothesis generated successfully.', 'success');
        return;
      } catch (e) { /* fall through */ }
    }
    // Fallback: show raw text
    if (preview) preview.innerHTML = '<em style="color:#00d4ff;">' + dIcon('sparkle',14) + ' AI Hypothesis:</em><br><br>' + escapeHtml(aiText.substring(0, 500));
    showToast('AI hypothesis generated.', 'success');
  })
  .catch(function(err) {
    console.warn('[TH] AI preview failed:', err);
    // Fallback to local generation
    _huntAIPreviewFallback(tactic, actor, platform, tacticName);
  });
}

function _huntAIPreviewFallback(tactic, actor, platform, tacticName) {
  var preview = document.getElementById('ai-hunt-preview');
  var queryWrap = document.getElementById('ai-hunt-query-wrap');
  var hypothesis = 'Hunt for ' + actor + ' ' + tacticName.toLowerCase() + ' TTPs targeting endpoints in scope. Focus on behavioral indicators consistent with known ' + actor + ' tradecraft for ' + tactic + '.';
  if (preview) preview.innerHTML = '<em style="color:#00d4ff;">' + dIcon('sparkle',14) + ' Hypothesis (local):</em><br><br>' + escapeHtml(hypothesis);
  var fallbackQueries = {
    'KQL': {
      'TA0001': 'SecurityEvent\n| where EventID == 4688\n| where NewProcessName endswith_cs ".iso" or NewProcessName endswith_cs ".img"\n| project TimeGenerated, Computer, Account, NewProcessName, CommandLine',
      'TA0002': 'DeviceProcessEvents\n| where FileName in~ ("mshta.exe","certutil.exe","regsvr32.exe","wscript.exe")\n| where InitiatingProcessFileName !in~ ("explorer.exe","svchost.exe")\n| summarize count() by FileName, InitiatingProcessFileName, DeviceName',
      'TA0011': 'DeviceNetworkEvents\n| where RemotePort in (80,443,8080,8443)\n| summarize ConnCount=count() by RemoteIP, DeviceName, bin(Timestamp, 1h)\n| where ConnCount between (50..120)'
    },
    'SPL': {
      'TA0001': 'index=email sourcetype=exchange_logs\n    (attachment_name="*.iso" OR attachment_name="*.img")\n| stats count by src_user, attachment_name',
      'TA0002': 'index=sysmon EventCode=1\n    (process_name="mshta.exe" OR process_name="certutil.exe")\n| stats count by dest, process_name',
      'TA0011': 'index=network sourcetype=palo_alto_traffic dest_port=443\n| bucket span=5m _time\n| stats count AS conn_count by dest_ip, src_ip, _time\n| where conn_count>10'
    },
    'EQL': {
      'TA0001': 'sequence by host.name with maxspan=5m\n  [process where process.name == "outlook.exe"]\n  [process where process.name in ("mshta.exe", "rundll32.exe")]',
      'TA0002': 'process where process.name in ("mshta.exe","certutil.exe","regsvr32.exe")\n  and process.parent.name not in ("svchost.exe","services.exe")',
      'TA0011': 'network where network.direction == "outbound"\n  and destination.port in (80, 443)\n  and process.name != "chrome.exe"'
    }
  };
  var querySet = fallbackQueries[platform] || fallbackQueries['KQL'];
  var queryText = querySet[tactic] || '// Modify detection query for ' + tacticName + ' based on your environment';
  var queryEl = document.getElementById('ai-hunt-query');
  if (queryEl) queryEl.value = queryText;
  if (queryWrap) queryWrap.style.display = 'block';
  showToast('AI unavailable — local hypothesis generated.', 'warning');
}

function huntAILaunchCopilot() {
  var tactic = _huntGetSelectVal('ai-hunt-tactic') || '';
  var actor = _huntGetSelectVal('ai-hunt-actor') || '';
  var query = _huntGetFieldVal('ai-hunt-query') || '';

  if (typeof window._copilotContext !== 'undefined') {
    window._copilotContext = {
      mode: 'hunt_generation',
      tactic: tactic,
      actor: actor,
      query_seed: query,
      source: 'threat_hunting_page'
    };
  }

  huntCloseModal('hunt-ai-modal-overlay');
  showToast('Opening AI Copilot for hunt generation...', 'info');
  if (typeof navigate === 'function') {
    navigate('copilot');
  }
}


// ═══ TI Action Functions (wired from toast-only buttons) ═════════
function tiLaunchHunt(actorName, tactic) {
  showToast('Creating hunt for ' + actorName + ' — navigating to Threat Hunting...', 'info');
  if (typeof navigate === 'function') {
    navigate('hunting');
    setTimeout(function() {
      // Open the AI Generate Hunt modal pre-populated
      if (typeof huntOpenAIGenerateModal === 'function') {
        huntOpenAIGenerateModal();
        // Try to set the actor select
        var actorSel = document.getElementById('ai-hunt-actor');
        if (actorSel) {
          for (var i = 0; i < actorSel.options.length; i++) {
            if (actorSel.options[i].text.toLowerCase().indexOf(actorName.toLowerCase()) !== -1 ||
                actorSel.options[i].value.toLowerCase().indexOf(actorName.toLowerCase()) !== -1) {
              actorSel.selectedIndex = i;
              break;
            }
          }
        }
        // Set tactic
        var tacticSel = document.getElementById('ai-hunt-tactic');
        if (tacticSel) {
          for (var j = 0; j < tacticSel.options.length; j++) {
            if (tacticSel.options[j].value === tactic) { tacticSel.selectedIndex = j; break; }
          }
        }
      }
    }, 500);
  }
}

function tiPushIOCsToSIEM(actorName) {
  showToast('Queuing ' + actorName + ' IOCs for SIEM push...', 'info');
  // Switch to SIEM Push tab
  if (typeof switchTiTab === 'function') {
    switchTiTab('siem');
  }
  showToast(actorName + ' IOCs queued for SIEM push — check SIEM Push tab.', 'success');
}

function tiAddToWatchlist(actorName) {
  // Persist to localStorage watchlist
  var watchlist = [];
  try { watchlist = JSON.parse(localStorage.getItem('dacta_ti_watchlist') || '[]'); } catch(e) {}
  if (watchlist.indexOf(actorName) === -1) {
    watchlist.push(actorName);
    localStorage.setItem('dacta_ti_watchlist', JSON.stringify(watchlist));
    showToast(actorName + ' added to watchlist.', 'success');
  } else {
    showToast(actorName + ' is already on your watchlist.', 'info');
  }
}

function tiRemoveFromWatchlist(actorName, btnEl) {
  if (!confirm('Remove ' + actorName + ' from watchlist?')) return;
  var watchlist = [];
  try { watchlist = JSON.parse(localStorage.getItem('dacta_ti_watchlist') || '[]'); } catch(e) {}
  var idx = watchlist.indexOf(actorName);
  if (idx !== -1) watchlist.splice(idx, 1);
  localStorage.setItem('dacta_ti_watchlist', JSON.stringify(watchlist));
  // Remove the card from DOM
  var card = btnEl ? btnEl.closest('.tip-actor-watchlist-card, .tip-card, div[style]') : null;
  if (card) {
    card.style.opacity = '0';
    card.style.transform = 'scale(0.95)';
    card.style.transition = 'all 0.3s ease';
    setTimeout(function() { card.remove(); }, 300);
  }
  showToast(actorName + ' removed from watchlist.', 'success');
}

function tiPushToHuntingModule() {
  showToast('Hunt job pushed to Threat Hunting module.', 'success');
  // Navigate to hunting page after a short delay
  setTimeout(function() {
    if (typeof navigate === 'function') navigate('hunting');
  }, 1200);
}

function tiPublishReport() {
  showToast('Report published to client portal.', 'success');
  // Update the status badge if visible
  var badges = document.querySelectorAll('.tip-badge-draft, .rpt-badge-draft');
  for (var i = 0; i < badges.length; i++) {
    badges[i].textContent = 'PUBLISHED';
    badges[i].className = badges[i].className.replace('draft', 'published');
    badges[i].style.background = 'rgba(16,185,129,0.15)';
    badges[i].style.color = '#10b981';
    badges[i].style.borderColor = 'rgba(16,185,129,0.25)';
  }
}

// ─── LIVE ELASTIC ENRICHMENT ─────────────────────────────────
function _huntTryLiveElastic() {
  // Try to query Elastic for live event count to update KPI
  try {
    _siemFetch('/api/elastic', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        action: 'search',
        index: 'logs-*',
        body: { query: { range: { '@timestamp': { gte: 'now-7d' } } }, size: 0 }
      })
    })
    .then(function(r) { return r.json(); })
    .then(function(data) {
      if (data && data.hits && data.hits.total && data.hits.total.value) {
        var count = data.hits.total.value;
        console.log('[ThreatHunting] Live log count (7d):', count);
        // Update first running hunt's events_scanned with live count if available
        if (_huntData && _huntData.hunts[0] && _huntData.hunts[0].status === 'running') {
          _huntData.hunts[0].events_scanned = count;
          _huntSaveData(_huntData);
          _huntRenderActiveHunts();
        }
      }
    })
    .catch(function(e) {
      console.log('[ThreatHunting] Elastic enrichment unavailable:', e.message);
    });
  } catch (e) {
    console.log('[ThreatHunting] Elastic not reachable.');
  }
}

