    var icon = iconMap[c.connector_type] || '<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" style="display:inline-flex;vertical-align:middle;flex-shrink:0;"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>';
    var label = labelMap[c.connector_type] || c.connector_type;
    var cid = orgId + '__' + idx;

    // ── Type-specific config hints ──
    // Vendor-specific config hints (keyed by vendor name lowercase, then by connector_type)
    var vendorConfigHints = {
      'crowdstrike': { endpoint_label: 'CrowdStrike API Base URL', endpoint_hint: 'https://api.us-2.crowdstrike.com', auth_hint: 'OAuth2 Client ID + Secret', needs_endpoint: true, auth_type_default: 'oauth2_client_credentials', cred_fields: ['client_id', 'client_secret'] },
      'trendmicro': { endpoint_label: 'Trend Vision One API URL', endpoint_hint: 'https://api.xdr.trendmicro.com', auth_hint: 'Vision One API Token (Bearer)', needs_endpoint: true, auth_type_default: 'token', cred_fields: ['api_token'] },
      'trend micro': { endpoint_label: 'Trend Vision One API URL', endpoint_hint: 'https://api.xdr.trendmicro.com', auth_hint: 'Vision One API Token (Bearer)', needs_endpoint: true, auth_type_default: 'token', cred_fields: ['api_token'] },
      'heimdal': { endpoint_label: 'Heimdal API Base URL', endpoint_hint: 'https://dashboard.heimdalsecurity.com/api/heimdalapi/2.0', auth_hint: 'API Key + Customer ID', needs_endpoint: true, auth_type_default: 'api_key', cred_fields: ['api_key', 'customer_id'] },
      'fortinet': { endpoint_label: 'FortiGate / FortiAnalyzer URL', endpoint_hint: 'https://fortianalyzer.example.com', auth_hint: 'API Key or Admin Credentials', needs_endpoint: true, auth_type_default: 'api_key', cred_fields: ['api_key'] },
      'fortigate': { endpoint_label: 'FortiGate Management URL', endpoint_hint: 'https://fortigate.example.com', auth_hint: 'API Key (access_token)', needs_endpoint: true, auth_type_default: 'api_key', cred_fields: ['api_key'] },
      'palo alto': { endpoint_label: 'PAN-OS / Cortex Data Lake URL', endpoint_hint: 'https://api.us.cdl.paloaltonetworks.com', auth_hint: 'API Key or OAuth2', needs_endpoint: true, auth_type_default: 'api_key', cred_fields: ['api_key', 'api_type'] },
      'paloalto': { endpoint_label: 'PAN-OS / Cortex Data Lake URL', endpoint_hint: 'https://api.us.cdl.paloaltonetworks.com', auth_hint: 'API Key or OAuth2', needs_endpoint: true, auth_type_default: 'api_key', cred_fields: ['api_key', 'api_type'] },
      'imperva': { endpoint_label: 'Imperva Cloud WAF API URL', endpoint_hint: 'https://my.imperva.com/api', auth_hint: 'API ID + API Key', needs_endpoint: true, auth_type_default: 'api_key', cred_fields: ['api_id', 'api_key', 'account_id', 'site_id'] },
      'elastic': { endpoint_label: 'Elastic Cluster URL', endpoint_hint: 'https://your-cluster.es.region.cloud', auth_hint: 'API Key or Basic Auth', needs_endpoint: true, auth_type_default: 'api_key', cred_fields: ['api_key'] },
      'microsoft': { endpoint_label: 'Microsoft Graph / Entra ID URL', endpoint_hint: 'https://graph.microsoft.com', auth_hint: 'OAuth2 Client Credentials', needs_endpoint: true, auth_type_default: 'oauth2_client_credentials', cred_fields: ['client_id', 'client_secret', 'tenant_id'] },
      'okta': { endpoint_label: 'Okta Domain', endpoint_hint: 'https://your-org.okta.com', auth_hint: 'API Token', needs_endpoint: true, auth_type_default: 'token', cred_fields: ['token'] },
      'sophos': { endpoint_label: 'Sophos Central API URL', endpoint_hint: 'https://api.central.sophos.com', auth_hint: 'OAuth2 Client Credentials', needs_endpoint: true, auth_type_default: 'oauth2_client_credentials', cred_fields: ['client_id', 'client_secret'] },
      'sentinelone': { endpoint_label: 'SentinelOne Console API URL', endpoint_hint: 'https://your-tenant.sentinelone.net', auth_hint: 'API Token', needs_endpoint: true, auth_type_default: 'token', cred_fields: ['api_token'] },
      'atlassian': { endpoint_label: 'Atlassian Instance URL', endpoint_hint: 'https://company.atlassian.net', auth_hint: 'API Token + Email', needs_endpoint: true, auth_type_default: 'basic', cred_fields: ['username', 'api_token'] },
      'confluence': { endpoint_label: 'Confluence Instance URL', endpoint_hint: 'https://company.atlassian.net/wiki', auth_hint: 'API Token + Email', needs_endpoint: true, auth_type_default: 'basic', cred_fields: ['username', 'api_token'] }
    };
    var typeConfigHints = {
      siem: { endpoint_label: 'SIEM URL', endpoint_hint: 'https://your-siem.example.com', auth_hint: 'API Key or Basic Auth', needs_endpoint: true },
      edr: { endpoint_label: 'EDR API Base URL', endpoint_hint: 'https://api.vendor.com', auth_hint: 'OAuth2 or API Token', needs_endpoint: true },
      firewall: { endpoint_label: 'Management API / Analyzer URL', endpoint_hint: 'https://firewall-mgmt.example.com', auth_hint: 'API Key or Token', needs_endpoint: true },
      threat_intel: { endpoint_label: 'TIP Endpoint', endpoint_hint: 'https://tip.example.com', auth_hint: 'API Token', needs_endpoint: true },
      ticketing: { endpoint_label: 'Instance URL', endpoint_hint: 'https://company.atlassian.net', auth_hint: 'API Token + Email', needs_endpoint: true },
      identity: { endpoint_label: 'Directory Endpoint', endpoint_hint: 'https://graph.microsoft.com or Okta domain', auth_hint: 'OAuth2 or API Token', needs_endpoint: true },
      email_security: { endpoint_label: 'API Endpoint', endpoint_hint: 'https://api.vendor.com', auth_hint: 'API Key', needs_endpoint: true },
      cloud_security: { endpoint_label: 'API Endpoint', endpoint_hint: 'AWS Security Hub / Azure Sentinel URL', auth_hint: 'IAM Role or API Key', needs_endpoint: true },
      vulnerability: { endpoint_label: 'Scanner API URL', endpoint_hint: 'https://cloud.tenable.com/api', auth_hint: 'API Key', needs_endpoint: true }
    };
    // Resolve: vendor-specific first, then type fallback
    var vendorKey = (c.vendor || '').toLowerCase().replace(/\s+/g, '');
    var vendorKeySpaced = (c.vendor || '').toLowerCase();
    var hint = vendorConfigHints[vendorKey] || vendorConfigHints[vendorKeySpaced] || typeConfigHints[c.connector_type] || { endpoint_label: 'API Endpoint', endpoint_hint: '', auth_hint: 'API Key', needs_endpoint: true };

    // Parse credentials_ref (JSON string or object)
    var creds = c.credentials_ref || {};
    if (typeof creds === 'string') { try { creds = JSON.parse(creds); } catch(e) { creds = {}; } }
    var hasApiEndpoint = !!(c.api_endpoint);
    var hasCreds = !!(creds.client_id || creds.api_key || creds.token || creds.username);
    // Config is complete if: has both endpoint + creds, OR connection was tested healthy, OR has creds with a known-default endpoint vendor
    var configComplete = (hasApiEndpoint && hasCreds) || (c.health_status === 'healthy') || (hasCreds && !hint.needs_endpoint) || (hasApiEndpoint && !hint.needs_creds);
    var configBadge = configComplete ? '<span style="font-size:8px;padding:1px 5px;background:rgba(34,197,94,0.1);color:#22c55e;border:1px solid rgba(34,197,94,0.2);border-radius:3px;margin-left:6px;">API Configured</span>'
      : '<span style="font-size:8px;padding:1px 5px;background:rgba(245,158,11,0.1);color:#f59e0b;border:1px solid rgba(245,158,11,0.2);border-radius:3px;margin-left:6px;">Needs Config</span>';

    // Build metadata fields as editable rows
    var metaKeys = Object.keys(c.metadata || {});
    var metaHtml = '';
    metaKeys.forEach(function(k) {
      metaHtml += '<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px;">' +
        '<span style="font-size:9px;color:var(--text-muted);min-width:75px;text-transform:uppercase;letter-spacing:0.3px;">' + k.replace(/_/g,' ') + '</span>' +
        '<input class="filter-input stg-meta-input" data-cid="' + cid + '" data-key="' + k + '" value="' + String(c.metadata[k] || '').replace(/"/g,'&quot;') + '" ' +
          'style="flex:1;font-size:10px;font-family:var(--font-mono);padding:3px 6px;background:var(--bg-elevated);border-color:var(--border-card);color:var(--text-secondary);">' +
      '</div>';
    });

    // ── Auth type options ──
    var authTypeOpts = ['api_key','oauth2_client_credentials','token','basic'].map(function(at) {
      var sel = (c.auth_type || 'api_key') === at ? ' selected' : '';
      var lbl = { api_key: 'API Key', oauth2_client_credentials: 'OAuth2 Client Credentials', token: 'Bearer Token', basic: 'Basic Auth (user:pass)' }[at] || at;
      return '<option value="' + at + '"' + sel + '>' + lbl + '</option>';
    }).join('');

    // ── Credential fields based on auth_type ──
    var authType = c.auth_type || 'api_key';
