var _ssoSettingsEnabled = false;

function toggleSSOEnabled() {
  _ssoSettingsEnabled = !_ssoSettingsEnabled;
  var knob = document.getElementById('ssoMasterKnob');
  var toggle = document.getElementById('ssoMasterToggle');
  var cards = document.getElementById('ssoProviderCards');
  if (_ssoSettingsEnabled) {
    if (knob) { knob.style.left = '18px'; knob.style.background = 'var(--green)'; }
    if (toggle) { toggle.style.background = 'rgba(16,185,129,0.3)'; toggle.style.borderColor = 'rgba(16,185,129,0.5)'; }
    if (cards) cards.style.display = 'block';
  } else {
    if (knob) { knob.style.left = '2px'; knob.style.background = 'var(--text-muted)'; }
    if (toggle) { toggle.style.background = 'var(--bg-input)'; toggle.style.borderColor = 'var(--border-card)'; }
    if (cards) cards.style.display = 'none';
  }
}

async function saveSSOConfig() {
  try {
    var cfg = { enabled: _ssoSettingsEnabled, providers: {} };
    ['azure_ad', 'okta', 'google_workspace'].forEach(function(provKey) {
      var check = document.querySelector('.sso-provider-check[data-provider="' + provKey + '"]');
      if (check && check.checked) {
        var domainInput = document.querySelector('.sso-cfg-input[data-provider="' + provKey + '"][data-field="domain"]');
        var pidInput = document.querySelector('.sso-cfg-input[data-provider="' + provKey + '"][data-field="provider_id"]');
        cfg.providers[provKey] = {
          enabled: true,
          domain: domainInput ? domainInput.value.trim() : '',
          provider_id: pidInput ? pidInput.value.trim() : ''
        };
      }
    });
    // Save to platform_settings table
    if (window._supabaseRef) {
      var { error } = await window._supabaseRef.from('platform_settings').upsert({
        key: 'sso_config',
        value: cfg,
        updated_at: new Date().toISOString()
      }, { onConflict: 'key' });
      if (error) {
        console.warn('[SSO] Save error:', error.message);
        // Fallback to localStorage
        localStorage.setItem('dacta_sso_config', JSON.stringify(cfg));
      }
    } else {
      localStorage.setItem('dacta_sso_config', JSON.stringify(cfg));
    }
    showToast('SSO configuration saved', 'success');
  } catch(e) {
    showToast('Failed to save SSO config: ' + e.message, 'error');
  }
}

// Load SSO settings into the admin UI on Settings page open
async function loadSSOSettingsUI() {
  try {
    var cfg = null;
    if (window._supabaseRef) {
      var resp = await window._supabaseRef.from('platform_settings').select('*').eq('key', 'sso_config').maybeSingle();
      if (resp.data && resp.data.value) {
        cfg = typeof resp.data.value === 'string' ? JSON.parse(resp.data.value) : resp.data.value;
      }
    }
    if (!cfg) {
      try { cfg = JSON.parse(localStorage.getItem('dacta_sso_config')); } catch(e) {}
    }
    if (!cfg) return;

    // Set master toggle
    if (cfg.enabled) {
      _ssoSettingsEnabled = false; // toggleSSOEnabled will flip it
      toggleSSOEnabled();
    }

    // Populate provider checkboxes and fields
    ['azure_ad', 'okta', 'google_workspace'].forEach(function(provKey) {
      var provCfg = cfg.providers && cfg.providers[provKey];
      var check = document.querySelector('.sso-provider-check[data-provider="' + provKey + '"]');
      if (check) check.checked = !!provCfg;
      if (provCfg) {
        var domainInput = document.querySelector('.sso-cfg-input[data-provider="' + provKey + '"][data-field="domain"]');
        var pidInput = document.querySelector('.sso-cfg-input[data-provider="' + provKey + '"][data-field="provider_id"]');
        if (domainInput && provCfg.domain) domainInput.value = provCfg.domain;
        if (pidInput && provCfg.provider_id) pidInput.value = provCfg.provider_id;
      }
    });
  } catch(e) {
    console.warn('[SSO] loadSSOSettingsUI error:', e.message);
  }
}

// Load persisted connector configs on startup
async function loadPersistedConnectors() {
  try {
    // DB is the single source of truth — if already loaded, nothing to do
    if (_orgConnectorsLoadedFromDB) return;
    
    // Try loading from DB directly
    if (window._supabaseRef) {
      await loadOrgConnectorsFromDB();
    }
    // Note: localStorage fallback removed — DB is authoritative.
    // This prevents deleted connectors from being re-injected by stale local data.
  } catch(e) { console.warn('[Settings] Load persisted failed:', e.message); }
}


async function testAndUpdateHealth(cid) {
  var parts = cid.split('__');
  var orgId = parts[0];
  var org = ORG_CONNECTORS[orgId];
  if (!org) return;
  var c = org.connectors[parseInt(parts[1])];
  if (!c) return;
  if (!c.is_enabled) {
    c.health_status = 'not_configured';
    showToast('Connector is disabled — enable it first to test', 'warn');
    renderSettingsConnectors();
    return;
  }
  // Show testing state
  var btn = document.querySelector('#stg-card-' + cid + ' .stg-conn-test-btn');
  if (btn) { btn.textContent = '⌛ Testing...'; btn.disabled = true; }
  try {
    var ok = false;
    var detail = '';
    // Determine vendor-specific proxy endpoint
    var vendorLower = (c.vendor || '').toLowerCase();
    if (c.connector_type === 'siem') {
      var r = await _siemFetch('/api/elastic', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ action: 'cluster_health', namespace: org.namespace }) });
      if (r.ok) { var d = await r.json(); ok = d.status && d.status !== 'red'; detail = d.status || 'unknown'; }
    } else if (c.connector_type === 'edr') {
      // Route to correct vendor API proxy
      if (vendorLower.includes('crowdstrike') || vendorLower.includes('falcon')) {
        var r2 = await _siemFetch('/api/crowdstrike', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ action: 'ping', org_id: orgId }) });
        ok = r2.ok; if (r2.ok) { var d2 = await r2.json(); detail = d2.status || 'connected'; }
      } else if (vendorLower.includes('trend') || vendorLower.includes('vision')) {
        var r2b = await _siemFetch('/api/trendmicro', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ action: 'ping', org_id: orgId }) });
        ok = r2b.ok; if (r2b.ok) { var d2b = await r2b.json(); detail = d2b.status || 'connected'; }
      } else if (vendorLower.includes('heimdal')) {
        var r2c = await _siemFetch('/api/heimdal', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ action: 'ping', org_id: orgId }) });
        ok = r2c.ok; if (r2c.ok) { var d2c = await r2c.json(); detail = d2c.status || 'connected'; }
      } else {
        // Generic EDR — check if api_endpoint is configured
        ok = !!(c.api_endpoint); detail = ok ? 'endpoint configured' : 'no API endpoint';
      }
    } else if (c.connector_type === 'firewall') {
      if (vendorLower.includes('fortinet') || vendorLower.includes('fortigate')) {
        var r3a = await _siemFetch('/api/fortinet', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ action: 'ping', org_id: orgId }) });
        ok = r3a.ok; if (r3a.ok) { var d3a = await r3a.json(); detail = d3a.status || 'connected'; }
      } else if (vendorLower.includes('palo') || vendorLower.includes('pan-os')) {
        var r3b = await _siemFetch('/api/paloalto', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ action: 'ping', org_id: orgId }) });
        ok = r3b.ok; if (r3b.ok) { var d3b = await r3b.json(); detail = d3b.status || 'connected'; }
      } else if (vendorLower.includes('imperva')) {
        var r3c = await _siemFetch('/api/imperva', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ action: 'ping', org_id: orgId }) });
        ok = r3c.ok; if (r3c.ok) { var d3c = await r3c.json(); detail = d3c.status || 'connected'; }
      } else {
        // Fallback: test via Elastic
        var r3d = await _siemFetch('/api/elastic', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ action: 'cluster_health', namespace: org.namespace }) });
        if (r3d.ok) { var d3d = await r3d.json(); ok = d3d.status && d3d.status !== 'red'; detail = d3d.status || 'unknown'; }
      }
    } else if (c.connector_type === 'ticketing') {
      var r4 = await _siemFetch('/api/jira?action=health', { method: 'POST', headers: {'Content-Type':'application/json'}, body: '{}' });
      ok = r4.ok;
    } else if (c.connector_type === 'threat_intel') {
      ok = !!(c.api_endpoint || (c.metadata && (c.metadata.url || c.metadata.api_key)));
      detail = ok ? 'configured' : 'missing config';
    } else {
      // For other types, check if api_endpoint is configured
      ok = !!(c.api_endpoint || c.is_enabled);
      detail = c.api_endpoint ? 'endpoint configured' : 'no direct API test';
    }
    c.health_status = ok ? 'healthy' : 'degraded';
    showToast((ok ? 'Connection OK' : 'Connection degraded') + ' — ' + (c.display_name || c.connector_type) + (detail ? ' (' + detail + ')' : ''), ok ? 'success' : 'warn');
  } catch(e) {
    c.health_status = 'degraded';
    showToast('Connection test failed — ' + (c.display_name || c.connector_type) + ': ' + e.message, 'error');
  }
  // Persist health status to DB so it survives refresh
  if (c.id) {
    try {
      _siemFetch('/api/connectors?action=update_connector', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id: c.id, health_status: c.health_status })
      });
    } catch(e) { /* non-blocking */ }
  }
  renderSettingsConnectors();
}

async function loadSettingsPage() {
  try {
    console.log('[Settings] loadSettingsPage called');
    var page = document.getElementById('page-settings');
    if (!page) { console.log('[Settings] page-settings not found'); return; }

    var sel = document.getElementById('settingsOrgSelector');
    var countEl = document.getElementById('settingsOrgCount');
    if (!sel) { console.log('[Settings] settingsOrgSelector not found'); return; }

    // Check ORG_CONNECTORS is ready
    if (typeof ORG_CONNECTORS === 'undefined' || !ORG_CONNECTORS) {
      console.log('[Settings] ORG_CONNECTORS not ready, retrying in 500ms');
      setTimeout(loadSettingsPage, 500);
      return;
    }

    // Ensure DB connector data is loaded (DB is single source of truth)
    // If loadOrgConnectorsFromDB hasn't completed yet, await it now
    if (!_orgConnectorsLoadedFromDB && window._supabaseRef) {
      console.log('[Settings] Awaiting loadOrgConnectorsFromDB...');
      await loadOrgConnectorsFromDB().catch(function(e) { console.warn('[Settings] DB connector load error:', e.message); });
    }
    // Also load any newly onboarded orgs
    await loadOrgsFromSupabase().catch(function(e) { console.warn('[Settings] loadOrgs error:', e.message); });

    // Populate org selector from ORG_CONNECTORS
    var optHTML = '';
    var orgCount = 0;
    var keys = Object.keys(ORG_CONNECTORS);
    for (var i = 0; i < keys.length; i++) {
      var id = keys[i];
      var o = ORG_CONNECTORS[id];
      var typeTag = o.type === 'internal' ? '(Internal)' : o.type === 'mdr' ? '(MDR)' : '(SOCaaS)';
      optHTML += '<option value="' + id + '">' + o.name + ' [' + o.code + '] ' + typeTag + '</option>';
      orgCount++;
    }
    console.log('[Settings] Generated ' + orgCount + ' org options');
    sel.innerHTML = optHTML;
    if (countEl) countEl.textContent = orgCount + ' organizations registered';

    // Restore previously selected org from localStorage (if still valid)
    var savedOrg = '';
    try { savedOrg = localStorage.getItem('stg_selectedOrg') || ''; } catch(e) {}
    if (savedOrg && sel.querySelector('option[value="' + savedOrg + '"]')) {
      sel.value = savedOrg;
    }

    // Render selected org's connectors
    renderSettingsConnectors();

    // Also populate the Client Log Sources org selector
    stgLsInit();

    // Load SSO admin settings UI
    loadSSOSettingsUI();

    // Load platform settings (notifications, audit toggles, tenant settings, LLM config)
    loadPlatformSettings();

    // Restore previously active tab from localStorage (default to logsources)
    var savedTab = '';
    try { savedTab = localStorage.getItem('stg_activeTab') || ''; } catch(e) {}
    var validTabs = ['logsources', 'connectors', 'rag', 'escalation', 'rules', 'security'];
    switchSettingsTab(validTabs.indexOf(savedTab) !== -1 ? savedTab : 'logsources');

    console.log('[Settings] Live connector registry loaded: ' + orgCount + ' orgs');
  } catch(err) {
    console.error('[Settings] Error in loadSettingsPage:', err.message, err.stack);
  }
}

// ============================================================
//  ESCALATION MATRIX — PER-CLIENT CONTACTS, SLA & TIERS
// ============================================================

var _escMatrixData = {}; // { orgId: { contacts: [], sla: {}, escalationTiers: [], notes: '' } }
var _escMatrixLoaded = false;
var _escCurrentOrgId = '';

// Initialize the escalation matrix tab — populate org selector, load data
async function initEscalationMatrixTab() {
  try {
    console.log('[EscMatrix] Initializing escalation matrix tab');
    var sel = document.getElementById('escMatrixOrgSelector');
    if (!sel) return;

    // Wait for ORG_CONNECTORS
    if (typeof ORG_CONNECTORS === 'undefined' || !ORG_CONNECTORS) {
      sel.innerHTML = '<option>Loading organizations...</option>';
      setTimeout(initEscalationMatrixTab, 500);
      return;
    }

    // Populate org selector
    var optHTML = '';
    var keys = Object.keys(ORG_CONNECTORS);
    for (var i = 0; i < keys.length; i++) {
      var id = keys[i];
      var o = ORG_CONNECTORS[id];
      var typeTag = o.type === 'internal' ? '(Internal)' : o.type === 'mdr' ? '(MDR)' : '(SOCaaS)';
      optHTML += '<option value="' + id + '">' + o.name + ' [' + o.code + '] ' + typeTag + '</option>';
    }
    sel.innerHTML = optHTML;

    // Load all matrices from server (first time)
    if (!_escMatrixLoaded) {
      await loadAllEscalationMatrices();
      _escMatrixLoaded = true;
    }

    // Load first org
    if (keys.length > 0) {
      loadEscalationMatrixForOrg();
    }
  } catch(e) {
    console.error('[EscMatrix] Init error:', e);
  }
}

// Load all escalation matrices from the API
async function loadAllEscalationMatrices() {
  try {
    var resp = await _siemFetch('/api/jira?action=getAllEscalationMatrices');
    var data = await resp.json();
    if (data.matrices && Array.isArray(data.matrices)) {
      data.matrices.forEach(function(m) {
        _escMatrixData[m.org_id] = {
          contacts: typeof m.contacts === 'string' ? JSON.parse(m.contacts || '[]') : (m.contacts || []),
          sla: typeof m.sla === 'string' ? JSON.parse(m.sla || '{}') : (m.sla || {}),
          escalationTiers: typeof m.escalation_tiers === 'string' ? JSON.parse(m.escalation_tiers || '[]') : (m.escalation_tiers || []),
          notes: m.notes || '',
          orgName: m.org_name || ''
        };
      });
      console.log('[EscMatrix] Loaded ' + data.matrices.length + ' matrices from server');
    }
  } catch(e) {
    console.warn('[EscMatrix] Could not load from server, using localStorage fallback');
  }
  // Also load from localStorage as fallback
  try {
    var local = JSON.parse(localStorage.getItem('dacta_esc_matrix') || '{}');
    Object.keys(local).forEach(function(orgId) {
      if (!_escMatrixData[orgId]) _escMatrixData[orgId] = local[orgId];
    });
  } catch(e) {}
}

// Load and render escalation matrix for the selected org
function loadEscalationMatrixForOrg() {
  var sel = document.getElementById('escMatrixOrgSelector');
  if (!sel) return;
  var orgId = sel.value;
  _escCurrentOrgId = orgId;
  var statusEl = document.getElementById('escMatrixStatus');

  // Get or create default matrix for this org
  var matrix = _escMatrixData[orgId] || { contacts: [], sla: {}, escalationTiers: [], notes: '' };

  // Render contacts table
  renderEscalationContacts(matrix.contacts);

  // Render SLA
  var hasCustomSla = matrix.sla && matrix.sla.customEnabled;
  var toggle = document.getElementById('escSlaOverrideToggle');
  if (toggle) toggle.checked = !!hasCustomSla;
  toggleSlaOverride();
  if (hasCustomSla && matrix.sla) {
    var fields = ['P1', 'P2', 'P3', 'P4'];
    fields.forEach(function(p) {
      var respEl = document.getElementById('escSla' + p + 'Resp');
      var resEl = document.getElementById('escSla' + p + 'Res');
      if (respEl && matrix.sla[p + '_response']) respEl.value = matrix.sla[p + '_response'];
      if (resEl && matrix.sla[p + '_resolution']) resEl.value = matrix.sla[p + '_resolution'];
    });
  }

  // Render escalation tiers
  if (matrix.escalationTiers && matrix.escalationTiers.length > 0) {
    var tiers = matrix.escalationTiers;
    if (tiers[0]) {
      var l1t = document.getElementById('escTierL1Time');
      var l1c = document.getElementById('escTierL1Contacts');
      if (l1t && tiers[0].time) l1t.value = tiers[0].time;
      if (l1c && tiers[0].notify) l1c.value = tiers[0].notify;
    }
    if (tiers[1]) {
      var l2t = document.getElementById('escTierL2Time');
      var l2c = document.getElementById('escTierL2Contacts');
      if (l2t && tiers[1].time) l2t.value = tiers[1].time;
      if (l2c && tiers[1].notify) l2c.value = tiers[1].notify;
    }
    if (tiers[2]) {
      var l3t = document.getElementById('escTierL3Time');
      var l3c = document.getElementById('escTierL3Contacts');
      if (l3t && tiers[2].time) l3t.value = tiers[2].time;
      if (l3c && tiers[2].notify) l3c.value = tiers[2].notify;
    }
  }

  // Render notes
  var notesEl = document.getElementById('escMatrixNotes');
  if (notesEl) notesEl.value = matrix.notes || '';

  // Status indicator
  if (statusEl) {
    var hasData = (matrix.contacts && matrix.contacts.length > 0) || hasCustomSla;
    statusEl.innerHTML = hasData
      ? '<span style="color:#10b981;">\u25cf</span> Configured'
      : '<span style="color:#f59e0b;">\u25cb</span> Not configured';
  }
}

// Render contacts table rows
function renderEscalationContacts(contacts) {
  var tbody = document.getElementById('escContactsTbody');
  var emptyEl = document.getElementById('escContactsEmpty');
  if (!tbody) return;

  if (!contacts || contacts.length === 0) {
    tbody.innerHTML = '';
    if (emptyEl) emptyEl.style.display = '';
    return;
  }
  if (emptyEl) emptyEl.style.display = 'none';

  var html = '';
  contacts.forEach(function(c, idx) {
    var tierColor = c.tier === 'primary' ? '#00d4ff' : c.tier === 'secondary' ? '#f97316' : c.tier === 'escalation' ? '#ef4444' : '#8892a4';
    var tierLabel = c.tier === 'primary' ? 'Primary' : c.tier === 'secondary' ? 'Secondary' : c.tier === 'escalation' ? 'Escalation' : (c.tier || 'Primary');
    html += '<tr style="border-bottom:1px solid var(--border-card);transition:background 0.15s;" onmouseenter="this.style.background=\'rgba(0,212,255,0.03)\'" onmouseleave="this.style.background=\'transparent\'">' +
      '<td style="padding:8px;"><input class="filter-input esc-contact-field" data-idx="' + idx + '" data-field="name" value="' + escapeHtml(c.name || '') + '" style="font-size:11px;padding:3px 6px;width:100%;background:transparent;border-color:transparent;color:var(--text-primary);font-weight:500;" onfocus="this.style.borderColor=\'rgba(0,212,255,0.3)\'" onblur="this.style.borderColor=\'transparent\';updateEscContact(' + idx + ',\'name\',this.value)"></td>' +
      '<td style="padding:8px;"><input class="filter-input esc-contact-field" data-idx="' + idx + '" data-field="role" value="' + escapeHtml(c.role || '') + '" placeholder="e.g. IT Manager" style="font-size:10px;padding:3px 6px;width:100%;background:transparent;border-color:transparent;color:var(--text-secondary);" onfocus="this.style.borderColor=\'rgba(0,212,255,0.3)\'" onblur="this.style.borderColor=\'transparent\';updateEscContact(' + idx + ',\'role\',this.value)"></td>' +
      '<td style="padding:8px;"><input class="filter-input esc-contact-field" data-idx="' + idx + '" data-field="email" value="' + escapeHtml(c.email || '') + '" type="email" style="font-size:10px;padding:3px 6px;width:100%;background:transparent;border-color:transparent;color:var(--cyan);font-family:var(--font-mono);" onfocus="this.style.borderColor=\'rgba(0,212,255,0.3)\'" onblur="this.style.borderColor=\'transparent\';updateEscContact(' + idx + ',\'email\',this.value)"></td>' +
      '<td style="padding:8px;"><input class="filter-input esc-contact-field" data-idx="' + idx + '" data-field="phone" value="' + escapeHtml(c.phone || '') + '" placeholder="+65..." style="font-size:10px;padding:3px 6px;width:100%;background:transparent;border-color:transparent;color:var(--text-secondary);font-family:var(--font-mono);" onfocus="this.style.borderColor=\'rgba(0,212,255,0.3)\'" onblur="this.style.borderColor=\'transparent\';updateEscContact(' + idx + ',\'phone\',this.value)"></td>' +
      '<td style="padding:8px;"><select class="filter-select" data-idx="' + idx + '" data-field="tier" style="font-size:9px;padding:2px 6px;min-width:80px;" onchange="updateEscContact(' + idx + ',\'tier\',this.value)">' +
        '<option value="primary"' + (c.tier === 'primary' ? ' selected' : '') + '>Primary</option>' +
        '<option value="secondary"' + (c.tier === 'secondary' ? ' selected' : '') + '>Secondary</option>' +
        '<option value="escalation"' + (c.tier === 'escalation' ? ' selected' : '') + '>Escalation</option>' +
      '</select></td>' +
      '<td style="padding:8px;text-align:center;"><button onclick="removeEscContact(' + idx + ')" style="background:none;border:none;color:#ef4444;cursor:pointer;font-size:14px;padding:2px 6px;opacity:0.6;transition:opacity 0.15s;" onmouseenter="this.style.opacity=1" onmouseleave="this.style.opacity=0.6" title="Remove contact">\u00d7</button></td>' +
    '</tr>';
  });
  tbody.innerHTML = html;
}

// Update a contact field in memory
function updateEscContact(idx, field, value) {
  if (!_escCurrentOrgId) return;
  if (!_escMatrixData[_escCurrentOrgId]) _escMatrixData[_escCurrentOrgId] = { contacts: [], sla: {}, escalationTiers: [], notes: '' };
  var contacts = _escMatrixData[_escCurrentOrgId].contacts || [];
  if (contacts[idx]) {
    contacts[idx][field] = value;
  }
}

// Add a new blank contact row
function addEscalationContact() {
  if (!_escCurrentOrgId) return;
  if (!_escMatrixData[_escCurrentOrgId]) _escMatrixData[_escCurrentOrgId] = { contacts: [], sla: {}, escalationTiers: [], notes: '' };
  _escMatrixData[_escCurrentOrgId].contacts.push({
    name: '', role: '', email: '', phone: '', tier: 'primary'
  });
  renderEscalationContacts(_escMatrixData[_escCurrentOrgId].contacts);
  // Focus the name field of the new row
  setTimeout(function() {
    var inputs = document.querySelectorAll('#escContactsTbody input[data-field="name"]');
    if (inputs.length > 0) inputs[inputs.length - 1].focus();
  }, 50);
}

// Remove a contact
function removeEscContact(idx) {
  if (!_escCurrentOrgId || !_escMatrixData[_escCurrentOrgId]) return;
  _escMatrixData[_escCurrentOrgId].contacts.splice(idx, 1);
  renderEscalationContacts(_escMatrixData[_escCurrentOrgId].contacts);
}

// Toggle SLA override
function toggleSlaOverride() {
  var toggle = document.getElementById('escSlaOverrideToggle');
  var grid = document.getElementById('escSlaGrid');
  var defaultMsg = document.getElementById('escSlaDefault');
  if (!toggle || !grid) return;
  if (toggle.checked) {
    grid.style.opacity = '1';
    grid.style.pointerEvents = 'auto';
    if (defaultMsg) defaultMsg.style.display = 'none';
  } else {
    grid.style.opacity = '0.5';
    grid.style.pointerEvents = 'none';
    if (defaultMsg) defaultMsg.style.display = '';
  }
}

// Import contacts from Jira request participants for this org
async function importContactsFromJira() {
  if (!_escCurrentOrgId) return;
  var sel = document.getElementById('escMatrixOrgSelector');
  var orgName = sel ? sel.options[sel.selectedIndex].text.split(' [')[0] : '';
  var statusEl = document.getElementById('escMatrixStatus');
  if (statusEl) statusEl.innerHTML = '<span style="color:var(--cyan);">\u21bb</span> Pulling contacts from Jira...';

  try {
    // First, find the Jira org ID for this org
    var jiraOrgId = null;
    // Check ORG_CONNECTORS for jira_org_id
    var orgConn = ORG_CONNECTORS[_escCurrentOrgId];
    if (orgConn && orgConn.jira_org_id) {
      jiraOrgId = orgConn.jira_org_id;
    }
    // If not found in connectors, search by name in _jiraOrgs cache
    if (!jiraOrgId && typeof _jiraOrgs !== 'undefined' && _jiraOrgs.length > 0) {
      var nameLC = orgName.toLowerCase().trim();
      var match = _jiraOrgs.find(function(jo) {
        var jn = jo.name.toLowerCase().trim();
        return jn === nameLC || nameLC.indexOf(jn) === 0 || jn.indexOf(nameLC) === 0;
      });
      if (match) jiraOrgId = match.jira_org_id;
    }
    // Last resort: fetch organizations fresh to get org ID
    if (!jiraOrgId) {
      try {
        var orgResp = await _siemFetch('/api/jira?action=organizations', { method: 'POST', headers: {'Content-Type':'application/json'}, body: '{}' });
        var orgData = await orgResp.json();
        var orgs = orgData.organizations || [];
        var nameLC2 = orgName.toLowerCase().trim();
        var match2 = orgs.find(function(jo) {
          var jn = jo.name.toLowerCase().trim();
          return jn === nameLC2 || nameLC2.indexOf(jn) === 0 || jn.indexOf(nameLC2) === 0;
        });
        if (match2) jiraOrgId = match2.jira_org_id;
      } catch(e) { /* continue */ }
    }

    if (!jiraOrgId) {
      if (statusEl) statusEl.innerHTML = '<span style="color:#f59e0b;">' + dIcon('warning',14) + '</span> Could not find Jira Organization ID for "' + escapeHtml(orgName) + '"';
      return;
    }

    // Use the orgMembers API to get all org members
    var resp = await _siemFetch('/api/jira?action=orgMembers&orgId=' + encodeURIComponent(jiraOrgId));
    var data = await resp.json();
    var members = data.members || [];

    // Import all org members, including those without emails (analyst can fill in later)
    var newContacts = [];
    var seenKeys = {};
    members.forEach(function(m) {
      if (!m.displayName) return;
      var hasEmail = m.emailAddress && m.emailAddress.indexOf('@') !== -1;
      var emailLC = hasEmail ? m.emailAddress.toLowerCase() : '';
      // Skip internal DACTA accounts
      if (hasEmail && (emailLC.indexOf('@dacta') !== -1 || emailLC.indexOf('@dactaglobal') !== -1)) return;
      // Dedupe by email or by accountId
      var key = hasEmail ? emailLC : (m.accountId || m.displayName.toLowerCase());
      if (seenKeys[key]) return;
      seenKeys[key] = true;
      newContacts.push({
        name: m.displayName || '',
        role: '',
        email: hasEmail ? m.emailAddress : '',
        phone: '',
        tier: newContacts.length === 0 ? 'primary' : 'secondary'
      });
    });

    // Also try ticket participants to get any additional contacts with emails
    try {
      var jql = encodeURIComponent('project = DAC AND "Organizations" = "' + orgName + '" ORDER BY created DESC');
      var tResp = await _siemFetch('/api/jira?action=search&jql=' + jql + '&maxResults=5&fields=key');
      var tData = await tResp.json();
      var tickets = tData.issues || [];
      for (var i = 0; i < Math.min(tickets.length, 3); i++) {
        try {
          var pResp = await _siemFetch('/api/jira?action=requestParticipants&key=' + tickets[i].key);
          var pData = await pResp.json();
          var participants = pData.participants || [];
          participants.forEach(function(p) {
            if (p.emailAddress && p.emailAddress.indexOf('@') !== -1) {
              var eLC = p.emailAddress.toLowerCase();
              if (eLC.indexOf('@dacta') !== -1 || eLC.indexOf('@dactaglobal') !== -1) return;
              if (!seenKeys[eLC]) {
                seenKeys[eLC] = true;
                newContacts.push({ name: p.displayName || '', role: '', email: p.emailAddress, phone: '', tier: 'secondary' });
              }
            }
          });
          if (pData.reporter && pData.reporter.emailAddress) {
            var rLC = pData.reporter.emailAddress.toLowerCase();
            if (rLC.indexOf('@dacta') === -1 && rLC.indexOf('@dactaglobal') === -1 && !seenKeys[rLC]) {
              seenKeys[rLC] = true;
              newContacts.push({ name: pData.reporter.displayName || '', role: 'Reporter', email: pData.reporter.emailAddress, phone: '', tier: 'secondary' });
            }
          }
        } catch(e) { /* continue */ }
      }
    } catch(e) { /* continue with what we have */ }

    if (newContacts.length === 0) {
      if (statusEl) statusEl.innerHTML = '<span style="color:#f59e0b;">' + dIcon('warning',14) + '</span> No members found for "' + escapeHtml(orgName) + '" in Jira.';
      return;
    }

    // Merge with existing contacts (don't overwrite)
    if (!_escMatrixData[_escCurrentOrgId]) _escMatrixData[_escCurrentOrgId] = { contacts: [], sla: {}, escalationTiers: [], notes: '' };
    var existing = _escMatrixData[_escCurrentOrgId].contacts || [];
    var existingKeys = {};
    existing.forEach(function(c) {
      if (c.email) existingKeys[c.email.toLowerCase()] = true;
      if (c.name) existingKeys[c.name.toLowerCase().trim()] = true;
    });
    var added = 0;
    var noEmailCount = 0;
    newContacts.forEach(function(nc) {
      var emailKey = nc.email ? nc.email.toLowerCase() : '';
      var nameKey = nc.name ? nc.name.toLowerCase().trim() : '';
      if ((emailKey && existingKeys[emailKey]) || (nameKey && existingKeys[nameKey])) return;
      existing.push(nc);
      if (emailKey) existingKeys[emailKey] = true;
      if (nameKey) existingKeys[nameKey] = true;
      added++;
      if (!nc.email) noEmailCount++;
    });
    _escMatrixData[_escCurrentOrgId].contacts = existing;
    renderEscalationContacts(existing);

    var emailNote = noEmailCount > 0 ? ' (' + noEmailCount + ' without email — please fill in manually)' : '';
    if (statusEl) statusEl.innerHTML = '<span style="color:#10b981;">' + dIcon('check',14) + '</span> Imported ' + added + ' contact' + (added !== 1 ? 's' : '') + ' from Jira' + emailNote;
  } catch(e) {
    console.error('[EscMatrix] Jira import error:', e);
    if (statusEl) statusEl.innerHTML = '<span style="color:#ef4444;">' + dIcon('close',14) + '</span> Import failed: ' + e.message;
  }
}

// Collect current form state into the data model
function collectEscalationMatrixState() {
  if (!_escCurrentOrgId) return null;
  if (!_escMatrixData[_escCurrentOrgId]) _escMatrixData[_escCurrentOrgId] = { contacts: [], sla: {}, escalationTiers: [], notes: '' };
  var m = _escMatrixData[_escCurrentOrgId];

  // Collect SLA
  var toggle = document.getElementById('escSlaOverrideToggle');
  m.sla = {
    customEnabled: toggle ? toggle.checked : false,
    P1_response: (document.getElementById('escSlaP1Resp') || {}).value || '15 min',
    P1_resolution: (document.getElementById('escSlaP1Res') || {}).value || '4 hr',
    P2_response: (document.getElementById('escSlaP2Resp') || {}).value || '30 min',
    P2_resolution: (document.getElementById('escSlaP2Res') || {}).value || '12 hr',
    P3_response: (document.getElementById('escSlaP3Resp') || {}).value || '2 hr',
    P3_resolution: (document.getElementById('escSlaP3Res') || {}).value || '48 hr',
    P4_response: (document.getElementById('escSlaP4Resp') || {}).value || '8 hr',
    P4_resolution: (document.getElementById('escSlaP4Res') || {}).value || '7 days'
  };

  // Collect escalation tiers
  m.escalationTiers = [
    { level: 'L1', time: (document.getElementById('escTierL1Time') || {}).value || '30 min', notify: (document.getElementById('escTierL1Contacts') || {}).value || 'primary' },
    { level: 'L2', time: (document.getElementById('escTierL2Time') || {}).value || '2 hr', notify: (document.getElementById('escTierL2Contacts') || {}).value || 'secondary' },
    { level: 'L3', time: (document.getElementById('escTierL3Time') || {}).value || '4 hr', notify: (document.getElementById('escTierL3Contacts') || {}).value || 'escalation' }
  ];

  // Collect notes
  m.notes = (document.getElementById('escMatrixNotes') || {}).value || '';

  return m;
}

// Save the escalation matrix for the current org
async function saveEscalationMatrix() {
  if (!_escCurrentOrgId) { alert('No organization selected'); return; }

  // Collect current state
  var matrix = collectEscalationMatrixState();
  if (!matrix) return;

  var sel = document.getElementById('escMatrixOrgSelector');
  var orgName = sel ? sel.options[sel.selectedIndex].text.split(' [')[0] : '';
  var statusEl = document.getElementById('escMatrixStatus');
  if (statusEl) statusEl.innerHTML = '<span style="color:var(--cyan);">\u21bb</span> Saving...';

  try {
    // Save to server
    var resp = await _siemFetch('/api/jira?action=saveEscalationMatrix', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        orgId: _escCurrentOrgId,
        orgName: orgName,
        contacts: matrix.contacts,
        sla: matrix.sla,
        escalationTiers: matrix.escalationTiers,
        notes: matrix.notes
      })
    });
    var data = await resp.json();

    // Also save to localStorage as backup
    try {
      var allLocal = JSON.parse(localStorage.getItem('dacta_esc_matrix') || '{}');
      allLocal[_escCurrentOrgId] = matrix;
      localStorage.setItem('dacta_esc_matrix', JSON.stringify(allLocal));
    } catch(e) {}

    if (statusEl) statusEl.innerHTML = '<span style="color:#10b981;">' + dIcon('check',14) + '</span> Saved';
    setTimeout(function() {
      if (statusEl && statusEl.innerHTML.indexOf('Saved') > -1) {
        var hasData = (matrix.contacts && matrix.contacts.length > 0) || (matrix.sla && matrix.sla.customEnabled);
        statusEl.innerHTML = hasData
          ? '<span style="color:#10b981;">\u25cf</span> Configured'
          : '<span style="color:#f59e0b;">\u25cb</span> Not configured';
      }
    }, 2000);
  } catch(e) {
    console.error('[EscMatrix] Save error:', e);
    if (statusEl) statusEl.innerHTML = '<span style="color:#ef4444;">' + dIcon('close',14) + '</span> Save failed';
  }
}

