// ── Get escalation contacts for a specific org (used by escalation draft) ──
function getEscalationContactsForOrg(orgName) {
  // Try to find by org name in _escMatrixData
  var keys = Object.keys(_escMatrixData);
  for (var i = 0; i < keys.length; i++) {
    var m = _escMatrixData[keys[i]];
    if (m && m.orgName === orgName && m.contacts && m.contacts.length > 0) {
      return m;
    }
    // Also check ORG_CONNECTORS for name match
    if (typeof ORG_CONNECTORS !== 'undefined' && ORG_CONNECTORS[keys[i]] && ORG_CONNECTORS[keys[i]].name === orgName) {
      return m;
    }
  }
  return null;
}

// ── Get client SLA for a specific org (used by dashboard and escalation) ──
function getClientSLA(orgName) {
  var matrix = getEscalationContactsForOrg(orgName);
  if (matrix && matrix.sla && matrix.sla.customEnabled) {
    return matrix.sla;
  }
  // Return global defaults
  return {
    customEnabled: false,
    P1_response: '15 min', P1_resolution: '4 hr',
    P2_response: '30 min', P2_resolution: '12 hr',
    P3_response: '2 hr', P3_resolution: '48 hr',
    P4_response: '8 hr', P4_resolution: '7 days'
  };
}

// ============================================================
//  AI USAGE TRACKER
// ============================================================
var _aiUsage = {"totalCalls":0,"totalTokensIn":0,"totalTokensOut":0,"calls":[],"byModel":{},"byDay":{}};
sessionStorage.removeItem('dacta_ai_usage');

// ============================================================
//  SUPABASE COMPLIANCE HELPERS
// ============================================================

// Fire-and-forget insert to any SIEMLess DB table
function logToSupabase(table, data) {
  if (!window._dactaSupabase) return;
  try {
    window._dactaSupabase.from(table).insert(data).then(function(res) {
      if (res.error) console.warn('[AuditLog] Insert error (' + table + '):', res.error.message);
    });
  } catch(e) { console.warn('[AuditLog] Error (' + table + '):', e); }
}

// Get current logged-in user email from SIEMLess DB session
function _getCurrentUserEmail() {
  try {
    var emailEl = document.getElementById('userMenuEmail');
    if (emailEl && emailEl.textContent) return emailEl.textContent.trim();
  } catch(e) {}
  return 'unknown';
}

// Generate a simple session ID for copilot sessions
var _copilotSessionId = 'cs-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);

function trackAIUsage(model, tokensIn, tokensOut, purpose, latencyMs, sessionId) {
  _aiUsage.totalCalls++;
  _aiUsage.totalTokensIn += tokensIn;
  _aiUsage.totalTokensOut += tokensOut;
  var now = new Date();
  var dayKey = now.toISOString().slice(0, 10);
  if (!_aiUsage.byModel[model]) _aiUsage.byModel[model] = { calls: 0, tokensIn: 0, tokensOut: 0 };
  _aiUsage.byModel[model].calls++;
  _aiUsage.byModel[model].tokensIn += tokensIn;
  _aiUsage.byModel[model].tokensOut += tokensOut;
  if (!_aiUsage.byDay[dayKey]) _aiUsage.byDay[dayKey] = { calls: 0, tokensIn: 0, tokensOut: 0 };
  _aiUsage.byDay[dayKey].calls++;
  _aiUsage.byDay[dayKey].tokensIn += tokensIn;
  _aiUsage.byDay[dayKey].tokensOut += tokensOut;
  _aiUsage.calls.push({ ts: now.toISOString(), model: model, tokensIn: tokensIn, tokensOut: tokensOut, purpose: purpose });
  if (_aiUsage.calls.length > 100) _aiUsage.calls = _aiUsage.calls.slice(-100);
  try { sessionStorage.setItem('dacta_ai_usage', JSON.stringify(_aiUsage)); } catch(e) {}
  // Note: LLM usage is now logged server-side in copilot.js (service role key, bypasses RLS).
  // Frontend logToSupabase for llm_usage_log is deprecated.
}

// Cost per 1K tokens by model (blended estimate)
var _aiModelCosts = {
  'Claude Opus': 0.075, 'Claude Sonnet': 0.015, 'Claude Haiku': 0.003,
  'GPT 5.2': 0.03, 'GPT-4o': 0.01, 'GPT-4': 0.06,
  'Gemini 3.1 Pro': 0.00625, 'Gemini Pro': 0.00625,
  'Copilot-Search': 0.005, 'DeepSeek': 0.002, 'Perplexity': 0.005
};
function _aiCostPer1K(model) {
  if (_aiModelCosts[model]) return _aiModelCosts[model];
  for (var k in _aiModelCosts) { if (model.toLowerCase().indexOf(k.toLowerCase()) >= 0) return _aiModelCosts[k]; }
  return 0.015; // default
}
var _aiModelColorMap = {
  'Claude': { bg: 'rgba(224,108,117,0.75)', border: '#e06c75' },
  'GPT':    { bg: 'rgba(78,201,176,0.75)',  border: '#4ec9b0' },
  'Gemini': { bg: 'rgba(139,92,246,0.75)',  border: '#8b5cf6' },
  'Copilot':{ bg: 'rgba(86,156,214,0.75)',  border: '#569cd6' },
  'DeepSeek':{ bg: 'rgba(220,220,170,0.75)',border: '#dcdcaa' },
  'Perplexity':{ bg: 'rgba(86,156,214,0.75)', border: '#569cd6' }
};
function _aiModelColor(model) {
  for (var k in _aiModelColorMap) { if (model.indexOf(k) >= 0) return _aiModelColorMap[k]; }
  return { bg: 'rgba(0,212,255,0.75)', border: '#00d4ff' };
}

// Cache for fetched data to avoid redundant queries
var _aiUsageDBCache = null;
var _aiUsageCacheKey = '';

async function loadAIUsagePage() {
  var page = document.getElementById('page-aiusage');
  if (!page) return;

  // --- Populate month filter dropdown ---
  // Use local year/month (not toISOString which converts to UTC and can roll back a month in UTC+ timezones)
  function _localYM(date) {
    return date.getFullYear() + '-' + String(date.getMonth() + 1).padStart(2, '0');
  }
  var monthSel = document.getElementById('aiUsageMonthFilter');
  if (monthSel && monthSel.options.length === 0) {
    var now = new Date();
    for (var mi = 0; mi < 6; mi++) {
      var d = new Date(now.getFullYear(), now.getMonth() - mi, 1);
      var val = _localYM(d);
      var label = d.toLocaleString('en-US', { month: 'long', year: 'numeric' });
      var opt = document.createElement('option');
      opt.value = val;
      opt.textContent = label;
      monthSel.appendChild(opt);
    }
  }

  var selectedMonth = (monthSel && monthSel.value) ? monthSel.value : _localYM(new Date());

  // --- Fetch from server-side API (bypasses RLS, always works) ---
  var cacheKey = selectedMonth;
  var rows;
  if (_aiUsageCacheKey === cacheKey && _aiUsageDBCache && _aiUsageDBCache.length > 0) {
    rows = _aiUsageDBCache;
  } else {
    try {
      var _aiUrl = '/api/ai-usage?month=' + encodeURIComponent(selectedMonth);
      console.log('[AIUsage] Fetching:', _aiUrl);
      var resp = await window._siemFetch(_aiUrl);
      console.log('[AIUsage] Response:', resp.status, resp.ok);
      if (resp.ok) {
        var json = await resp.json();
        rows = (json.data && json.data.length > 0) ? json.data : [];
        console.log('[AIUsage] API returned', rows.length, 'rows');
      } else {
        console.warn('[AIUsage] API error:', resp.status);
        rows = [];
      }
    } catch (e) {
      console.warn('[AIUsage] API fetch failed:', e.message);
      rows = [];
    }
    // AI usage data is exclusively fetched from /api/ai-usage endpoint (server-side)
    _aiUsageDBCache = rows;
    _aiUsageCacheKey = cacheKey;
  }

  // Also merge in-memory session calls that haven't been persisted yet
  if (_aiUsage && _aiUsage.calls && _aiUsage.calls.length > 0) {
    var existingIds = new Set(rows.map(function(r) { return r.id; }));
    _aiUsage.calls.forEach(function(c) {
      var cDate = c.ts ? c.ts.slice(0, 7) : '';
      if (cDate === selectedMonth && !existingIds.has(c.id)) {
        rows.push({
          model: c.model, task_type: c.purpose || 'copilot_query',
          input_tokens: c.tokensIn, output_tokens: c.tokensOut,
          latency_ms: null, created_at: c.ts, _session: true
        });
      }
    });
  }

  // --- Aggregate data ---
  var totalRequests = rows.length;
  var totalTokensIn = 0, totalTokensOut = 0, totalCost = 0;
  var byModel = {}, byDay = {}, byTask = {};

  rows.forEach(function(r) {
    var tIn = r.input_tokens || 0;
    var tOut = r.output_tokens || 0;
    totalTokensIn += tIn;
    totalTokensOut += tOut;
    var cost = ((tIn + tOut) / 1000) * _aiCostPer1K(r.model || 'unknown');
    totalCost += cost;

    var m = r.model || 'Unknown';
    if (!byModel[m]) byModel[m] = { calls: 0, tokensIn: 0, tokensOut: 0, cost: 0 };
    byModel[m].calls++;
    byModel[m].tokensIn += tIn;
    byModel[m].tokensOut += tOut;
    byModel[m].cost += cost;

    var dayKey = (r.created_at || '').slice(0, 10);
    if (dayKey) {
      if (!byDay[dayKey]) byDay[dayKey] = { calls: 0, tokensIn: 0, tokensOut: 0 };
      byDay[dayKey].calls++;
      byDay[dayKey].tokensIn += tIn;
      byDay[dayKey].tokensOut += tOut;
    }

    var task = r.task_type || 'other';
    if (!byTask[task]) byTask[task] = 0;
    byTask[task]++;
  });

  // --- Update subtitle ---
  var subtitle = document.getElementById('aiUsageSubtitle');
  if (subtitle) subtitle.textContent = totalRequests > 0
    ? 'Live Data \u00b7 ' + totalRequests + ' requests this period'
    : 'No usage data for this period';

  // --- Update metric cards ---
  var costEl = document.getElementById('aiMetricCost');
  if (costEl) {
    var costStr = totalCost.toFixed(2);
    var costParts = costStr.split('.');
    costEl.innerHTML = '$' + costParts[0] + '<span style="font-size:16px;">.' + costParts[1] + '</span>';
  }
  var reqEl = document.getElementById('aiMetricRequests');
  if (reqEl) reqEl.textContent = totalRequests.toLocaleString();
  var tiEl = document.getElementById('aiMetricTokensIn');
  if (tiEl) tiEl.textContent = totalTokensIn.toLocaleString();
  var toEl = document.getElementById('aiMetricTokensOut');
  if (toEl) toEl.textContent = totalTokensOut.toLocaleString();

  // --- Update Model Breakdown cards ---
  var breakdownEl = document.getElementById('aiModelBreakdown');
  if (breakdownEl) {
    if (Object.keys(byModel).length === 0) {
      breakdownEl.innerHTML = '<div style="text-align:center;padding:24px;font-size:11px;color:var(--text-muted);">No usage data for this period</div>';
    } else {
      var bHTML = '';
      var sortedModels = Object.keys(byModel).sort(function(a, b) { return byModel[b].calls - byModel[a].calls; });
      sortedModels.forEach(function(model) {
        var m = byModel[model];
        var mc = _aiModelColor(model);
        var pct = totalRequests > 0 ? ((m.calls / totalRequests) * 100).toFixed(1) : '0';
        bHTML += '<div style="padding:12px;background:var(--bg-elevated);border-radius:8px;border:1px solid var(--border-subtle);border-left:3px solid ' + mc.border + ';">' +
          '<div style="display:flex;justify-content:space-between;align-items:center;">' +
            '<span style="font-size:12px;font-weight:600;color:' + mc.border + ';">' + model + '</span>' +
            '<span style="font-size:10px;color:var(--text-muted);background:rgba(255,255,255,0.04);padding:2px 8px;border-radius:10px;">' + pct + '%</span>' +
          '</div>' +
          '<div style="display:flex;gap:16px;margin-top:8px;font-size:10px;color:var(--text-muted);">' +
            '<span>' + m.calls + ' calls</span>' +
            '<span>' + (m.tokensIn + m.tokensOut).toLocaleString() + ' tokens</span>' +
            '<span>$' + m.cost.toFixed(3) + '</span>' +
          '</div>' +
          '<div style="margin-top:6px;height:4px;background:rgba(255,255,255,0.04);border-radius:2px;overflow:hidden;">' +
            '<div style="height:100%;width:' + pct + '%;background:' + mc.border + ';border-radius:2px;"></div>' +
          '</div>' +
        '</div>';
      });
      breakdownEl.innerHTML = bHTML;
    }
  }

  // --- Update Model Legend under doughnut ---
  var legendEl = document.getElementById('aiModelLegend');
  if (legendEl) {
    if (Object.keys(byModel).length === 0) {
      legendEl.innerHTML = '<div style="font-size:11px;color:var(--text-muted);text-align:center;padding:8px;">No data yet</div>';
    } else {
      var lHTML = '<div style="display:flex;flex-wrap:wrap;gap:10px;justify-content:center;padding:4px 8px;">';
      Object.keys(byModel).forEach(function(model) {
        var mc = _aiModelColor(model);
        lHTML += '<div style="display:flex;align-items:center;gap:5px;font-size:10px;color:var(--text-secondary);">' +
          '<span style="width:8px;height:8px;border-radius:50%;background:' + mc.border + ';display:inline-block;"></span>' +
          model + ' (' + byModel[model].calls + ')' +
        '</div>';
      });
      lHTML += '</div>';
      legendEl.innerHTML = lHTML;
    }
  }

  // --- Update Charts ---
  // Destroy old charts so they can be recreated with fresh data
  if (charts.aiProvider) { charts.aiProvider.destroy(); charts.aiProvider = null; }
  if (charts.aiDaily) { charts.aiDaily.destroy(); charts.aiDaily = null; }
  _renderAICharts(byModel, byDay);

  // --- Populate Recent Calls table ---
  var logBody = document.getElementById('aiUsageLogBody');
  var logSummary = document.getElementById('aiLogSummary');
  if (logBody) {
    if (rows.length === 0) {
      logBody.innerHTML = '<tr><td colspan="6" style="text-align:center;color:var(--text-muted);font-size:11px;padding:24px;">No AI calls recorded for this period</td></tr>';
    } else {
      var logHTML = '';
      rows.slice(0, 100).forEach(function(r) {
        var ts = new Date(r.created_at).toLocaleString('en-SG', { timeZone: 'Asia/Singapore', day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit', second: '2-digit' });
        var mc = _aiModelColor(r.model || '');
        var latStr = r.latency_ms ? (r.latency_ms / 1000).toFixed(1) + 's' : '—';
        var taskLabel = (r.task_type || 'unknown').replace(/_/g, ' ');
        logHTML += '<tr>' +
          '<td style="font-size:10px;font-family:var(--font-mono);color:var(--text-muted);white-space:nowrap;">' + ts + '</td>' +
          '<td style="font-size:11px;color:' + mc.border + ';font-weight:500;">' + (r.model || 'Unknown') + '</td>' +
          '<td style="font-size:10px;color:var(--text-secondary);text-transform:capitalize;">' + taskLabel + '</td>' +
          '<td style="font-size:10px;font-family:var(--font-mono);">' + (r.input_tokens || 0).toLocaleString() + '</td>' +
          '<td style="font-size:10px;font-family:var(--font-mono);">' + (r.output_tokens || 0).toLocaleString() + '</td>' +
          '<td style="font-size:10px;font-family:var(--font-mono);color:var(--text-muted);">' + latStr + '</td>' +
        '</tr>';
      });
      logBody.innerHTML = logHTML;
    }
    if (logSummary) logSummary.textContent = rows.length > 0 ? rows.length + ' calls · ' + (totalTokensIn + totalTokensOut).toLocaleString() + ' total tokens' : '';
  }

  console.log('[AIUsage] Loaded from DB: ' + totalRequests + ' requests, $' + totalCost.toFixed(2) + ' est. cost');
}

function exportAIUsageCSV() {
  if (!_aiUsageDBCache || _aiUsageDBCache.length === 0) { showToast('No data to export', 'warn'); return; }
  var csv = 'Timestamp,Model,Task Type,Tokens In,Tokens Out,Latency (ms),Est. Cost\n';
  _aiUsageDBCache.forEach(function(r) {
    var cost = (((r.input_tokens || 0) + (r.output_tokens || 0)) / 1000 * _aiCostPer1K(r.model || '')).toFixed(4);
    csv += [r.created_at, r.model, r.task_type, r.input_tokens || 0, r.output_tokens || 0, r.latency_ms || '', cost].join(',') + '\n';
  });
  var blob = new Blob([csv], { type: 'text/csv' });
  var a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = 'ai_usage_' + (_aiUsageCacheKey || 'export') + '.csv';
  a.click();
  showToast('CSV exported', 'success');
}

