async function _loadPrivacyPolicyCount(sb) {
  try {
    var res = await sb.from('platform_settings').select('value').eq('key', 'privacy_policies').single();
    if (!res.data || !res.data.value) return;
    var policies = res.data.value;
    var active = policies.filter(function(p) { return p.is_active; }).length;
    var total = policies.length;
    var el = document.getElementById('privMetricPolicies');
    if (el) el.textContent = active;
    el = document.getElementById('privMetricPoliciesSub');
    if (el) el.textContent = total + ' total, ' + active + ' active';
  } catch(e) { console.error('[Privacy] Policy count error:', e); }
}

function openPrivacyPoliciesModal() {
  var modal = document.getElementById('privacyPoliciesModal');
  if (!modal) return;
  modal.classList.add('open');
  _loadPrivacyPolicies();
}

function closePrivacyPoliciesModal() {
  var modal = document.getElementById('privacyPoliciesModal');
  if (modal) modal.classList.remove('open');
}

async function _loadPrivacyPolicies() {
  var sb = window._dactaSupabase || window._supabaseRef;
  if (!sb) return;
  var tbody = document.getElementById('privPoliciesTableBody');
  if (!tbody) return;
  tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:var(--text-muted);padding:20px;">Loading policies...</td></tr>';

  try {
    var res = await sb.from('platform_settings').select('value').eq('key', 'privacy_policies').single();
    if (!res.data || !res.data.value) {
      tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:var(--text-muted);padding:20px;">No policies configured.</td></tr>';
      return;
    }
    window._privPolicies = res.data.value;
    _renderPrivacyPoliciesTable();
  } catch(e) { console.error('[Privacy] Load policies error:', e); }
}

function _renderPrivacyPoliciesTable() {
  var tbody = document.getElementById('privPoliciesTableBody');
  if (!tbody || !window._privPolicies) return;
  var policies = window._privPolicies;

  if (policies.length === 0) {
    tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;color:var(--text-muted);padding:20px;">No policies configured.</td></tr>';
    return;
  }

  var riskColors = { critical: '#ef4444', moderate: '#f59e0b', safe: '#10b981' };
  var html = '';
  policies.forEach(function(p, idx) {
    var rc = riskColors[p.risk_level] || '#8892a4';
    var rcRgb = rc === '#ef4444' ? '239,68,68' : rc === '#f59e0b' ? '245,158,11' : rc === '#10b981' ? '16,185,129' : '136,146,164';
    html += '<tr>';
    html += '<td style="font-weight:600;color:var(--text-primary);">' + (p.name || '') + '</td>';
    html += '<td style="font-size:11px;color:var(--text-secondary);max-width:200px;">' + (p.description || '').slice(0, 80) + '</td>';
    html += '<td><span style="font-size:10px;padding:2px 8px;border-radius:4px;background:rgba(' + rcRgb + ',0.15);color:' + rc + ';font-weight:600;text-transform:uppercase;">' + (p.risk_level || 'unknown') + '</span></td>';
    html += '<td style="font-family:var(--font-mono);font-size:11px;">' + (p.treatment || '') + '</td>';
    html += '<td style="font-size:11px;color:var(--text-muted);">' + (p.org_id || 'global') + '</td>';
    html += '<td><label class="toggle-switch" style="margin:0;"><input type="checkbox" ' + (p.is_active ? 'checked' : '') + ' onchange="_togglePrivPolicy(' + idx + ', this.checked)"><span class="toggle-slider"></span></label></td>';
    html += '<td><button class="btn btn-secondary btn-sm" style="color:var(--danger);border-color:rgba(239,68,68,0.3);" onclick="_deletePrivPolicy(' + idx + ')">&times;</button></td>';
    html += '</tr>';
  });
  tbody.innerHTML = html;
}

async function _togglePrivPolicy(idx, active) {
  if (!window._privPolicies || !window._privPolicies[idx]) return;
  window._privPolicies[idx].is_active = active;
  await _savePrivPolicies();
  showToast('Policy ' + (active ? 'enabled' : 'disabled'), 'success');
}

async function _deletePrivPolicy(idx) {
  if (!window._privPolicies) return;
  var name = window._privPolicies[idx].name;
  if (!confirm('Delete policy "' + name + '"?')) return;
  window._privPolicies.splice(idx, 1);
  await _savePrivPolicies();
  _renderPrivacyPoliciesTable();
  showToast('Policy deleted', 'success');
}

async function _savePrivPolicies() {
  var sb = window._dactaSupabase || window._supabaseRef;
  if (!sb || !window._privPolicies) return;
  await sb.from('platform_settings').upsert({ key: 'privacy_policies', value: window._privPolicies }, { onConflict: 'key' });
  // Refresh count
  _loadPrivacyPolicyCount(sb);
}

function _addPrivPolicy() {
  var name = document.getElementById('privNewPolicyName');
  var desc = document.getElementById('privNewPolicyDesc');
  var cats = document.getElementById('privNewPolicyCats');
  var treat = document.getElementById('privNewPolicyTreat');
  var risk = document.getElementById('privNewPolicyRisk');
  var org = document.getElementById('privNewPolicyOrg');

  if (!name || !name.value.trim()) { showToast('Policy name is required', 'warn'); return; }

  var newPolicy = {
    id: crypto.randomUUID ? crypto.randomUUID() : 'pp-' + Date.now(),
    name: name.value.trim(),
    description: desc ? desc.value.trim() : '',
    data_categories: cats ? cats.value.split(',').map(function(s) { return s.trim(); }).filter(Boolean) : [],
    treatment: treat ? treat.value : 'tokenize',
    risk_level: risk ? risk.value : 'critical',
    org_id: org ? org.value.trim() || 'global' : 'global',
    is_active: true,
    created_by: window._currentUser ? window._currentUser.email : 'admin@dacta.sg',
    created_at: new Date().toISOString()
  };

  if (!window._privPolicies) window._privPolicies = [];
  window._privPolicies.push(newPolicy);
  _savePrivPolicies();
  _renderPrivacyPoliciesTable();

  // Clear form
  name.value = ''; if (desc) desc.value = ''; if (cats) cats.value = '';
  showToast('Policy added: ' + newPolicy.name, 'success');
}

function initAICharts() {
  // Charts are now rendered by loadAIUsagePage after DB fetch.
  // This function is kept as a no-op for nav compatibility.
  // loadAIUsagePage calls _renderAICharts(byModel, byDay) directly.
}

function _renderAICharts(byModel, byDay) {
  var providerColors = {
    'Claude': ['rgba(224,108,117,0.75)', '#e06c75'],
    'GPT':    ['rgba(78,201,176,0.75)', '#4ec9b0'],
    'Gemini': ['rgba(139,92,246,0.75)', '#8b5cf6'],
    'Copilot':['rgba(86,156,214,0.75)', '#569cd6'],
    'DeepSeek':['rgba(220,220,170,0.75)','#dcdcaa'],
    'Perplexity':['rgba(86,156,214,0.75)','#569cd6']
  };
  var defaultC = ['rgba(0,212,255,0.75)', '#00d4ff'];

  // --- Provider/Model doughnut ---
  var ctx = document.getElementById('aiProviderChart');
  if (ctx) {
    var aiProvLabels = [], aiProvData = [], aiProvBg = [], aiProvBorder = [];
    if (byModel && Object.keys(byModel).length > 0) {
      Object.keys(byModel).forEach(function(m) {
        aiProvLabels.push(m);
        aiProvData.push(byModel[m].calls);
        var matched = defaultC;
        Object.keys(providerColors).forEach(function(k) { if (m.toLowerCase().indexOf(k.toLowerCase()) >= 0) matched = providerColors[k]; });
        aiProvBg.push(matched[0]);
        aiProvBorder.push(matched[1]);
      });
    } else {
      aiProvLabels = ['No data yet'];
      aiProvData = [1];
      aiProvBg = ['rgba(100,116,139,0.3)'];
      aiProvBorder = ['#64748b'];
    }
    charts.aiProvider = new Chart(ctx, {
      type: 'doughnut',
      data: {
        labels: aiProvLabels,
        datasets: [{ data: aiProvData, backgroundColor: aiProvBg, borderColor: aiProvBorder, borderWidth: 1.5, hoverOffset: 6 }]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: getThemeTooltipConfig()
        }, cutout: '70%'
      }
    });
  }

  // --- Daily line chart ---
  var ctx2 = document.getElementById('aiDailyChart');
  if (ctx2) {
    var dailyLabels = [], dailyVals = [];
    if (byDay && Object.keys(byDay).length > 0) {
      var sortedDays = Object.keys(byDay).sort();
      sortedDays.forEach(function(d) { dailyLabels.push(d.slice(5)); dailyVals.push(byDay[d].calls); });
    } else {
      var today = new Date().toISOString().slice(5, 10);
      dailyLabels = [today];
      dailyVals = [0];
    }
    charts.aiDaily = new Chart(ctx2, {
      type: 'line',
      data: {
        labels: dailyLabels,
        datasets: [{
          label: 'Requests',
          data: dailyVals,
          borderColor: 'rgba(0,212,255,0.8)',
          backgroundColor: 'rgba(0,212,255,0.07)',
          fill: true, tension: 0.4, pointRadius: 3, borderWidth: 2,
          pointBackgroundColor: 'rgba(0,212,255,0.9)',
        }]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: { legend: { display: false }, tooltip: getThemeTooltipConfig() },
        scales: {
          x: { grid: { color: getThemeGridColor() }, ticks: { color: getThemeTickColor(), font: { size: 9 } } },
          y: { grid: { color: getThemeGridColor() }, ticks: { color: getThemeTickColor(), font: { size: 9 } }, beginAtZero: true }
        }
      }
    });
  }
}

