// Utility: HTML entity escaping
function escapeHtml(s) {
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}
function _escHtml(s) { if (!s) return ''; var d = document.createElement('div'); d.textContent = s; return d.innerHTML; }

// Decode HTML entities (&#91; → [, &#93; → ], &amp; → &, etc.)
function decodeHtmlEntities(s) {
  return s.replace(/&#(\d+);/g, function(m, n) { return String.fromCharCode(parseInt(n)); })
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'");
}

// ── Session State ──
var _copilotIOCs = [];
var _copilotConversation = []; // Full message history for Claude
var _copilotBusy = false;

// ── Simple Markdown Renderer ──
function copilotRenderMarkdown(text) {
  if (!text) return '';
  var html = escapeHtml(text);
  
  // Code blocks (```...```)
  html = html.replace(/```(\w*)\n([\s\S]*?)```/g, function(m, lang, code) {
    return '<div class="copilot-code-block"><div class="copilot-code-lang">' + (lang || 'code') + '</div><pre><code>' + code.trim() + '</code></pre></div>';
  });
  
  // Inline code (`...`)
  html = html.replace(/`([^`]+)`/g, '<code class="copilot-inline-code">$1</code>');
  
  // Bold (**...**)
  html = html.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
  
  // Headers (## ... and ### ...)
  html = html.replace(/^### (.+)$/gm, '<h4 class="copilot-h4">$1</h4>');
  html = html.replace(/^## (.+)$/gm, '<h3 class="copilot-h3">$1</h3>');
  
  // Markdown tables (|col1|col2|...)
  html = html.replace(/(^\|.+\|\n)(^\|[-:|\s]+\|\n)((?:^\|.+\|\n?)+)/gm, function(match, headerRow, sepRow, bodyRows) {
    var headers = headerRow.trim().split('|').filter(function(c) { return c.trim(); });
    var rows = bodyRows.trim().split('\n');
    var tableHTML = '<table class="copilot-table"><thead><tr>';
    headers.forEach(function(h) { tableHTML += '<th>' + h.trim() + '</th>'; });
    tableHTML += '</tr></thead><tbody>';
    rows.forEach(function(row) {
      var cells = row.split('|').filter(function(c) { return c.trim() !== '' || c.includes(' '); });
      if (cells.length > 0 && cells.some(function(c){ return c.trim(); })) {
        tableHTML += '<tr>';
        cells.forEach(function(c) { tableHTML += '<td>' + c.trim() + '</td>'; });
        tableHTML += '</tr>';
      }
    });
    tableHTML += '</tbody></table>';
    return tableHTML;
  });
  
  // Unordered lists (- item)
  html = html.replace(/^- (.+)$/gm, '<li>$1</li>');
  html = html.replace(/(<li>.*<\/li>\n?)+/g, function(m) {
    return '<ul class="copilot-list">' + m + '</ul>';
  });
  
  // Ordered lists (1. item)
  html = html.replace(/^\d+\. (.+)$/gm, '<li>$1</li>');
  
  // Horizontal rule
  html = html.replace(/^---$/gm, '<hr class="copilot-hr">');
  
  // Paragraphs: convert double newlines to paragraph breaks
  html = html.replace(/\n\n/g, '</p><p>');
  html = '<p>' + html + '</p>';
  
  // Clean up empty paragraphs
  html = html.replace(/<p>\s*<\/p>/g, '');
  html = html.replace(/<p>\s*(<h[34])/g, '$1');
  html = html.replace(/(<\/h[34]>)\s*<\/p>/g, '$1');
  html = html.replace(/<p>\s*(<ul)/g, '$1');
  html = html.replace(/(<\/ul>)\s*<\/p>/g, '$1');
  html = html.replace(/<p>\s*(<div class="copilot-code)/g, '$1');
  html = html.replace(/(<\/pre><\/div>)\s*<\/p>/g, '$1');
  html = html.replace(/<p>\s*(<table)/g, '$1');
  html = html.replace(/(<\/table>)\s*<\/p>/g, '$1');
  html = html.replace(/<p>\s*(<hr)/g, '$1');
  
  return html;
}

