// ── Data Source Health Check ──
async function copilotCheckSources() {
  var statusEl = document.getElementById('copilotDataStatus');
  var sources = [];
  try {
    var r = await _siemFetch('/api/elastic', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({action:'search',index:'logs-*',body:{size:0}}) });
    sources.push(r.ok ? 'Elastic SIEM ' + dIcon('check',14) + '' : 'Elastic ' + dIcon('close',14) + '');
  } catch(e) { sources.push('Elastic ' + dIcon('close',14) + ''); }
  try {
    var r2 = await _siemFetch('/api/opencti', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({query:'{ about { version } }'}) });
    sources.push(r2.ok ? 'DACTA TIP ' + dIcon('check',14) + '' : 'DACTA TIP ' + dIcon('close',14) + '');
  } catch(e) { sources.push('DACTA TIP ' + dIcon('close',14) + ''); }
  try {
    var r3 = await _siemFetch('/api/jira', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({action:'search',jql:'project=DAC',maxResults:1}) });
    sources.push(r3.ok ? 'Jira ' + dIcon('check',14) + '' : 'Jira ' + dIcon('close',14) + '');
  } catch(e) { sources.push('Jira ' + dIcon('close',14) + ''); }
  // Check multi-scanner enrichment (VT + AbuseIPDB + CrowdStrike)
  try {
    var r4e = await _siemFetch('/api/ioc-enrich', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({action:'health'}) });
    var enrichData = r4e.ok ? await r4e.json().catch(function(){return {};}) : {};
    var scanners = enrichData.scanners || {};
    if (scanners.virustotal && scanners.virustotal.configured) sources.push('VirusTotal ' + dIcon('check',14));
    if (scanners.abuseipdb && scanners.abuseipdb.configured) sources.push('AbuseIPDB ' + dIcon('check',14));
    if (scanners.crowdstrike && scanners.crowdstrike.configured) sources.push('CrowdStrike ' + dIcon('check',14));
  } catch(e) { /* scanner health check optional */ }
  // Check Claude (OPTIONS pre-flight only — does NOT consume API tokens)
  try {
    var r4 = await _siemFetch('/api/copilot', { method:'OPTIONS' });
    sources.push((r4.ok || r4.status === 204) ? 'Claude AI ' + dIcon('check',14) + '' : 'Claude AI ' + dIcon('close',14) + '');
  } catch(e) { sources.push('Claude AI ' + dIcon('close',14) + ''); }
  if (statusEl) statusEl.innerHTML = sources.join(' \u00b7 ');
}

