/* ==============================================================
   TASK 6: HANDOVER ARTIFACT UPLOAD + CLIENT SEND TOGGLE
   ============================================================== */
var fileIconMap = { pdf: dIcon('document',14) + '', png: dIcon('image',14) + '', jpg: dIcon('image',14) + '', docx: dIcon('document',14) + '', doc: dIcon('document',14) + '', csv: dIcon('trendUp',14) + '', pcap: dIcon('antenna',14) + '', xlsx: dIcon('barChart',14) + '', txt: dIcon('note',14) + '' };
function getFileIcon(filename) {
  var ext = filename.split('.').pop().toLowerCase();
  return fileIconMap[ext] || dIcon('folder',14) + '';
}
function addArtifactFile(name, size) {
  var list = document.getElementById('artifactFileList');
  if (!list) return;
  var sizeStr = size > 1048576 ? (size/1048576).toFixed(1)+' MB' : (size > 1024 ? (size/1024).toFixed(0)+' KB' : size + ' B');
  var item = document.createElement('div');
  item.className = 'handover-file-item';
  item.innerHTML = '<div class="handover-file-icon">' + getFileIcon(name) + '</div><div class="handover-file-name">' + name + '</div><div style="font-size:10px;color:var(--text-muted);">' + sizeStr + '</div><div class="handover-file-remove" onclick="this.parentElement.remove()">&#x2715;</div>';
  list.appendChild(item);
}
function handleArtifactDrop(event) {
  event.preventDefault();
  document.getElementById('artifactDropZone').classList.remove('drag-over');
  var files = event.dataTransfer.files;
  for (var i = 0; i < files.length; i++) addArtifactFile(files[i].name, files[i].size);
}
function handleArtifactSelect(event) {
  var files = event.target.files;
  for (var i = 0; i < files.length; i++) addArtifactFile(files[i].name, files[i].size);
}
function toggleClientSend() {
  var toggle = document.getElementById('clientSendToggle');
  var fields = document.getElementById('clientSendFields');
  if (!toggle || !fields) return;
  var isOn = toggle.classList.contains('on');
  if (isOn) {
    toggle.classList.remove('on'); toggle.classList.add('off');
    fields.classList.remove('visible');
  } else {
    toggle.classList.remove('off'); toggle.classList.add('on');
    fields.classList.add('visible');
  }
}


/* ==============================================================
   SHIFT HANDOVER — Roster Planning, Handover Modal, Live Data
   ============================================================== */

// ── Roster State ──
var _rosterWeekOffset = 0;
var _rosterData = {}; // { 'YYYY-MM-DD': { shiftA: ['Name',...], shiftB: ['Name',...] } }
var _rosterAnalystPool = [];
var _rosterOnCall = {};
var _activePicker = null;

function openRosterModal() {
  _rosterWeekOffset = 0;
  document.getElementById('rosterOverlay').classList.add('open');
  loadRosterAnalysts();
  renderRosterGrid();
}
function closeRosterModal() {
  document.getElementById('rosterOverlay').classList.remove('open');
  if (_activePicker) { _activePicker.remove(); _activePicker = null; }
}
function rosterNavWeek(dir) {
  if (dir === 0) _rosterWeekOffset = 0;
  else _rosterWeekOffset += dir;
  renderRosterGrid();
}

async function loadRosterAnalysts() {
  try {
    var users = await DactaJira.fetchAssignableUsers();
    _rosterAnalystPool = (users.users || users || []).map(function(u) {
      return { id: u.accountId || u.id, name: u.displayName || u.name || 'Unknown' };
    });
  } catch(e) {
    console.error('[Roster] Failed to load analysts:', e);
    _rosterAnalystPool = [
      { id: 'a1', name: 'Christian Miguel' }, { id: 'a2', name: 'Wendy Melyana' },
      { id: 'a3', name: 'Marcfrance Limasin' }, { id: 'a4', name: 'John Lim' },
      { id: 'a5', name: 'Sarah Tan' }, { id: 'a6', name: 'Marcus Wong' }
    ];
  }
  // Load on-call from JSM
  try {
    var ops = await DactaJira.fetchOpsData();
    _rosterOnCall = {};
    (ops.schedules || []).forEach(function(s) {
      (s.onCall || []).forEach(function(p) {
        _rosterOnCall[p.name] = true;
      });
    });
  } catch(e) { console.warn('[Roster] On-call load failed:', e); }
  // Load saved roster from localStorage
  try {
    var saved = localStorage.getItem('dacta-roster');
    if (saved) _rosterData = JSON.parse(saved);
  } catch(e) {}
  renderRosterGrid();
}

function getWeekDates(offset) {
  var now = new Date();
  var monday = new Date(now);
  monday.setDate(now.getDate() - ((now.getDay() + 6) % 7) + (offset * 7));
  var dates = [];
  for (var i = 0; i < 7; i++) {
    var d = new Date(monday);
    d.setDate(monday.getDate() + i);
    dates.push(d);
  }
  return dates;
}

function fmtDate(d) { return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0'); }
function fmtDateShort(d) { return ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'][d.getDay()]+' '+d.getDate(); }

function renderRosterGrid() {
  var dates = getWeekDates(_rosterWeekOffset);
  var label = document.getElementById('rosterWeekLabel');
  var months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  if (label) label.textContent = months[dates[0].getMonth()] + ' ' + dates[0].getDate() + ' — ' + months[dates[6].getMonth()] + ' ' + dates[6].getDate() + ', ' + dates[0].getFullYear();

  var todayStr = fmtDate(new Date());
  var grid = document.getElementById('rosterGrid');
  if (!grid) return;

  var html = '<div class="roster-cell header"></div>';
  dates.forEach(function(d) {
    var cls = fmtDate(d) === todayStr ? 'roster-cell header today' : 'roster-cell header';
    html += '<div class="'+cls+'">'+fmtDateShort(d)+'</div>';
  });

  // Shift A row
  html += '<div class="roster-cell shift-label">SHIFT A<br><span style="font-size:8px;color:var(--text-muted);font-weight:400;">07:00–19:00</span></div>';
  dates.forEach(function(d) {
    var key = fmtDate(d);
    var cls = key === todayStr ? 'roster-cell today' : 'roster-cell';
    var roster = (_rosterData[key] && _rosterData[key].shiftA) || [];
    html += '<div class="'+cls+'" data-date="'+key+'" data-shift="shiftA">';
    // On-call tags
    Object.keys(_rosterOnCall).forEach(function(name) {
      html += '<div class="oncall-tag">&#9741; ON-CALL: '+escH(name.split(' ')[0])+'</div>';
    });
    roster.forEach(function(name, idx) {
      html += '<div class="roster-analyst" data-idx="'+idx+'">'+escH(name)+'<span class="ra-remove" onclick="removeRosterEntry(\x27'+key+'\x27,\x27shiftA\x27,'+idx+')">&#x2715;</span></div>';
    });
    html += '<div class="roster-add-btn" onclick="showAnalystPicker(this,\x27'+key+'\x27,\x27shiftA\x27)">+ Add</div>';
    html += '</div>';
  });

  // Shift B row
  html += '<div class="roster-cell shift-label b">SHIFT B<br><span style="font-size:8px;color:var(--text-muted);font-weight:400;">19:00–07:00</span></div>';
  dates.forEach(function(d) {
    var key = fmtDate(d);
    var cls = key === todayStr ? 'roster-cell today' : 'roster-cell';
    var roster = (_rosterData[key] && _rosterData[key].shiftB) || [];
    html += '<div class="'+cls+'" data-date="'+key+'" data-shift="shiftB">';
    roster.forEach(function(name, idx) {
      html += '<div class="roster-analyst shift-b" data-idx="'+idx+'">'+escH(name)+'<span class="ra-remove" onclick="removeRosterEntry(\x27'+key+'\x27,\x27shiftB\x27,'+idx+')">&#x2715;</span></div>';
    });
    html += '<div class="roster-add-btn" onclick="showAnalystPicker(this,\x27'+key+'\x27,\x27shiftB\x27)">+ Add</div>';
    html += '</div>';
  });

  grid.innerHTML = html;
}

function showAnalystPicker(el, dateKey, shift) {
  if (_activePicker) { _activePicker.remove(); _activePicker = null; }
  var picker = document.createElement('div');
  picker.className = 'roster-analyst-picker';
  var existing = (_rosterData[dateKey] && _rosterData[dateKey][shift]) || [];
  _rosterAnalystPool.forEach(function(a) {
    if (existing.indexOf(a.name) !== -1) return; // already assigned
    var initials = a.name.split(' ').map(function(w){return w[0]}).join('').substring(0,2).toUpperCase();
    picker.innerHTML += '<div class="rap-item" onclick="addRosterEntry(\x27'+dateKey+'\x27,\x27'+shift+'\x27,\x27'+escH(a.name)+'\x27)"><span class="rap-avatar">'+initials+'</span>'+escH(a.name)+'</div>';
  });
  if (!picker.innerHTML) picker.innerHTML = '<div style="padding:6px;font-size:10px;color:var(--text-muted);">All analysts assigned</div>';
  el.parentElement.appendChild(picker);
  _activePicker = picker;
  setTimeout(function() {
    document.addEventListener('click', function handler(e) {
      if (!picker.contains(e.target) && e.target !== el) {
        picker.remove(); _activePicker = null;
        document.removeEventListener('click', handler);
      }
    });
  }, 10);
}

function addRosterEntry(dateKey, shift, name) {
  if (!_rosterData[dateKey]) _rosterData[dateKey] = { shiftA: [], shiftB: [] };
  if (!_rosterData[dateKey][shift]) _rosterData[dateKey][shift] = [];
  _rosterData[dateKey][shift].push(name);
  if (_activePicker) { _activePicker.remove(); _activePicker = null; }
  renderRosterGrid();
}

function removeRosterEntry(dateKey, shift, idx) {
  if (_rosterData[dateKey] && _rosterData[dateKey][shift]) {
    _rosterData[dateKey][shift].splice(idx, 1);
  }
  renderRosterGrid();
}

function saveRoster() {
  localStorage.setItem('dacta-roster', JSON.stringify(_rosterData));
  showToast('Roster saved successfully', 'success');
  closeRosterModal();
}

// ── Handover Modal ──
var _hoModalFiles = [];

function openHandoverModal() {
  document.getElementById('handoverModalOverlay').classList.add('open');
  _hoModalFiles = [];
  document.getElementById('hoModalFileList').innerHTML = '';
  document.getElementById('hoModalNotes').value = '';
  loadHandoverOpenItems();
}
function closeHandoverModal() {
  document.getElementById('handoverModalOverlay').classList.remove('open');
}

async function loadHandoverOpenItems() {
  var container = document.getElementById('hoModalOpenItems');
  if (!container) return;
  try {
    var data = await DactaJira.fetchTriage({ maxResults: 50 });
    var tickets = (data.issues || data.tickets || []).filter(function(t) {
      var fields = t.fields || t;
      var status = (fields.status && fields.status.name) ? fields.status.name.toLowerCase() : (fields.statusName || '').toLowerCase();
      return status !== 'closed' && status !== 'canceled' && status !== 'completed';
    });
    if (!tickets.length) {
      container.innerHTML = '<div style="text-align:center;padding:12px;color:var(--text-muted);font-size:10px;">No open tickets to hand over.</div>';
      return;
    }
    var html = '';
    tickets.slice(0, 20).forEach(function(t) {
      var fields = t.fields || t;
      var key = t.key || fields.key || '—';
      var summary = fields.summary || fields.title || '';
      var priority = (fields.priority && fields.priority.name) ? fields.priority.name : fields.priorityShort || 'P3';
      var pShort = priority.replace(/[^0-9]/g, '') || '3';
      html += '<div class="ho-open-item">' +
        '<input type="checkbox" checked>' +
        '<span class="ho-oi-key">'+escH(key)+'</span>' +
        '<span class="ho-oi-priority"><span class="badge badge-p'+pShort+'">P'+pShort+'</span></span>' +
        '<span class="ho-oi-title">'+escH(summary.substring(0,80))+'</span>' +
        '</div>';
    });
    container.innerHTML = html;
  } catch(e) {
    console.error('[Handover] Failed to load open items:', e);
    container.innerHTML = '<div style="text-align:center;padding:12px;color:var(--red-bright);font-size:10px;">Failed to load open items from Jira</div>';
  }
}

function hoModalArtifactDrop(event) {
  event.preventDefault();
  document.getElementById('hoModalDropZone').classList.remove('drag-over');
  var files = event.dataTransfer.files;
  for (var i = 0; i < files.length; i++) addHoModalFile(files[i].name, files[i].size);
}
function hoModalArtifactSelect(event) {
  var files = event.target.files;
  for (var i = 0; i < files.length; i++) addHoModalFile(files[i].name, files[i].size);
}
function addHoModalFile(name, size) {
  _hoModalFiles.push({ name: name, size: size });
  renderHoModalFiles();
}
function removeHoModalFile(idx) {
  _hoModalFiles.splice(idx, 1);
  renderHoModalFiles();
}
function renderHoModalFiles() {
  var list = document.getElementById('hoModalFileList');
  if (!list) return;
  if (!_hoModalFiles.length) { list.innerHTML = ''; return; }
  var html = '';
  _hoModalFiles.forEach(function(f, i) {
    var sz = f.size > 1048576 ? (f.size/1048576).toFixed(1)+' MB' : (f.size > 1024 ? (f.size/1024).toFixed(0)+' KB' : f.size+' B');
    html += '<div class="handover-file-item"><div class="handover-file-icon">' + getFileIcon(f.name) + '</div><div class="handover-file-name">'+escH(f.name)+'</div><div style="font-size:10px;color:var(--text-muted);">'+sz+'</div><div class="handover-file-remove" onclick="removeHoModalFile('+i+')">&#x2715;</div></div>';
  });
  list.innerHTML = html;
}

function toggleHoClientSend() {
  var toggle = document.getElementById('hoClientToggle');
  var fields = document.getElementById('hoClientFields');
  if (!toggle || !fields) return;
  var isOn = toggle.classList.contains('on');
  if (isOn) {
    toggle.classList.remove('on'); toggle.classList.add('off');
    fields.classList.remove('visible');
  } else {
    toggle.classList.remove('off'); toggle.classList.add('on');
    fields.classList.add('visible');
  }
}

function saveDraftHandover() {
  var notes = document.getElementById('hoModalNotes').value;
  localStorage.setItem('dacta-handover-draft', JSON.stringify({ notes: notes, files: _hoModalFiles, timestamp: Date.now() }));
  showToast('Handover draft saved', 'info');
}

function submitHandover() {
  var notes = document.getElementById('hoModalNotes').value.trim();
  if (!notes) { showToast('Please enter handover notes before submitting', 'warning'); return; }
  // Gather checked open items
  var checks = document.querySelectorAll('#hoModalOpenItems .ho-open-item input[type="checkbox"]');
  var items = [];
  checks.forEach(function(cb) {
    if (cb.checked) {
      var item = cb.closest('.ho-open-item');
      if (item) {
        var key = item.querySelector('.ho-oi-key');
        var title = item.querySelector('.ho-oi-title');
        items.push({ key: key ? key.textContent : '', title: title ? title.textContent : '' });
      }
    }
  });

  // Save handover to localStorage (acts as SIEMLess DB for now)
  var shift = getCurrentShiftInfo();
  var handover = {
    shift: shift.name,
    notes: notes,
    openItems: items,
    files: _hoModalFiles.map(function(f){return f.name}),
    timestamp: new Date().toISOString(),
    author: 'Current User'
  };
  var history = JSON.parse(localStorage.getItem('dacta-handover-history') || '[]');
  history.unshift(handover);
  if (history.length > 20) history = history.slice(0, 20);
  localStorage.setItem('dacta-handover-history', JSON.stringify(history));
  localStorage.removeItem('dacta-handover-draft');

  // If send to client is on
  var toggle = document.getElementById('hoClientToggle');
  if (toggle && toggle.classList.contains('on')) {
    var to = document.getElementById('hoClientTo').value;
    showToast('Handover submitted + sent to ' + (to || 'client'), 'success');
  } else {
    showToast('Handover submitted successfully', 'success');
  }

  closeHandoverModal();
  loadHandoverPageData(); // refresh page
}

// ── Live Data Loading ──
async function loadHandoverPageData() {
  var shift = getCurrentShiftInfo();
  updateShiftDisplays();

  // Load metrics from Jira
  try {
    var dash = await DactaJira.fetchDashboard();
    var openEl = document.getElementById('hoOpenCount');
    var closedEl = document.getElementById('hoClosedCount');
    var escEl = document.getElementById('hoEscalatedCount');
    if (openEl) openEl.textContent = (dash.totalOpen !== undefined ? dash.totalOpen : dash.open || 0);
    if (closedEl) closedEl.textContent = (dash.resolved || dash.closed || 0);
    if (escEl) escEl.textContent = (dash.escalated || 0);
  } catch(e) { console.warn('[Handover] Dashboard load failed:', e); }

  // Load on-duty team from JSM ops
  try {
    var ops = await DactaJira.fetchOpsData();
    renderOnDutyTeams(ops, shift);
  } catch(e) {
    console.warn('[Handover] Ops load failed:', e);
    renderFallbackTeams(shift);
  }

  // Load open items table
  loadOpenItemsTable();

  // Load previous handover notes
  loadPreviousHandoverNotes();

  // Load ops command center
  loadOpsCommandData();
}

function renderOnDutyTeams(ops, shift) {
  var onDutyEl = document.getElementById('hoOnDutyList');
  var incomingEl = document.getElementById('hoIncomingList');
  if (!onDutyEl || !incomingEl) return;

  var colors = ['linear-gradient(135deg,#00d4ff,#3b82f6)', 'linear-gradient(135deg,#f59e0b,#ef4444)', 'linear-gradient(135deg,#10b981,#3b82f6)', 'linear-gradient(135deg,#8b5cf6,#06b6d4)', 'linear-gradient(135deg,#f97316,#8b5cf6)', 'linear-gradient(135deg,#ef4444,#f59e0b)'];

  // Current on-call from ops
  var onCallNames = [];
  (ops.schedules || []).forEach(function(s) {
    (s.onCall || []).forEach(function(p) {
      if (onCallNames.indexOf(p.name) === -1) onCallNames.push(p.name);
    });
  });

  // Get roster for today
  var todayKey = fmtDate(new Date());
  var todayRoster = _rosterData[todayKey] || {};
  var shiftATeam = todayRoster.shiftA || [];
  var shiftBTeam = todayRoster.shiftB || [];

  var currentTeamNames = (shift.name === 'Shift A') ? shiftATeam : shiftBTeam;
  var incomingTeamNames = (shift.name === 'Shift A') ? shiftBTeam : shiftATeam;

  // If no roster, use on-call
  if (!currentTeamNames.length) currentTeamNames = onCallNames.length ? onCallNames : [];

  function renderTeamList(el, names, isOnCall) {
    if (!names.length) {
      el.innerHTML = '<div style="text-align:center;padding:12px;color:var(--text-muted);font-size:10px;">No roster assigned. Use Plan Roster to assign analysts.</div>';
      return;
    }
    var html = '';
    names.forEach(function(name, i) {
      var initials = name.split(' ').map(function(w){return w[0]}).join('').substring(0,2).toUpperCase();
      var isOC = onCallNames.indexOf(name) !== -1;
      html += '<div class="ho-team-member"><div class="ho-tm-avatar" style="background:'+colors[i%colors.length]+';">'+initials+'</div><div><div class="ho-tm-name">'+escH(name)+'</div><div class="ho-tm-role">SOC Analyst</div></div>';
      if (isOC) html += '<div class="ho-tm-oncall">ON-CALL</div>';
      html += '<div class="status-dot green" style="margin-left:auto;"></div></div>';
    });
    el.innerHTML = html;
  }

  renderTeamList(onDutyEl, currentTeamNames, true);
  renderTeamList(incomingEl, incomingTeamNames, false);
}

function renderFallbackTeams(shift) {
  var onDutyEl = document.getElementById('hoOnDutyList');
  var incomingEl = document.getElementById('hoIncomingList');
  if (onDutyEl) onDutyEl.innerHTML = '<div style="text-align:center;padding:12px;color:var(--text-muted);font-size:10px;">Use Plan Roster to assign analysts to shifts.</div>';
  if (incomingEl) incomingEl.innerHTML = '<div style="text-align:center;padding:12px;color:var(--text-muted);font-size:10px;">No incoming roster configured.</div>';
}

async function loadOpenItemsTable() {
  var tbody = document.getElementById('hoOpenItemsBody');
  var badge = document.getElementById('hoOpenItemsBadge');
  if (!tbody) return;

  try {
    var data = await DactaJira.fetchTriage({ maxResults: 100 });
    var tickets = (data.issues || data.tickets || []).filter(function(t) {
      var fields = t.fields || t;
      var status = (fields.status && fields.status.name) ? fields.status.name.toLowerCase() : (fields.statusName || '').toLowerCase();
      return status !== 'closed' && status !== 'canceled' && status !== 'completed';
    });

    if (badge) badge.textContent = tickets.length + ' items';

    if (!tickets.length) {
      tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:20px;color:var(--green);font-size:11px;">All clear — no open items.</td></tr>';
      return;
    }

    var html = '';
    tickets.slice(0, 25).forEach(function(t) {
      var fields = t.fields || t;
      var key = t.key || fields.key || '—';
      var summary = fields.summary || fields.title || '';
      var priority = (fields.priority && fields.priority.name) ? fields.priority.name : fields.priorityShort || 'P3';
      var pShort = priority.replace(/[^0-9]/g, '') || '3';
      var org = (fields.customfield_10002 && fields.customfield_10002.name) ? fields.customfield_10002.name : fields.org || fields.organization || '—';
      if (Array.isArray(fields.customfield_10002)) org = fields.customfield_10002.map(function(o){return o.name||o}).join(', ');
      var status = (fields.status && fields.status.name) ? fields.status.name : fields.statusName || '—';
      var assignee = (fields.assignee && fields.assignee.displayName) ? fields.assignee.displayName : fields.assigneeName || 'Unassigned';
      var created = fields.created ? new Date(fields.created).toLocaleDateString('en-GB',{day:'2-digit',month:'short',hour:'2-digit',minute:'2-digit'}) : '—';

      var statusCls = '';
      if (status.toLowerCase() === 'open') statusCls = 'badge-amber';
      else if (status.toLowerCase().indexOf('escalat') !== -1) statusCls = 'badge-red';
      else if (status.toLowerCase().indexOf('report') !== -1) statusCls = 'badge-blue';
      else statusCls = 'badge-blue';

      html += '<tr>' +
        '<td class="mono" style="color:var(--cyan);font-size:10px;font-weight:600;">'+escH(key)+'</td>' +
        '<td><span class="badge badge-p'+pShort+'">P'+pShort+'</span></td>' +
        '<td style="max-width:250px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:var(--text-primary);font-weight:500;">'+escH(summary.substring(0,60))+'</td>' +
        '<td style="font-size:10px;">'+escH(typeof org === 'string' ? org : '—')+'</td>' +
        '<td><span class="badge '+statusCls+'" style="font-size:9px;">'+escH(status.toUpperCase())+'</span></td>' +
        '<td style="font-size:10px;">'+escH(assignee)+'</td>' +
        '<td style="font-size:10px;font-family:var(--font-mono);color:var(--text-muted);">'+created+'</td>' +
        '</tr>';
    });
    tbody.innerHTML = html;
  } catch(e) {
    console.error('[Handover] Open items load failed:', e);
    tbody.innerHTML = '<tr><td colspan="7" style="text-align:center;padding:20px;color:var(--red-bright);font-size:11px;">Failed to load open items from Jira</td></tr>';
  }
}

function loadPreviousHandoverNotes() {
  var container = document.getElementById('hoNotesContainer');
  var timestamp = document.getElementById('hoNotesTimestamp');
  if (!container) return;

  var history = JSON.parse(localStorage.getItem('dacta-handover-history') || '[]');
  if (!history.length) {
    container.innerHTML = '<div class="ho-notes-empty">No handover notes from previous shift yet.</div>';
    return;
  }

  var latest = history[0];
  if (timestamp) {
    var ts = new Date(latest.timestamp);
    timestamp.textContent = ts.toLocaleString('en-SG', { day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit', timeZone: 'Asia/Singapore' }) + ' SGT';
  }

  var html = '<div class="ho-notes-card">' +
    '<div class="ho-nc-header"><div class="ho-nc-from">From: ' + escH(latest.author || 'Analyst') + ' · ' + escH(latest.shift || '') + '</div>' +
    '<div class="ho-nc-time">' + new Date(latest.timestamp).toLocaleTimeString('en-SG', { hour: '2-digit', minute: '2-digit', timeZone: 'Asia/Singapore' }) + '</div></div>' +
    '<div class="ho-nc-body">' + escH(latest.notes).replace(/\n/g, '<br>') + '</div>';

  if (latest.openItems && latest.openItems.length) {
    html += '<div style="margin-top:8px;"><div style="font-size:9px;font-weight:700;text-transform:uppercase;color:var(--text-muted);margin-bottom:4px;">Open Items Handed Over:</div>';
    latest.openItems.forEach(function(item) {
      html += '<div style="font-size:10px;color:var(--text-secondary);padding:2px 0;"><span style="color:var(--cyan);font-family:var(--font-mono);">'+escH(item.key)+'</span> — '+escH(item.title)+'</div>';
    });
    html += '</div>';
  }

  if (latest.files && latest.files.length) {
    html += '<div style="margin-top:6px;font-size:9px;color:var(--text-muted);">Artifacts: ' + latest.files.join(', ') + '</div>';
  }

  html += '</div>';

  // Show older handovers
  if (history.length > 1) {
    html += '<div style="margin-top:8px;font-size:10px;color:var(--text-muted);cursor:pointer;" onclick="var el=this.nextElementSibling;if(el.style.display===\x27none\x27){el.style.display=\x27block\x27;this.textContent=\x27Hide older handovers\x27;}else{el.style.display=\x27none\x27;this.textContent=\x27Show older handovers...\x27;}">Show '+Math.min(history.length-1,5)+' older handovers...</div>';
    html += '<div style="display:none;margin-top:6px;">';
    history.slice(1,6).forEach(function(h) {
      html += '<div class="ho-notes-card" style="margin-bottom:6px;opacity:0.7;"><div class="ho-nc-header"><div class="ho-nc-from">'+escH(h.author||'Analyst')+' · '+escH(h.shift||'')+'</div><div class="ho-nc-time">'+new Date(h.timestamp).toLocaleDateString('en-SG')+'</div></div><div class="ho-nc-body">'+escH(h.notes||'').replace(/\n/g,'<br>').substring(0,200)+'</div></div>';
    });
    html += '</div>';
  }

  container.innerHTML = html;
}

function generateHandoverReport() {
  showToast('Generating handover report...', 'info');
  setTimeout(function() { showToast('Handover report generated and ready for download', 'success'); }, 1500);
}

function completeHandover() {
  var shift = getCurrentShiftInfo();
  showToast('Handover from ' + shift.name + ' to ' + shift.next + ' completed', 'success');
}

// ── Escalation Modal Attach Files ──
var _escModalAttachments = [];

function handleEscModalAttach(event) {
  var files = event.target.files;
  for (var i = 0; i < files.length; i++) {
    _escModalAttachments.push({ name: files[i].name, size: files[i].size });
  }
  showToast(_escModalAttachments.length + ' file(s) attached', 'info');
  // Show file names in modal
  renderEscModalAttachments();
}

function renderEscModalAttachments() {
  var existing = document.getElementById('escModalAttachList');
  if (existing) existing.remove();
  if (!_escModalAttachments.length) return;

  var footer = document.querySelector('.esc-modal-footer');
  if (!footer) return;

  var list = document.createElement('div');
  list.id = 'escModalAttachList';
  list.style.cssText = 'display:flex;flex-wrap:wrap;gap:4px;padding:0 20px 8px;';
  _escModalAttachments.forEach(function(f, i) {
    list.innerHTML += '<div style="display:flex;align-items:center;gap:4px;padding:3px 8px;background:rgba(0,212,255,0.08);border:1px solid rgba(0,212,255,0.15);border-radius:4px;font-size:9px;color:var(--text-secondary);"><span style="font-family:var(--font-mono);">'+escH(f.name)+'</span><span style="cursor:pointer;color:var(--red-bright);font-size:10px;" onclick="removeEscModalAttach('+i+')">&#x2715;</span></div>';
  });
  footer.parentElement.insertBefore(list, footer);
}

function removeEscModalAttach(idx) {
  _escModalAttachments.splice(idx, 1);
  renderEscModalAttachments();
}

