    var fbSrcIPs = [...new Set(elasticLogs.firewallBlocks.map(function(b) { return b.srcIp; }).filter(Boolean))].slice(0,3).join(', ');
    var fbDstIPs = [...new Set(elasticLogs.firewallBlocks.map(function(b) { return b.dstIp; }).filter(Boolean))].slice(0,3).join(', ');
