    console.log('[Evidence] Jira correlation classification: ' + _jcFPCount + ' FP, ' + _jcTPCount + ' TP, ' + _jcUnknownCount + ' unknown, ' + _jcOpen + ' open (from ' + _jcLen + ' total, ' + Object.keys(_ticketAnalystText).length + ' with analyst text)');

    var _jcKeys = elasticLogs.jiraCorrelation.slice(0, 5).map(function(j) { return j.key; }).join(', ');

