// ── Org helper: get org profile for simulation ──
function getOrgSimProfile(orgId) {
  var org = ORG_CONNECTORS[orgId];
  if (!org) return null;
  var edrConn = org.connectors.find(function(c) { return c.connector_type === 'edr'; });
  var siemConn = org.connectors.find(function(c) { return c.connector_type === 'siem'; });
  var edrVendor = (edrConn && edrConn.is_enabled && edrConn.vendor !== 'None') ? edrConn.vendor : 'None';
  var siemVendor = (siemConn && siemConn.is_enabled) ? siemConn.vendor : 'None';
  // Collect all enabled log source categories
  var logCats = [];
  org.connectors.forEach(function(c) {
    if (c.is_enabled && CONNECTOR_TO_LOGSOURCE[c.connector_type]) {
      CONNECTOR_TO_LOGSOURCE[c.connector_type].forEach(function(cat) {
        if (logCats.indexOf(cat) === -1) logCats.push(cat);
      });
    }
  });
  return { orgId: orgId, name: org.name, namespace: org.namespace, code: org.code, edr: edrVendor, siem: siemVendor, siemMeta: siemConn ? siemConn.metadata : {}, logCategories: logCats, connectors: org.connectors };
}

// ── Populate org selectors ──
function populateRlOrgSelectors() {
  var selectors = [document.getElementById('rlOrgSelector'), document.getElementById('rlTestTarget')];
  selectors.forEach(function(sel) {
    if (!sel) return;
    var current = sel.value;
    sel.innerHTML = '<option value="all">All Organizations</option>';
    Object.keys(ORG_CONNECTORS).forEach(function(id) {
      var org = ORG_CONNECTORS[id];
      var edrConn = org.connectors.find(function(c) { return c.connector_type === 'edr' && c.is_enabled && c.vendor !== 'None'; });
      var siemConn = org.connectors.find(function(c) { return c.connector_type === 'siem' && c.is_enabled; });
      var tags = [];
      if (siemConn) tags.push(siemConn.vendor);
      if (edrConn) tags.push(edrConn.vendor);
      sel.innerHTML += '<option value="' + id + '">' + escHtml(org.name) + (tags.length ? ' (' + tags.join(' + ') + ')' : '') + '</option>';
    });
    if (current) sel.value = current;
  });
}

function onRlOrgChange() {
  // Sync both org selectors
  var header = document.getElementById('rlOrgSelector');
  var target = document.getElementById('rlTestTarget');
  if (header && target) target.value = header.value;
  // Refresh simulation library with relevance scores
  loadSimulationLibrary();
}

// ── Load Simulation Library into Tab 1 (with per-org relevance) ──
function loadSimulationLibrary() {
  var grid = document.getElementById('rlSimGrid');
  if (!grid) return;

  var selectedOrg = (document.getElementById('rlOrgSelector') || {}).value || 'all';
  var orgProfiles = [];
  if (selectedOrg === 'all') {
    Object.keys(ORG_CONNECTORS).forEach(function(id) { var p = getOrgSimProfile(id); if (p) orgProfiles.push(p); });
  } else {
    var p = getOrgSimProfile(selectedOrg);
    if (p) orgProfiles.push(p);
  }

  var iconSvgs = {
    malware: '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#ef4444" stroke-width="2"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>',
    lateral: '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#a78bfa" stroke-width="2"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87"/><path d="M16 3.13a4 4 0 010 7.75"/></svg>',
    credential: '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#60a5fa" stroke-width="2"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"/><path d="M7 11V7a5 5 0 0110 0v4"/></svg>',
    exfil: '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#fbbf24" stroke-width="2"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg>',
    c2: '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#34d399" stroke-width="2"><circle cx="12" cy="12" r="2"/><path d="M16.24 7.76a6 6 0 010 8.49m-8.48-.01a6 6 0 010-8.49m11.31-2.82a10 10 0 010 14.14m-14.14 0a10 10 0 010-14.14"/></svg>',
    persistence: '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#f472b6" stroke-width="2"><path d="M12 22c5.523 0 10-4.477 10-10S17.523 2 12 2 2 6.477 2 12s4.477 10 10 10z"/><path d="M12 6v6l4 2"/></svg>'
  };

  var sevBadge = { Critical:'badge-red', High:'badge-amber', Medium:'badge-cyan' };

  var html = '';
  SIMULATION_LIBRARY.forEach(function(sim) {
    // Calculate relevance: how many techniques can be assessed against selected orgs
    var relevanceScore = 0;
    var totalTechs = sim.techniques.length;
    sim.techniques.forEach(function(tech) {
      var reqs = TECHNIQUE_LOG_REQUIREMENTS[tech] || [];
      orgProfiles.forEach(function(prof) {
        var hasLogs = reqs.length === 0 || reqs.some(function(r) { return prof.logCategories.indexOf(r) >= 0; });
        if (hasLogs) { relevanceScore++; return; }
      });
    });
    var relevancePct = orgProfiles.length > 0 ? Math.round((relevanceScore / (totalTechs * orgProfiles.length)) * 100) : 0;
    var relevanceColor = relevancePct >= 70 ? 'var(--green)' : relevancePct >= 40 ? 'var(--amber)' : 'var(--red-bright)';

    html += '<div class="rl-sim-card" data-sim-category="' + sim.category + '" onclick="launchSimFromCard(\'' + escAttr(sim.name) + '\')">';
    html += '<div class="rl-sim-header">';
    html += '<div class="rl-sim-icon ' + sim.icon + '">' + (iconSvgs[sim.icon] || iconSvgs.malware) + '</div>';
    html += '<div style="flex:1;">';
    html += '<div style="font-size:13px;font-weight:600;color:var(--text-primary);">' + escHtml(sim.name) + '</div>';
    html += '<div style="font-size:10px;color:var(--text-muted);">' + sim.steps + ' attack steps \xb7 ' + sim.techniques.length + ' MITRE techniques \xb7 ' + sim.duration + '</div>';
    html += '</div>';
    html += '<span class="badge ' + (sevBadge[sim.severity] || 'badge-cyan') + '">' + sim.severity + '</span></div>';
    // Relevance indicator
    if (selectedOrg !== 'all' || orgProfiles.length > 0) {
      html += '<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px;">';
      html += '<div style="flex:1;height:4px;background:rgba(255,255,255,0.06);border-radius:2px;overflow:hidden;"><div style="height:100%;width:' + relevancePct + '%;background:' + relevanceColor + ';border-radius:2px;"></div></div>';
      html += '<span style="font-size:9px;color:' + relevanceColor + ';font-weight:600;">' + relevancePct + '% relevant</span>';
      html += '</div>';
    }
    html += '<div style="display:flex;gap:4px;flex-wrap:wrap;">';
    sim.techniques.forEach(function(t) { html += '<span class="mitre-tag">' + t + '</span>'; });
    html += '</div>';
    html += '<div style="font-size:10px;color:var(--text-muted);margin-top:8px;">' + escHtml(sim.description) + '</div>';
    html += '</div>';
  });
  grid.innerHTML = html;
}

