// elastic_client.py — Elasticsearch interface
// ============================================================
'elastic_client.py': [
'"""',
'Elasticsearch client for the Novelty Catcher Agent.',
'Handles connection, querying, batch fetching, and alert indexing.',
'"""',
'',
'import logging',
'import time',
'import json',
'',
'import requests',
'',
'logger = logging.getLogger("novelty-catcher.elastic")',
'',
'',
'class ElasticClient:',
'    """Thin Elasticsearch REST client using requests (no elasticsearch-py dep)."""',
'',
'    def __init__(self, url, api_key, indices, batch_size=1000):',
'        self.url = url.rstrip("/") if url else ""',
'        self.api_key = api_key or ""',
'        self.indices = indices or []',
'        self.batch_size = batch_size',
'        self._session = requests.Session()',
'        if self.api_key:',
'            self._session.headers["Authorization"] = "ApiKey " + self.api_key',
'        self._session.headers["Content-Type"] = "application/json"',
'        self._last_poll_ts = None',
'',
'    # ------------------------------------------------------------------',
'    # Health check',
'    # ------------------------------------------------------------------',
'',
'    def ping(self):',
'        """Check cluster connectivity."""',
'        if not self.url:',
'            logger.warning("Elasticsearch URL not configured")',
'            return False',
'        try:',
'            resp = self._session.get(self.url, timeout=10)',
'            return resp.status_code == 200',
'        except Exception:',
'            logger.exception("Elasticsearch ping failed")',
'            return False',
'',
'    # ------------------------------------------------------------------',
'    # Querying',
'    # ------------------------------------------------------------------',
'',
'    def _build_index_str(self):',
'        """Build comma-separated index pattern string."""',
'        if not self.indices:',
'            return "*"',
'        return ",".join(self.indices)',
'',
'    def _search(self, body, size=None):',
'        """Execute an _search request and return hits."""',
'        if not self.url:',
'            logger.debug("Elasticsearch not configured — skipping search")',
'            return []',
'        idx = self._build_index_str()',
'        endpoint = "{}/{}/_search".format(self.url, idx)',
'        if size is not None:',
'            body["size"] = size',
'        try:',
'            resp = self._session.post(endpoint, json=body, timeout=30)',
'            if resp.status_code != 200:',
'                logger.error("ES search failed: %d %s", resp.status_code, resp.text[:500])',
'                return []',
'            data = resp.json()',
'            hits = data.get("hits", {}).get("hits", [])',
'            return [h.get("_source", {}) for h in hits]',
'        except requests.exceptions.Timeout:',
'            logger.error("ES search timed out")',
'            return []',
'        except Exception:',
'            logger.exception("ES search error")',
'            return []',
'',
'    def poll_recent(self, lookback_minutes=5):',
'        """Fetch events from the last N minutes, sorted by @timestamp desc."""',
'        now_ms = int(time.time() * 1000)',
'        from_ms = now_ms - (lookback_minutes * 60 * 1000)',
'        body = {',
'            "query": {',
'                "range": {',
'                    "@timestamp": {',
'                        "gte": from_ms,',
'                        "lte": now_ms,',
'                        "format": "epoch_millis"',
'                    }',
'                }',
'            },',
'            "sort": [{"@timestamp": {"order": "desc"}}],',
'        }',
'        return self._search(body, size=self.batch_size)',
'',
'    def fetch_historical(self, lookback_hours=168):',
'        """Fetch historical events in batches using search_after for pagination."""',
'        if not self.url:',
'            logger.warning("Elasticsearch not configured — cannot fetch historical data")',
'            return []',
'',
'        now_ms = int(time.time() * 1000)',
'        from_ms = now_ms - (lookback_hours * 3600 * 1000)',
'        all_events = []',
'        search_after = None',
'        page = 0',
'',
'        logger.info("Fetching historical data: %d hours, indices=%s", lookback_hours, self.indices)',
'',
'        while True:',
'            body = {',
'                "size": self.batch_size,',
'                "query": {',
'                    "range": {',
'                        "@timestamp": {',
'                            "gte": from_ms,',
'                            "lte": now_ms,',
'                            "format": "epoch_millis"',
'                        }',
'                    }',
'                },',
'                "sort": [',
'                    {"@timestamp": {"order": "asc"}},',
'                    {"_id": {"order": "asc"}}',
'                ],',
'            }',
'            if search_after:',
'                body["search_after"] = search_after',
'',
'            idx = self._build_index_str()',
'            endpoint = "{}/{}/_search".format(self.url, idx)',
'            try:',
'                resp = self._session.post(endpoint, json=body, timeout=60)',
'                if resp.status_code != 200:',
'                    logger.error("ES historical fetch failed: %d", resp.status_code)',
'                    break',
'                data = resp.json()',
'                hits = data.get("hits", {}).get("hits", [])',
'                if not hits:',
'                    break',
'                for h in hits:',
'                    all_events.append(h.get("_source", {}))',
'                search_after = hits[-1].get("sort")',
'                page += 1',
'                if page % 10 == 0:',
'                    logger.info("Fetched %d events so far (%d pages)", len(all_events), page)',
'                if len(hits) < self.batch_size:',
'                    break',
'            except Exception:',
'                logger.exception("Error fetching historical batch (page %d)", page)',
'                break',
'',
'        logger.info("Historical fetch complete: %d events in %d pages", len(all_events), page)',
'        return all_events',
'',
'    # ------------------------------------------------------------------',
'    # Alert indexing',
'    # ------------------------------------------------------------------',
'',
'    def index_alert(self, index, alert_doc):',
'        """Index a single alert document into Elasticsearch."""',
'        if not self.url:',
'            return False',
'        endpoint = "{}/{}/_doc".format(self.url, index)',
'        try:',
'            resp = self._session.post(endpoint, json=alert_doc, timeout=10)',
'            if resp.status_code not in (200, 201):',
'                logger.error("Failed to index alert: %d %s", resp.status_code, resp.text[:300])',
'                return False',
'            return True',
'        except Exception:',
'            logger.exception("Error indexing alert")',
'            return False',
].join('\n'),


