// reporter.py — SIEMLess API client (heartbeat, alerts, config)
// ============================================================
'reporter.py': [
'"""',
'SIEMLess Reporter — handles heartbeat, alerts, config & schema pulls.',
'Communicates with the DACTA SIEMLess backend API.',
'"""',
'',
'import logging',
'import platform',
'import threading',
'import time',
'',
'import requests',
'',
'logger = logging.getLogger("novelty-catcher.reporter")',
'',
'',
'class SIEMLessReporter:',
'    """Client for the SIEMLess Novelty Catcher API endpoints."""',
'',
'    def __init__(self, base_url, endpoint, catcher_id, enabled=True):',
'        self.base_url = base_url.rstrip("/")',
'        self.endpoint = endpoint',
'        self.catcher_id = catcher_id',
'        self.enabled = enabled',
'        self._session = requests.Session()',
'        self._session.headers["Content-Type"] = "application/json"',
'        self._heartbeat_thread = None',
'        self._stop_event = None',
'',
'        # Mutable stats for heartbeat',
'        self._mode = "monitor"',
'        self._events_processed = 0',
'        self._alerts_24h = 0',
'        self._stats = {}',
'',
'    @property',
'    def _api_url(self):',
'        return "{}{}".format(self.base_url, self.endpoint)',
'',
'    # ------------------------------------------------------------------',
'    # Heartbeat',
'    # ------------------------------------------------------------------',
'',
'    def update_stats(self, mode, events_processed, alerts_24h, stats):',
'        """Update cached stats that the heartbeat loop will send."""',
'        self._mode = mode',
'        self._events_processed = events_processed',
'        self._alerts_24h = alerts_24h',
'        self._stats = stats',
'',
'    def send_heartbeat(self, mode=None, events_processed=None, alerts_24h=None, stats=None):',
'        """Send a single heartbeat to the SIEMLess API."""',
'        if not self.enabled:',
'            return',
'        payload = {',
'            "catcher_id": self.catcher_id,',
'            "hostname": platform.node(),',
'            "version": "3.0.0",',
'            "mode": mode or self._mode,',
'            "events_processed": events_processed if events_processed is not None else self._events_processed,',
'            "alerts_24h": alerts_24h if alerts_24h is not None else self._alerts_24h,',
'            "stats": stats or self._stats,',
'        }',
'        try:',
'            url = "{}?action=heartbeat".format(self._api_url)',
'            resp = self._session.post(url, json=payload, timeout=15)',
'            if 200 <= resp.status_code < 300:',
'                logger.debug("Heartbeat sent — mode=%s, events=%d",',
'                             payload["mode"], payload["events_processed"])',
'            else:',
'                logger.warning("Heartbeat failed: %d %s", resp.status_code, resp.text[:200])',
'        except Exception:',
'            logger.warning("Heartbeat request failed", exc_info=True)',
'',
'    def start_heartbeat_loop(self, stop_event, interval=60):',
'        """Start a daemon thread that sends heartbeats periodically."""',
'        self._stop_event = stop_event',
'',
'        def _loop():',
'            while not stop_event.is_set():',
'                self.send_heartbeat()',
'                stop_event.wait(timeout=interval)',
'            # Final heartbeat on shutdown',
'            self.send_heartbeat()',
'            logger.info("Heartbeat loop stopped")',
'',
'        self._heartbeat_thread = threading.Thread(target=_loop, daemon=True, name="heartbeat")',
'        self._heartbeat_thread.start()',
'        logger.info("Heartbeat loop started — interval=%ds", interval)',
'',
'    def stop(self):',
'        """Signal heartbeat thread to stop and wait for it."""',
'        if self._stop_event:',
'            self._stop_event.set()',
'        if self._heartbeat_thread and self._heartbeat_thread.is_alive():',
'            self._heartbeat_thread.join(timeout=5)',
'',
'    # ------------------------------------------------------------------',
'    # Alerts',
'    # ------------------------------------------------------------------',
'',
'    def send_alert(self, org_id, alert_type, severity, source_key, detail, alert_data):',
'        """Send an alert to the SIEMLess API."""',
'        if not self.enabled:',
'            return',
'        payload = {',
'            "catcher_id": self.catcher_id,',
'            "org_id": org_id,',
'            "alert_type": alert_type,',
'            "severity": severity,',
'            "source_key": source_key,',
'            "detail": detail,',
'            "alert_data": alert_data,',
'        }',
'        try:',
'            url = "{}?action=alert".format(self._api_url)',
'            resp = self._session.post(url, json=payload, timeout=15)',
'            if 200 <= resp.status_code < 300:',
'                logger.info("Alert sent — type=%s, severity=%s, source=%s",',
'                            alert_type, severity, source_key)',
'            else:',
'                logger.warning("Alert send failed: %d %s", resp.status_code, resp.text[:200])',
'        except Exception:',
'            logger.warning("Alert request failed", exc_info=True)',
'',
'    # ------------------------------------------------------------------',
'    # Config pull',
'    # ------------------------------------------------------------------',
'',
'    def pull_config(self):',
'        """Pull agent config from SIEMLess DB."""',
'        if not self.enabled:',
'            return None',
'        try:',
'            url = "{}?action=config&catcher_id={}".format(self._api_url, self.catcher_id)',
'            resp = self._session.get(url, timeout=15)',
'            if 200 <= resp.status_code < 300:',
'                data = resp.json()',
'                logger.info("Pulled remote config for catcher %s", self.catcher_id)',
'                return data',
'            else:',
'                logger.debug("Config pull returned %d — using local config", resp.status_code)',
'                return None',
'        except Exception:',
'            logger.warning("Config pull failed — using local config", exc_info=True)',
'            return None',
'',
'    # ------------------------------------------------------------------',
'    # Feature schema pull',
'    # ------------------------------------------------------------------',
'',
'    def pull_feature_schema(self, org_id):',
'        """Pull feature schema from SIEMLess DB for field auto-discovery."""',
'        if not self.enabled or not org_id:',
'            return None',
'        try:',
'            url = "{}?action=feature_schema&org_id={}".format(self._api_url, org_id)',
'            resp = self._session.get(url, timeout=15)',
'            if 200 <= resp.status_code < 300:',
'                data = resp.json()',
'                logger.info("Pulled feature schema for org %s — %d indices",',
'                            org_id, len(data.get("indices", [])))',
'                return data',
'            else:',
'                logger.debug("Feature schema pull returned %d", resp.status_code)',
'                return None',
'        except Exception:',
'            logger.warning("Feature schema pull failed", exc_info=True)',
'            return None',
].join('\n'),


